--
-- Name: detect_refresh_token_reuse(); Type: FUNCTION; Schema: auth_governance; Owner: postgres
--

CREATE FUNCTION auth_governance.detect_refresh_token_reuse() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- If this token was already consumed and someone is updating it again,
    -- that is a replay attack. Revoke the entire family immediately.
    IF OLD.consumed_at IS NOT NULL AND NEW.consumed_at IS NOT NULL THEN
        UPDATE auth_governance.token_families
        SET
            status       = 'revoked',
            revoked_at   = now(),
            revoke_reason = 'reuse_detected'
        WHERE id = OLD.family_id
          AND status <> 'revoked';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION auth_governance.detect_refresh_token_reuse() OWNER TO postgres;

