--
-- Name: log_module_activation(); Type: FUNCTION; Schema: core; Owner: postgres
--

CREATE FUNCTION core.log_module_activation() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' OR OLD.status <> NEW.status THEN
        INSERT INTO core.module_activation_log
            (tenant_id, module_name, event_type,
             previous_status, new_status, tier)
        VALUES (
            NEW.tenant_id,
            NEW.module_name,
            CASE
                WHEN TG_OP = 'INSERT' THEN 'activated'
                WHEN NEW.status = 'active' THEN 'reactivated'
                WHEN NEW.status = 'suspended' THEN 'suspended'
                WHEN NEW.status = 'cancelled' THEN 'cancelled'
                ELSE 'status_changed'
            END,
            CASE WHEN TG_OP = 'UPDATE' THEN OLD.status ELSE NULL END,
            NEW.status,
            NEW.tier
        );
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION core.log_module_activation() OWNER TO postgres;

--
-- Name: provision_platform_services(uuid); Type: FUNCTION; Schema: core; Owner: postgres
--

CREATE FUNCTION core.provision_platform_services(p_tenant_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_module core.module_catalog%ROWTYPE;
BEGIN
    FOR v_module IN
        SELECT * FROM core.module_catalog
        WHERE is_platform_service = true
          AND is_available = true
    LOOP
        INSERT INTO core.tenant_subscriptions
            (tenant_id, module_id, module_name, tier, status, activated_at)
        VALUES
            (p_tenant_id, v_module.id, v_module.module_name,
             'enterprise', 'active', now())
        ON CONFLICT (tenant_id, module_name) DO NOTHING;
    END LOOP;
END;
$$;


ALTER FUNCTION core.provision_platform_services(p_tenant_id uuid) OWNER TO postgres;

--
-- Name: FUNCTION provision_platform_services(p_tenant_id uuid); Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON FUNCTION core.provision_platform_services(p_tenant_id uuid) IS 'Inserts active tenant_subscriptions rows for all platform services for a newly created tenant. Called by the Rust provisioning service immediately after a tenant record is created. ON CONFLICT DO NOTHING makes it idempotent — safe to re-run.';


--
-- Name: resolve_login_credentials(text, text); Type: FUNCTION; Schema: core; Owner: postgres
--

CREATE FUNCTION core.resolve_login_credentials(p_username text, p_domain text) RETURNS TABLE(user_id uuid, password_hash text, tenant_id uuid, system_role core.system_role)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'core', 'auth_governance', 'public'
    AS $$
    SELECT
        u.id            AS user_id,
        u.password_hash,
        tm.tenant_id,
        tm.system_role
    FROM core.users u
    JOIN core.tenant_memberships tm ON tm.user_id = u.id
    JOIN core.tenants t             ON t.id = tm.tenant_id
    WHERE u.username    = p_username
      AND t.domain      = p_domain
      AND u.is_active   = true;
$$;


ALTER FUNCTION core.resolve_login_credentials(p_username text, p_domain text) OWNER TO postgres;

