--
-- Name: auto_dead_letter(); Type: FUNCTION; Schema: event_bus; Owner: postgres
--

CREATE FUNCTION event_bus.auto_dead_letter() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.status = 'dead' AND OLD.status <> 'dead' THEN
        INSERT INTO event_bus.dead_letters (
            outbox_id,
            tenant_id,
            event_name,
            aggregate_type,
            aggregate_id,
            payload,
            correlation_id,
            producer_service,
            failing_subscriber,
            last_error,
            total_attempts,
            died_at
        ) VALUES (
            NEW.id,
            NEW.tenant_id,
            NEW.event_name,
            NEW.aggregate_type,
            NEW.aggregate_id,
            NEW.payload,
            NEW.correlation_id,
            NEW.producer_service,
            NEW.locked_by,      -- relay sets locked_by to its own ID before marking dead
            'max_attempts_exceeded',
            NEW.attempt_count,
            now()
        );
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION event_bus.auto_dead_letter() OWNER TO postgres;

--
-- Name: enforce_outbox_immutability(); Type: FUNCTION; Schema: event_bus; Owner: postgres
--

CREATE FUNCTION event_bus.enforce_outbox_immutability() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF OLD.status IN ('processed', 'dead') THEN
        RAISE EXCEPTION
            'outbox row % is terminal (status=%) and cannot be modified',
            OLD.id, OLD.status
            USING ERRCODE = 'restrict_violation';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION event_bus.enforce_outbox_immutability() OWNER TO postgres;

