--
-- Name: check_vendor_tax_compliance(); Type: FUNCTION; Schema: finance; Owner: postgres
--

CREATE FUNCTION finance.check_vendor_tax_compliance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_tax     finance.vendor_tax_details%ROWTYPE;
    v_invoice finance.vendor_invoices%ROWTYPE;
BEGIN
    SELECT * INTO v_invoice
    FROM finance.vendor_invoices
    WHERE id = NEW.invoice_id;

    SELECT * INTO v_tax
    FROM finance.vendor_tax_details
    WHERE vendor_id = v_invoice.vendor_id
      AND tenant_id = NEW.tenant_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Vendor has no tax details record. Create a vendor_tax_details record before processing payments.'
            USING ERRCODE = 'check_violation';
    END IF;

    IF v_tax.tax_classification = 'unknown' THEN
        RAISE EXCEPTION 'Vendor tax classification is unknown. Classify the vendor before processing payments.'
            USING ERRCODE = 'check_violation';
    END IF;

    IF v_tax.tax_classification IN ('foreign_individual', 'foreign_entity') THEN
        IF v_tax.w8_form_type IS NULL THEN
            RAISE EXCEPTION 'Foreign vendor requires a W-8 form on file before payment.'
                USING ERRCODE = 'check_violation';
        END IF;
        IF v_tax.w8_expiration_date IS NOT NULL
           AND v_tax.w8_expiration_date < CURRENT_DATE THEN
            RAISE EXCEPTION 'Foreign vendor W-8 form expired on %. Obtain a renewed W-8 before payment.',
                v_tax.w8_expiration_date
                USING ERRCODE = 'check_violation';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION finance.check_vendor_tax_compliance() OWNER TO postgres;

--
-- Name: FUNCTION check_vendor_tax_compliance(); Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON FUNCTION finance.check_vendor_tax_compliance() IS 'Blocks vendor_payments INSERT when: (1) no vendor_tax_details record exists, (2) tax_classification = unknown, or (3) foreign vendor W-8 is missing or expired. This is a hard database-level gate — the Rust AP service cannot bypass it. Satisfies IRS requirements for proper documentation before making payments to vendors subject to backup withholding or FATCA reporting.';


--
-- Name: maintain_journal_balance(); Type: FUNCTION; Schema: finance; Owner: postgres
--

CREATE FUNCTION finance.maintain_journal_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_entry finance.journal_entries%ROWTYPE;
BEGIN
    -- Determine which entry is affected
    IF TG_OP = 'DELETE' THEN
        SELECT * INTO v_entry FROM finance.journal_entries WHERE id = OLD.journal_entry_id;
    ELSE
        SELECT * INTO v_entry FROM finance.journal_entries WHERE id = NEW.journal_entry_id;
    END IF;
 
    -- Block modification of posted entries
    IF v_entry.status = 'posted' THEN
        RAISE EXCEPTION 'Cannot modify lines of a posted journal entry (id: %). Create a reversing entry instead.',
            v_entry.id USING ERRCODE = 'check_violation';
    END IF;
 
    -- Recalculate totals from all lines
    UPDATE finance.journal_entries
    SET
        total_debits  = COALESCE((
            SELECT SUM(debit_amount)
            FROM finance.journal_lines
            WHERE journal_entry_id = v_entry.id
              AND debit_amount IS NOT NULL
        ), 0),
        total_credits = COALESCE((
            SELECT SUM(credit_amount)
            FROM finance.journal_lines
            WHERE journal_entry_id = v_entry.id
              AND credit_amount IS NOT NULL
        ), 0),
        updated_at = now()
    WHERE id = v_entry.id;
 
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION finance.maintain_journal_balance() OWNER TO postgres;

--
-- Name: FUNCTION maintain_journal_balance(); Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON FUNCTION finance.maintain_journal_balance() IS 'Maintains journal_entries.total_debits and total_credits as lines are added or changed. Fires AFTER each journal_lines DML so the totals are always current. Also enforces immutability of posted entries — any attempt to modify a posted entry''s lines raises check_violation. The balanced CHECK on journal_entries then prevents posting if total_debits != total_credits.';


--
-- Name: update_account_balance(); Type: FUNCTION; Schema: finance; Owner: postgres
--

CREATE FUNCTION finance.update_account_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_line   finance.journal_lines%ROWTYPE;
    v_acct   finance.gl_accounts%ROWTYPE;
    v_delta  numeric(18,4);
    v_factor smallint;
BEGIN
    -- Only act on status transitions to 'posted' or 'reversed'
    IF OLD.status = NEW.status THEN
        RETURN NEW;
    END IF;
 
    -- Determine direction: posting increases balances, reversing decreases them
    IF NEW.status = 'posted' THEN
        v_factor := 1;
    ELSIF NEW.status = 'reversed' AND OLD.status = 'posted' THEN
        v_factor := -1;
    ELSE
        RETURN NEW;
    END IF;
 
    -- Apply each line to its account
    FOR v_line IN
        SELECT * FROM finance.journal_lines
        WHERE journal_entry_id = NEW.id
    LOOP
        SELECT * INTO v_acct
        FROM finance.gl_accounts
        WHERE id = v_line.gl_account_id;
 
        -- Delta depends on normal balance and debit/credit side
        IF v_acct.normal_balance = 'debit' THEN
            v_delta := COALESCE(v_line.debit_amount, 0)
                     - COALESCE(v_line.credit_amount, 0);
        ELSE
            v_delta := COALESCE(v_line.credit_amount, 0)
                     - COALESCE(v_line.debit_amount, 0);
        END IF;
 
        UPDATE finance.gl_accounts
        SET current_balance = current_balance + (v_delta * v_factor),
            updated_at = now()
        WHERE id = v_line.gl_account_id;
    END LOOP;
 
    RETURN NEW;
END;
$$;


ALTER FUNCTION finance.update_account_balance() OWNER TO postgres;

--
-- Name: FUNCTION update_account_balance(); Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON FUNCTION finance.update_account_balance() IS 'Updates gl_accounts.current_balance when a journal entry is posted or reversed. Fires AFTER UPDATE on journal_entries when status changes to posted or reversed. Balance delta respects normal_balance polarity: debiting an asset account increases its balance; debiting a liability account decreases it. Reversals apply the inverse delta, restoring the pre-posting balances.';


--
-- Name: auto_flag_on_critical_event(); Type: FUNCTION; Schema: lms; Owner: postgres
--

CREATE FUNCTION lms.auto_flag_on_critical_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.severity = 'critical' THEN
        UPDATE lms.assessment_attempts
        SET is_flagged = true,
            flag_reason = COALESCE(flag_reason || '; ', '')
                          || NEW.event_type::text
                          || ' at ' || to_char(NEW.occurred_at, 'HH24:MI:SS'),
            updated_at  = now()
        WHERE id = NEW.attempt_id
          AND is_flagged = false;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION lms.auto_flag_on_critical_event() OWNER TO postgres;

--
-- Name: FUNCTION auto_flag_on_critical_event(); Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON FUNCTION lms.auto_flag_on_critical_event() IS 'Automatically sets assessment_attempts.is_flagged = true when a critical severity event is logged (multiple_faces, prohibited_app_detected, etc.). Appends the event type and timestamp to flag_reason for the review queue. Only fires when is_flagged is currently false to avoid duplicate appends.';


--
-- Name: enforce_roster_lock(); Type: FUNCTION; Schema: lms; Owner: postgres
--

CREATE FUNCTION lms.enforce_roster_lock() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_status lms.grade_roster_status;
BEGIN
    SELECT status INTO v_status
    FROM lms.grade_roster_submissions
    WHERE id = NEW.roster_id;
 
    IF v_status = 'locked' AND NOT NEW.is_registrar_override THEN
        RAISE EXCEPTION
            'Grade roster % is locked. Set is_registrar_override = true '
            'and provide override_reason to make changes.',
            NEW.roster_id
            USING ERRCODE = 'restrict_violation';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION lms.enforce_roster_lock() OWNER TO postgres;

--
-- Name: record_grade_history(); Type: FUNCTION; Schema: lms; Owner: postgres
--

CREATE FUNCTION lms.record_grade_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO lms.grade_history (
        tenant_id,
        grade_id,
        submission_id,
        score,
        previous_score,
        feedback_text,
        change_reason,
        changed_by_user_id,
        is_lti_generated,
        changed_at
    )
    SELECT
        NEW.tenant_id,
        NEW.id,
        NEW.submission_id,
        NEW.score,
        CASE WHEN TG_OP = 'UPDATE' THEN OLD.score ELSE NULL END,
        NEW.feedback_text,
        CASE
            WHEN TG_OP = 'INSERT' THEN 'initial_grade'::lms.grade_change_reason
            WHEN NEW.is_lti_generated AND (OLD.is_lti_generated IS DISTINCT FROM NEW.is_lti_generated
                 OR OLD.score IS DISTINCT FROM NEW.score) THEN 'lti_passback'::lms.grade_change_reason
            ELSE 'instructor_revision'::lms.grade_change_reason
        END,
        NEW.grader_id,
        NEW.is_lti_generated,
        now();
    RETURN NEW;
END;
$$;


ALTER FUNCTION lms.record_grade_history() OWNER TO postgres;

