END;
$$;


ALTER FUNCTION lms.set_updated_at() OWNER TO postgres;

--
-- Name: update_bank_question_count(); Type: FUNCTION; Schema: lms; Owner: postgres
--

CREATE FUNCTION lms.update_bank_question_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE lms.question_banks
        SET total_questions = total_questions + 1,
            updated_at = now()
        WHERE id = NEW.bank_id;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE lms.question_banks
        SET total_questions = GREATEST(total_questions - 1, 0),
            updated_at = now()
        WHERE id = OLD.bank_id;
    ELSIF TG_OP = 'UPDATE' AND OLD.bank_id <> NEW.bank_id THEN
        UPDATE lms.question_banks
        SET total_questions = GREATEST(total_questions - 1, 0),
            updated_at = now()
        WHERE id = OLD.bank_id;
        UPDATE lms.question_banks
        SET total_questions = total_questions + 1,
            updated_at = now()
        WHERE id = NEW.bank_id;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION lms.update_bank_question_count() OWNER TO postgres;

--
-- Name: auto_translate_transfer_grade(); Type: FUNCTION; Schema: sis; Owner: postgres
--

CREATE FUNCTION sis.auto_translate_transfer_grade() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_policy            sis.transfer_grade_policies%ROWTYPE;
    v_eval              sis.transfer_evaluations%ROWTYPE;
    v_ext_entry         sis.external_grade_entries%ROWTYPE;
    v_crosswalk         sis.grade_crosswalks%ROWTYPE;
    v_int_entry         lms.grading_scale_entries%ROWTYPE;
    v_min_entry         sis.external_grade_entries%ROWTYPE;
    v_meets_min         boolean := true;
    v_accepted_statuses sis.transfer_course_status[] :=
        ARRAY['accepted_equivalent', 'accepted_elective', 'accepted_remedial']
        ::sis.transfer_course_status[];
BEGIN
    -- Only process accepted rows with a grade symbol
    IF NEW.status <> ALL(v_accepted_statuses) THEN
        RETURN NEW;
    END IF;
    IF NEW.external_grade_symbol IS NULL THEN
        RETURN NEW;
    END IF;
    -- Skip if already translated and grade symbol hasn't changed
    IF TG_OP = 'UPDATE'
       AND OLD.status = NEW.status
       AND OLD.external_grade_symbol IS NOT DISTINCT FROM NEW.external_grade_symbol
       AND NEW.translated_letter_grade IS NOT NULL THEN
        RETURN NEW;
    END IF;
 
    -- ── Resolve the transfer evaluation (for institution context) ────────────
    SELECT * INTO v_eval
    FROM sis.transfer_evaluations
    WHERE id = NEW.evaluation_id;
 
    -- ── Resolve the applicable transfer grade policy ─────────────────────────
    -- Try institution-specific first, fall back to tenant default
    SELECT * INTO v_policy
    FROM sis.transfer_grade_policies
    WHERE tenant_id = NEW.tenant_id
      AND external_institution_id = v_eval.external_institution_id
      AND is_active = true
    LIMIT 1;
 
    IF NOT FOUND THEN
        SELECT * INTO v_policy
        FROM sis.transfer_grade_policies
        WHERE tenant_id = NEW.tenant_id
          AND external_institution_id IS NULL
          AND is_active = true
        LIMIT 1;
    END IF;
 
    -- No policy at all → leave translation fields NULL, return
    IF NOT FOUND THEN
        RETURN NEW;
    END IF;
 
    -- ── Resolve the external grade entry ────────────────────────────────────
    -- Find the institution's scale assignment to get the external scale
    SELECT ege.* INTO v_ext_entry
    FROM sis.external_grade_entries ege
    JOIN sis.external_institution_scale_assignments eisa
        ON eisa.scale_id = ege.scale_id
    WHERE eisa.external_institution_id = v_eval.external_institution_id
      AND eisa.tenant_id = NEW.tenant_id
      AND ege.grade_symbol = NEW.external_grade_symbol
      AND eisa.is_primary = true
    LIMIT 1;
 
    IF FOUND THEN
        NEW.external_grade_entry_id := v_ext_entry.id;
 
        -- ── Evaluate minimum grade requirement ───────────────────────────────
        IF v_policy.min_acceptable_grade_symbol IS NOT NULL THEN
            SELECT * INTO v_min_entry
            FROM sis.external_grade_entries
            WHERE scale_id = v_policy.min_grade_scale_id
              AND grade_symbol = v_policy.min_acceptable_grade_symbol;
 
            IF FOUND AND v_ext_entry.percentage_midpoint IS NOT NULL
               AND v_min_entry.percentage_midpoint IS NOT NULL THEN
                v_meets_min :=
                    v_ext_entry.percentage_midpoint >= v_min_entry.percentage_midpoint;
            END IF;
        END IF;
        NEW.grade_meets_minimum := v_meets_min;
 
        -- ── Crosswalk lookup: exact match ────────────────────────────────────
        IF v_policy.qp_treatment <> 'credit_only' THEN
            SELECT gc.* INTO v_crosswalk
            FROM sis.grade_crosswalks gc
            WHERE gc.tenant_id = NEW.tenant_id
              AND gc.external_scale_id = v_ext_entry.scale_id
              AND gc.internal_scale_id = v_policy.internal_scale_id
              AND gc.external_grade_entry_id = v_ext_entry.id
              AND gc.is_approved = true
            LIMIT 1;
 
            IF FOUND THEN
                -- Resolve the internal grade entry
                SELECT * INTO v_int_entry
                FROM lms.grading_scale_entries
                WHERE id = v_crosswalk.internal_grade_entry_id;
 
                NEW.crosswalk_entry_id      := v_crosswalk.id;
                NEW.translated_letter_grade := v_int_entry.letter_grade;
                NEW.translation_source      := 'crosswalk_exact';
                NEW.translated_quality_points :=
                    CASE v_policy.qp_treatment
                        WHEN 'use_translated_grade' THEN v_int_entry.quality_points
                        WHEN 'credit_only'           THEN 0
                        ELSE v_int_entry.quality_points
                    END;
 
            ELSIF NOT v_policy.block_on_missing_crosswalk THEN
                -- No crosswalk match + policy says don't block → credit only
                NEW.translation_source        := 'policy_default';
                NEW.translated_letter_grade   := NULL;
                NEW.translated_quality_points := 0;
            END IF;
            -- If block_on_missing_crosswalk = true and no match: leave NULL
            -- → Rust service detects NULL translation_source and flags for review
 
        ELSE
            -- Policy says credit_only regardless of crosswalk
            NEW.translation_source        := 'credit_only_policy';
            NEW.translated_letter_grade   := NULL;
            NEW.translated_quality_points := 0;
        END IF;
 
    END IF; -- v_ext_entry found
 
    RETURN NEW;
	END;
$$;


ALTER FUNCTION sis.auto_translate_transfer_grade() OWNER TO postgres;

--
-- Name: FUNCTION auto_translate_transfer_grade(); Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON FUNCTION sis.auto_translate_transfer_grade() IS 'Automatically resolves a translated internal letter grade and quality points for an accepted transfer course record using the grade crosswalk and transfer grade policy. Fires BEFORE INSERT OR UPDATE on status or external_grade_symbol. Resolution order: exact crosswalk → policy default. Sets grade_meets_minimum by comparing percentage_midpoints. Leaves translation fields NULL when block_on_missing_crosswalk = true and no crosswalk match is found — signals registrar review needed.';


--
-- Name: enforce_scd2_current_uniqueness(); Type: FUNCTION; Schema: sis; Owner: postgres
--

CREATE FUNCTION sis.enforce_scd2_current_uniqueness() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Each table's trigger passes the natural key check as a dynamic query.
    -- The individual per-table triggers handle this with WHERE clauses.
    -- This function is a shared noop that per-table triggers extend.
    RETURN NEW;
END;
$$;


ALTER FUNCTION sis.enforce_scd2_current_uniqueness() OWNER TO postgres;

--
-- Name: enforce_transfer_grade_lock(); Type: FUNCTION; Schema: sis; Owner: postgres
--

CREATE FUNCTION sis.enforce_transfer_grade_lock() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_eval_status text;
BEGIN
    SELECT te.status::text INTO v_eval_status
    FROM sis.transfer_evaluations te
    WHERE te.id = OLD.evaluation_id;
 
    IF v_eval_status = 'completed'
       AND (OLD.translated_letter_grade IS DISTINCT FROM NEW.translated_letter_grade
            OR OLD.translated_quality_points IS DISTINCT FROM NEW.translated_quality_points)
       AND NEW.registrar_grade_override IS NULL THEN
        RAISE EXCEPTION
            'Transfer course record % belongs to a completed evaluation. '
            'Set registrar_grade_override and override_reason to change the grade.',
            OLD.id
            USING ERRCODE = 'restrict_violation';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION sis.enforce_transfer_grade_lock() OWNER TO postgres;

--
-- Name: FUNCTION enforce_transfer_grade_lock(); Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON FUNCTION sis.enforce_transfer_grade_lock() IS 'Prevents changes to translated grades on transfer course records belonging to completed evaluations without a registrar override. Mirrors the roster lock in lms.grade_roster_entries.';


