--
-- Name: courses; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.courses (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    subject character varying(16) NOT NULL,
    course character varying(16) NOT NULL,
    title character varying(255) NOT NULL,
    description text,
    credits numeric(4,2) DEFAULT 3.00 NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    department_id uuid NOT NULL,
    cip_code character varying(50),
    course_level character varying(100),
    grading_basis sis.grading_basis DEFAULT 'graded_letter'::sis.grading_basis NOT NULL,
    lecture_hours numeric(6,2) DEFAULT 0.00 NOT NULL,
    lab_hours numeric(6,2) DEFAULT 0.00 NOT NULL,
    clinical_hours numeric(6,2) DEFAULT 0.00 NOT NULL,
    independent_study_hours numeric(6,2) DEFAULT 0.00 NOT NULL,
    total_contact_hours numeric(6,2) GENERATED ALWAYS AS ((((lecture_hours + lab_hours) + clinical_hours) + independent_study_hours)) STORED,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS (((setweight(to_tsvector('english'::regconfig, COALESCE((((subject)::text || ' '::text) || (course)::text), ''::text)), 'A'::"char") || setweight(to_tsvector('english'::regconfig, (COALESCE(title, ''::character varying))::text), 'A'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(description, ''::text)), 'B'::"char"))) STORED,
    is_repeatable boolean DEFAULT true NOT NULL,
    max_repeat_attempts smallint,
    repeat_policy_id uuid,
    effective_start_date date DEFAULT CURRENT_DATE NOT NULL,
    effective_end_date date,
    is_current boolean DEFAULT true NOT NULL,
    catalog_year integer,
    superseded_at timestamp with time zone,
    superseded_by_id uuid,
    change_notes text,
    CONSTRAINT courses_dates_valid CHECK (((effective_end_date IS NULL) OR (effective_end_date > effective_start_date))),
    CONSTRAINT courses_max_repeat_attempts_positive CHECK (((max_repeat_attempts IS NULL) OR (max_repeat_attempts > 0)))
);


ALTER TABLE sis.courses OWNER TO postgres;

--
-- Name: TABLE courses; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.courses IS 'The master course record (independent of term). subject + course form the course number (e.g., "ENG 101"). credits, lecture_hours, lab_hours, clinical_hours, and independent_study_hours define the contact hour structure. grading_basis: letter_grade, pass_fail, audit, credit_no_credit. cip_code links to the federal program taxonomy.';


--
-- Name: COLUMN courses.is_repeatable; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.courses.is_repeatable IS 'Whether this course can be repeated for credit or grade replacement. false = enrollment blocked if student has any prior completion.';


--
-- Name: COLUMN courses.max_repeat_attempts; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.courses.max_repeat_attempts IS 'Course-level cap on total allowed attempts (including first enrollment). Overrides the applicable course_repeat_policy.max_attempts. NULL = use the policy default.';


--
-- Name: COLUMN courses.repeat_policy_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.courses.repeat_policy_id IS 'Course-specific repeat policy override. NULL = use the program or tenant default.';


--
-- Name: COLUMN courses.effective_start_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.courses.effective_start_date IS 'First date this version of the course was active in the catalog. Transcript records reference the course_id at time of enrollment. When generating transcripts, use the course version active during the term: WHERE id = $course_id matches the correct version via FK.';


--
-- Name: COLUMN courses.change_notes; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.courses.change_notes IS 'What changed in this course version. Required for curriculum committee records and accreditation substantive change documentation.';


--
-- Name: get_course_as_of(uuid, date); Type: FUNCTION; Schema: sis; Owner: postgres
--

CREATE FUNCTION sis.get_course_as_of(p_course_id uuid, p_as_of_date date) RETURNS SETOF sis.courses
    LANGUAGE sql STABLE
    SET search_path TO 'sis', 'public'
    AS $$
    SELECT *
    FROM sis.courses
    WHERE id = p_course_id
      AND effective_start_date <= p_as_of_date
      AND (effective_end_date IS NULL OR effective_end_date > p_as_of_date)
    LIMIT 1;
$$;


ALTER FUNCTION sis.get_course_as_of(p_course_id uuid, p_as_of_date date) OWNER TO postgres;

--
-- Name: FUNCTION get_course_as_of(p_course_id uuid, p_as_of_date date); Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON FUNCTION sis.get_course_as_of(p_course_id uuid, p_as_of_date date) IS 'Returns the courses row that was in effect on p_as_of_date. Used by the transcript generation service to get the course title, credit hours, and CIP code as they were when the student was enrolled, not as they are today.';


--
-- Name: academic_programs; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.academic_programs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    department_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    credential_id uuid NOT NULL,
    total_credits_required numeric(5,2) NOT NULL,
    cip_code character varying(20),
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    published_credit_length numeric(6,2) DEFAULT 120.00 NOT NULL,
    max_timeframe_credits numeric(6,2) GENERATED ALWAYS AS ((published_credit_length * 1.5)) STORED,
    diploma_title character varying(255),
    nsc_degree_designation sis.nsc_degree_designation,
    hegis_code character varying(10),
    is_title_iv_eligible boolean DEFAULT true NOT NULL,
    is_gainful_employment boolean DEFAULT false NOT NULL,
    weeks_of_instruction integer,
    effective_start_date date DEFAULT CURRENT_DATE NOT NULL,
    effective_end_date date,
    is_current boolean DEFAULT true NOT NULL,
    catalog_year integer,
    superseded_at timestamp with time zone,
    superseded_by_id uuid,
    change_summary text,
    CONSTRAINT academic_programs_dates_valid CHECK (((effective_end_date IS NULL) OR (effective_end_date > effective_start_date)))
);


ALTER TABLE sis.academic_programs OWNER TO postgres;

--
-- Name: TABLE academic_programs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.academic_programs IS 'An authorized academic program leading to a credential. total_credits_required and published_credit_length drive financial aid credit load calculations. max_timeframe_credits is the SAP maximum timeframe (typically 150% of published length). cip_code links to the federal program taxonomy for IPEDS reporting.';


--
-- Name: COLUMN academic_programs.diploma_title; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.diploma_title IS 'Program title exactly as it appears on the diploma and in NSC DegreeVerify. May differ from the internal program name (e.g. "Bachelor of Science in Computer Science" vs internal name "CS - B.S."). Required for NSC DegreeVerify submissions.';


--
-- Name: COLUMN academic_programs.nsc_degree_designation; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.nsc_degree_designation IS 'NSC-controlled vocabulary degree abbreviation for DegreeVerify reporting (e.g. B.S., A.A., M.B.A., Ph.D., Cert.). Must match NSC''s accepted degree designation list exactly.';


--
-- Name: COLUMN academic_programs.is_gainful_employment; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.is_gainful_employment IS 'Whether this program is subject to ED Gainful Employment regulations (34 CFR Part 668, Subpart Q). Applicable to most non-degree programs and some degree programs at for-profit institutions. Drives the gainful_employment reporting feed to NSLDS.';


--
-- Name: COLUMN academic_programs.weeks_of_instruction; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.weeks_of_instruction IS 'Total weeks of instructional time in the program. Required for clock-hour programs in NSLDS enrollment reporting and for VA enrollment certification.';


--
-- Name: COLUMN academic_programs.catalog_year; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.catalog_year IS 'The academic catalog year this program version belongs to (e.g., 2024). Students are governed by the catalog year in which they first enrolled in the program (student_programs.declared_term_id → academic_terms.academic_year). The CPOS sweep resolves the correct program version via: WHERE id = $program_id AND effective_start_date <= $enrollment_date AND (effective_end_date IS NULL OR effective_end_date > $enrollment_date).';


--
-- Name: COLUMN academic_programs.change_summary; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_programs.change_summary IS 'Human-readable summary of what changed in this catalog year version. Required for academic governance documentation and SACSCOC substantive change reporting when program requirements change materially.';


--
-- Name: get_program_as_of(uuid, date); Type: FUNCTION; Schema: sis; Owner: postgres
--

CREATE FUNCTION sis.get_program_as_of(p_program_id uuid, p_as_of_date date) RETURNS SETOF sis.academic_programs
    LANGUAGE sql STABLE
    SET search_path TO 'sis', 'public'
    AS $$
    SELECT *
    FROM sis.academic_programs
    WHERE id = p_program_id
      AND effective_start_date <= p_as_of_date
      AND (effective_end_date IS NULL OR effective_end_date > p_as_of_date)
    LIMIT 1;
$$;


ALTER FUNCTION sis.get_program_as_of(p_program_id uuid, p_as_of_date date) OWNER TO postgres;

--
-- Name: FUNCTION get_program_as_of(p_program_id uuid, p_as_of_date date); Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON FUNCTION sis.get_program_as_of(p_program_id uuid, p_as_of_date date) IS 'Returns the academic_programs row that was in effect on p_as_of_date. Used by the CPOS sweep to evaluate students against the program requirements that were current when they enrolled, not the current requirements. Called from Rust as: SELECT * FROM sis.get_program_as_of($program_id, $enrollment_date).';


