--
-- Name: oauth_clients; Type: TABLE; Schema: auth_governance; Owner: postgres
--

CREATE TABLE auth_governance.oauth_clients (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid,
    client_name character varying(255) NOT NULL,
    client_type auth_governance.oauth_client_type NOT NULL,
    client_secret_hash character varying(255),
    allowed_redirect_uris text NOT NULL,
    allowed_grant_types auth_governance.oauth_grant_type[] NOT NULL,
    allowed_scopes text DEFAULT 'openid profile email'::text NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    require_pkce boolean DEFAULT false NOT NULL,
    access_token_ttl_secs integer,
    refresh_token_ttl_secs integer,
    metadata jsonb,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT access_token_ttl_positive CHECK (((access_token_ttl_secs IS NULL) OR (access_token_ttl_secs > 0))),
    CONSTRAINT public_clients_have_no_secret CHECK (((client_type <> 'public'::auth_governance.oauth_client_type) OR (client_secret_hash IS NULL))),
    CONSTRAINT public_clients_require_pkce CHECK (((client_type <> 'public'::auth_governance.oauth_client_type) OR (require_pkce = true))),
    CONSTRAINT refresh_token_ttl_positive CHECK (((refresh_token_ttl_secs IS NULL) OR (refresh_token_ttl_secs > 0)))
);


ALTER TABLE auth_governance.oauth_clients OWNER TO postgres;

