    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    token_hash character varying(64) NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    requested_ip inet,
    consumed_at timestamp with time zone,
    consumed_ip inet,
    invalidated_at timestamp with time zone,
    CONSTRAINT not_both_consumed_and_invalidated CHECK ((NOT ((consumed_at IS NOT NULL) AND (invalidated_at IS NOT NULL)))),
    CONSTRAINT password_reset_expiry_after_creation CHECK ((expires_at > created_at))
);


ALTER TABLE auth_governance.password_reset_tokens OWNER TO postgres;

