--
-- Name: permissions; Type: TABLE; Schema: auth_governance; Owner: postgres
--

CREATE TABLE auth_governance.permissions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    grantee_user_id uuid,
    grantee_role core.system_role,
    action character varying(100) NOT NULL,
    resource_type character varying(150) NOT NULL,
    resource_id uuid,
    effect auth_governance.permission_effect DEFAULT 'allow'::auth_governance.permission_effect NOT NULL,
    conditions jsonb,
    granted_by_user_id uuid,
    granted_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone,
    revoked_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT permissions_exactly_one_grantee CHECK (((((grantee_user_id IS NOT NULL))::integer + ((grantee_role IS NOT NULL))::integer) = 1)),
    CONSTRAINT permissions_expiry_after_grant CHECK (((expires_at IS NULL) OR (expires_at > granted_at)))
);


ALTER TABLE auth_governance.permissions OWNER TO postgres;

--
-- Name: TABLE permissions; Type: COMMENT; Schema: auth_governance; Owner: postgres
--

COMMENT ON TABLE auth_governance.permissions IS 'Fine-grained RBAC + ABAC permission grants. Evaluated by the auth service policy engine at request time. Object-level grants use resource_id; type-level grants leave it NULL.';


--
-- Name: refresh_tokens; Type: TABLE; Schema: auth_governance; Owner: postgres
--

CREATE TABLE auth_governance.refresh_tokens (
