    token_hash character varying(64) NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    issued_at timestamp with time zone DEFAULT now() NOT NULL,
    consumed_at timestamp with time zone,
    consumed_ip inet,
    is_valid_use boolean,
    CONSTRAINT consumed_tokens_have_validity CHECK (((consumed_at IS NULL) OR (is_valid_use IS NOT NULL))),
    CONSTRAINT refresh_tokens_expiry_after_issue CHECK ((expires_at > issued_at))
);


ALTER TABLE auth_governance.refresh_tokens OWNER TO postgres;

