-- Name: TABLE refresh_tokens; Type: COMMENT; Schema: auth_governance; Owner: postgres
--

COMMENT ON TABLE auth_governance.refresh_tokens IS 'Individual refresh tokens. Write-once; token value hashed at rest. Never store or log the cleartext token value.';


