-- Name: sso_identity_providers; Type: TABLE; Schema: auth_governance; Owner: postgres
--

CREATE TABLE auth_governance.sso_identity_providers (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    provider_name character varying(255) NOT NULL,
    protocol character varying(10) NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    oidc_issuer_url text,
    oidc_client_id character varying(255),
    oidc_client_secret_enc text,
    oidc_scopes text DEFAULT 'openid profile email'::text,
    saml_metadata_url text,
    saml_metadata_xml text,
    saml_sp_entity_id text,
    attribute_map jsonb,
    auto_provision_users boolean DEFAULT false NOT NULL,
    default_role core.system_role DEFAULT 'user'::core.system_role NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT oidc_requires_issuer CHECK ((((protocol)::text <> 'oidc'::text) OR (oidc_issuer_url IS NOT NULL))),
    CONSTRAINT saml_requires_metadata CHECK ((((protocol)::text <> 'saml'::text) OR ((saml_metadata_url IS NOT NULL) OR (saml_metadata_xml IS NOT NULL)))),
    CONSTRAINT sso_idp_protocol_check CHECK (((protocol)::text = ANY ((ARRAY['saml'::character varying, 'oidc'::character varying])::text[])))
);


ALTER TABLE auth_governance.sso_identity_providers OWNER TO postgres;

