    mfa_grace_period_hours smallint DEFAULT 48 NOT NULL,
    allowed_mfa_types auth_governance.mfa_factor_type[] DEFAULT ARRAY['totp'::auth_governance.mfa_factor_type, 'webauthn'::auth_governance.mfa_factor_type, 'sms_otp'::auth_governance.mfa_factor_type, 'email_otp'::auth_governance.mfa_factor_type, 'backup_code'::auth_governance.mfa_factor_type] NOT NULL,
    access_token_ttl_secs integer DEFAULT 900 NOT NULL,
    refresh_token_ttl_secs integer DEFAULT 2592000 NOT NULL,
    max_concurrent_sessions smallint DEFAULT 10 NOT NULL,
    lockout_threshold smallint DEFAULT 5 NOT NULL,
    lockout_duration_minutes smallint DEFAULT 30 NOT NULL,
    force_sso boolean DEFAULT false NOT NULL,
    allowed_ip_ranges inet[],
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT access_token_ttl_positive CHECK ((access_token_ttl_secs > 0)),
    CONSTRAINT lockout_duration_positive CHECK ((lockout_duration_minutes > 0)),
    CONSTRAINT lockout_threshold_positive CHECK ((lockout_threshold > 0)),
    CONSTRAINT max_concurrent_sessions_positive CHECK ((max_concurrent_sessions > 0)),
    CONSTRAINT min_password_length_reasonable CHECK (((min_password_length >= 8) AND (min_password_length <= 128))),
    CONSTRAINT password_history_non_negative CHECK ((password_history_count >= 0)),
    CONSTRAINT refresh_token_ttl_positive CHECK ((refresh_token_ttl_secs > 0))
);


