    grant_type auth_governance.session_grant_type NOT NULL,
    status auth_governance.token_family_status DEFAULT 'active'::auth_governance.token_family_status NOT NULL,
    created_ip inet,
    created_ua text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    last_rotated_at timestamp with time zone,
    revoked_at timestamp with time zone,
    revoke_reason character varying(255),
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT revoked_families_have_reason CHECK (((revoked_at IS NULL) OR (revoke_reason IS NOT NULL)))
);


