ALTER TABLE core.users OWNER TO postgres;

--
-- Name: TABLE users; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.users IS 'Global user identity record, shared across all tenant contexts. A single human has one users row regardless of how many schools they belong to. Institutional affiliation is expressed via tenant_memberships. password_hash stores an Argon2id hash; the plaintext password is never stored. Uses cross_tenant_user_isolation RLS: visible within any tenant the user belongs to.';


--
-- Name: vw_active_sessions; Type: VIEW; Schema: auth_governance; Owner: postgres
--

CREATE VIEW auth_governance.vw_active_sessions AS
 SELECT tf.id AS family_id,
    tf.tenant_id,
    tf.user_id,
    u.username,
    u.first_name,
    u.last_name,
    oc.client_name,
    tf.grant_type,
    tf.created_at AS session_started_at,
    tf.created_ip,
    tf.last_rotated_at,
    rt.expires_at AS session_expires_at
   FROM (((auth_governance.token_families tf
     JOIN core.users u ON ((tf.user_id = u.id)))
     JOIN auth_governance.oauth_clients oc ON ((tf.client_id = oc.id)))
     LEFT JOIN LATERAL ( SELECT refresh_tokens.expires_at
           FROM auth_governance.refresh_tokens
          WHERE ((refresh_tokens.family_id = tf.id) AND (refresh_tokens.consumed_at IS NULL))
          ORDER BY refresh_tokens.issued_at DESC
         LIMIT 1) rt ON (true))
  WHERE (tf.status = 'active'::auth_governance.token_family_status);


ALTER VIEW auth_governance.vw_active_sessions OWNER TO postgres;

