--
-- Name: vw_public_portal_meetings; Type: VIEW; Schema: board; Owner: postgres
--

CREATE VIEW board.vw_public_portal_meetings AS
 SELECT tenant_id,
    id AS meeting_id,
    title AS meeting_title,
    date,
    location,
    livestream_url,
    recording_video_url,
    minutes_status,
        CASE
            WHEN (minutes_status = 'approved_and_published'::board.minutes_status) THEN minutes_markdown
            ELSE NULL::text
        END AS minutes_markdown,
    ( SELECT jsonb_agg(jsonb_build_object('item_id', a.id, 'order_index', a.order_index, 'title', a.title, 'item_type', a.item_type, 'description', a.public_description, 'motion_text', a.motion_text) ORDER BY a.order_index) AS jsonb_agg
           FROM board.agendas a
          WHERE ((a.meeting_id = m.id) AND (a.item_type <> 'executive_session'::board.agenda_item_type))) AS public_agenda_items
   FROM board.meetings m
  WHERE ((is_public = true) AND (is_published_to_portal = true));


ALTER VIEW board.vw_public_portal_meetings OWNER TO postgres;

--
-- Name: VIEW vw_public_portal_meetings; Type: COMMENT; Schema: board; Owner: postgres
--

COMMENT ON VIEW board.vw_public_portal_meetings IS 'Public-safe view of meetings approved for portal publication. Joins meeting metadata with approved agenda items and minutes markdown. Excludes private agenda items and unpublished meetings. Consumed by the CMS and the public board portal microservice.';


