--
-- Name: vw_media_clearance_status; Type: VIEW; Schema: cms; Owner: postgres
--

CREATE VIEW cms.vw_media_clearance_status AS
 SELECT mas.tenant_id,
    mas.media_asset_id,
    mas.subject_user_id,
    u.first_name,
    u.last_name,
    COALESCE(( SELECT uc.is_granted
           FROM core.user_consents uc
          WHERE ((uc.user_id = mas.subject_user_id) AND (uc.type = 'photo_video_release'::core.consent_type))
          ORDER BY uc.updated_at DESC
         LIMIT 1), false) AS has_media_release,
        CASE
            WHEN (mas.is_identifiable = false) THEN 'cleared'::cms.privacy_clearance_status
            WHEN (( SELECT uc.is_granted
               FROM core.user_consents uc
              WHERE ((uc.user_id = mas.subject_user_id) AND (uc.type = 'photo_video_release'::core.consent_type))
              ORDER BY uc.updated_at DESC
             LIMIT 1) = true) THEN 'cleared'::cms.privacy_clearance_status
            ELSE 'blocked_by_policy'::cms.privacy_clearance_status
        END AS subject_clearance_status
   FROM (cms.media_asset_subjects mas
     JOIN core.users u ON ((mas.subject_user_id = u.id)));


ALTER VIEW cms.vw_media_clearance_status OWNER TO postgres;

--
-- Name: VIEW vw_media_clearance_status; Type: COMMENT; Schema: cms; Owner: postgres
--

COMMENT ON VIEW cms.vw_media_clearance_status IS 'Resolves per-subject media release clearance status for each asset. Joins media_asset_subjects with data_governance.vw_current_consents to determine whether an identifiable person has a valid media_release consent on file. Returns subject_clearance_status of cleared, pending, or denied. Consumed by the publishing workflow to block asset publication when clearance is missing.';


