    story_points numeric(5,2),
    estimated_hours numeric(6,2),
    actual_logged_hours numeric(6,2) DEFAULT 0.00 NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(title, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(description, ''::text)), 'B'::"char"))) STORED
);


