--
-- Name: vw_kanban_dashboard; Type: VIEW; Schema: collab; Owner: postgres
--

CREATE VIEW collab.vw_kanban_dashboard AS
 SELECT t.tenant_id,
    t.id AS task_id,
    t.title AS task_title,
    t.status AS task_status,
    t.priority AS task_priority,
    t.due_date,
    w.id AS workspace_id,
    w.name AS workspace_name,
    (((creator.first_name)::text || ' '::text) || (creator.last_name)::text) AS created_by_name,
    (((assignee.first_name)::text || ' '::text) || (assignee.last_name)::text) AS assigned_to_name,
    ( SELECT count(*) AS count
           FROM collab.task_comments c
          WHERE (c.task_id = t.id)) AS total_comments
   FROM (((collab.tasks t
     JOIN collab.workspaces w ON ((t.workspace_id = w.id)))
     JOIN core.users creator ON ((t.creator_id = creator.id)))
     LEFT JOIN core.users assignee ON ((t.assignee_id = assignee.id)));


ALTER VIEW collab.vw_kanban_dashboard OWNER TO postgres;

--
-- Name: VIEW vw_kanban_dashboard; Type: COMMENT; Schema: collab; Owner: postgres
--

COMMENT ON VIEW collab.vw_kanban_dashboard IS 'Flattened view of tasks enriched with assignee and creator names for direct consumption by the Kanban board UI. Returns task_id, title, status, priority, due_date, and display names without requiring the frontend to join the users table separately.';


