--
-- Name: journeys; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.journeys (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT communication_journeys_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT communication_journeys_tenant_id_not_null NOT NULL,
    name character varying(255) CONSTRAINT communication_journeys_name_not_null NOT NULL,
    trigger_event character varying(100) CONSTRAINT communication_journeys_trigger_event_not_null NOT NULL,
    is_active boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE comms.journeys OWNER TO postgres;

--
-- Name: TABLE journeys; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.journeys IS 'An automated multi-step communication sequence triggered by a specific event_bus event (trigger_event matches event_bus.event_types.event_name). When the event fires, the comms service resolves the active journey and executes its steps in order. is_active gates whether the journey processes new trigger events.';


--
-- Name: logs; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.logs (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT communication_logs_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT communication_logs_tenant_id_not_null NOT NULL,
    sender_id uuid,
    recipient_id uuid CONSTRAINT communication_logs_recipient_id_not_null NOT NULL,
    template_id uuid,
    channel comms.communication_channel CONSTRAINT communication_logs_channel_not_null NOT NULL,
    recipient_address character varying(255) CONSTRAINT communication_logs_recipient_address_not_null NOT NULL,
    subject character varying(255),
    body text CONSTRAINT communication_logs_body_not_null NOT NULL,
    status comms.delivery_status DEFAULT 'queued'::comms.delivery_status CONSTRAINT communication_logs_status_not_null NOT NULL,
    external_message_id character varying(255),
    error_details text,
    sent_at timestamp with time zone DEFAULT now() CONSTRAINT communication_logs_sent_at_not_null NOT NULL,
    delivered_at timestamp with time zone
);


ALTER TABLE comms.logs OWNER TO postgres;

--
-- Name: TABLE logs; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.logs IS 'Immutable delivery log of every individual message sent. Captures channel, recipient address, body snapshot, sent_at, delivered_at, status, and external_message_id from the delivery provider. Append-only: status updates arrive as delivery_events rows, not as updates to this table. Indexed on (tenant_id, recipient_id, sent_at) for recipient history queries.';


--
-- Name: templates; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.templates (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT communication_templates_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT communication_templates_tenant_id_not_null NOT NULL,
    name character varying(255) CONSTRAINT communication_templates_name_not_null NOT NULL,
    channel comms.communication_channel CONSTRAINT communication_templates_channel_not_null NOT NULL,
    subject_template character varying CONSTRAINT communication_templates_subject_template_not_null NOT NULL,
    body_template text CONSTRAINT communication_templates_body_template_not_null NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now(),
    category comms.notification_category DEFAULT 'administrative'::comms.notification_category CONSTRAINT communication_templates_category_not_null NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    json_template jsonb,
    fts_doc tsvector GENERATED ALWAYS AS (((setweight(to_tsvector('english'::regconfig, (COALESCE(name, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, (COALESCE(subject_template, ''::character varying))::text), 'B'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(body_template, ''::text)), 'C'::"char"))) STORED
);


ALTER TABLE comms.templates OWNER TO postgres;

--
-- Name: TABLE templates; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.templates IS 'Reusable message templates supporting Handlebars-style variable interpolation. Each template is scoped to a channel (email, sms, push, in_app) and a notification_category. Carries both a body_template (plain text / markdown) and json_template (rich structured payload for push notifications). The unique constraint on (tenant, name, channel) prevents duplicate template names per channel.';


--
-- Name: COLUMN templates.fts_doc; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON COLUMN comms.templates.fts_doc IS 'Generated tsvector for template search by name (A), subject_template (B), and body_template (C). Enables the template picker to search across template content, not just names.';


--
-- Name: user_devices; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.user_devices (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    device_name character varying(100),
    platform comms.device_platform NOT NULL,
    push_token character varying(255) NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    last_active_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE comms.user_devices OWNER TO postgres;

--
-- Name: TABLE user_devices; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.user_devices IS 'Registered push notification devices. Stores the push_token (unique globally across providers), platform (ios, android, web), device_name, and last_active_at. Uses cross_tenant_user_devices RLS policy so a user''s devices are accessible across all their tenant contexts. The push_token unique constraint prevents duplicate registrations.';


--
-- Name: user_preferences; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.user_preferences (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT user_notification_preferences_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT user_notification_preferences_tenant_id_not_null NOT NULL,
    user_id uuid CONSTRAINT user_notification_preferences_user_id_not_null NOT NULL,
    category comms.notification_category CONSTRAINT user_notification_preferences_category_not_null NOT NULL,
    email_enabled boolean DEFAULT true CONSTRAINT user_notification_preferences_email_enabled_not_null NOT NULL,
    sms_enabled boolean DEFAULT false CONSTRAINT user_notification_preferences_sms_enabled_not_null NOT NULL,
    in_app_enabled boolean DEFAULT true CONSTRAINT user_notification_preferences_in_app_enabled_not_null NOT NULL,
    updated_at timestamp with time zone DEFAULT now() CONSTRAINT user_notification_preferences_updated_at_not_null NOT NULL,
    push_enabled boolean DEFAULT true NOT NULL,
    CONSTRAINT emergency_override CHECK (((category <> 'emergency'::comms.notification_category) OR ((email_enabled = true) OR (sms_enabled = true) OR (in_app_enabled = true))))
);


ALTER TABLE comms.user_preferences OWNER TO postgres;

--
-- Name: TABLE user_preferences; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.user_preferences IS 'Per-user, per-category notification channel opt-in/opt-out settings. Covers email_enabled, sms_enabled, push_enabled, in_app_enabled per notification_category. The emergency_override constraint ensures safety and emergency notification categories cannot be disabled — these always deliver regardless of preference.';


--
-- Name: webhook_delivery_logs; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.webhook_delivery_logs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    endpoint_id uuid NOT NULL,
    topic_name character varying(255) NOT NULL,
    response_status_code integer,
    response_body text,
    is_successful boolean DEFAULT false NOT NULL,
    delivered_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE comms.webhook_delivery_logs OWNER TO postgres;

--
-- Name: TABLE webhook_delivery_logs; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.webhook_delivery_logs IS 'Append-only log of each outbound webhook delivery attempt. Records the response_status_code and response_body so failed deliveries can be diagnosed and replayed. is_successful is false for non-2xx responses and network errors.';


--
-- Name: webhook_endpoints; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.webhook_endpoints (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    endpoint_url character varying(1024) NOT NULL,
    signing_secret character varying(255) NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE comms.webhook_endpoints OWNER TO postgres;

--
-- Name: TABLE webhook_endpoints; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.webhook_endpoints IS 'Outbound webhook destinations registered by a tenant for receiving real-time event notifications. signing_secret is used by the delivery system to HMAC-sign payloads so the recipient can verify authenticity. is_active gates delivery.';


--
-- Name: webhook_subscriptions; Type: TABLE; Schema: comms; Owner: postgres
--

CREATE TABLE comms.webhook_subscriptions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    endpoint_id uuid NOT NULL,
    topic_name character varying(255) NOT NULL
);


ALTER TABLE comms.webhook_subscriptions OWNER TO postgres;

--
-- Name: TABLE webhook_subscriptions; Type: COMMENT; Schema: comms; Owner: postgres
--

COMMENT ON TABLE comms.webhook_subscriptions IS 'Maps a webhook endpoint to specific event topic names it should receive. topic_name matches event_bus.event_types.event_name patterns. The unique constraint prevents a single endpoint from subscribing to the same topic twice.';


--
-- Name: api_rate_limit_policies; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.api_rate_limit_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid,
    api_scope auth_governance.api_key_scope,
    module_name core.module_name,
    requests_per_minute integer DEFAULT 600 NOT NULL,
    requests_per_hour integer DEFAULT 10000 NOT NULL,
    requests_per_day integer DEFAULT 100000 NOT NULL,
    burst_size integer DEFAULT 100 NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT api_rate_limit_policies_limits_positive CHECK (((requests_per_minute > 0) AND (requests_per_hour > 0) AND (requests_per_day > 0) AND (burst_size > 0)))
);


ALTER TABLE core.api_rate_limit_policies OWNER TO postgres;

--
-- Name: TABLE api_rate_limit_policies; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.api_rate_limit_policies IS 'Per-tenant API rate limit configuration. The Rust API middleware reads the most specific applicable policy (tenant+scope+module > tenant+scope > tenant > global default) and passes it to the Redis rate limiter. Enforcement is in Redis; this table is the source of truth for limits. Enterprise tenants can negotiate higher limits stored here.';


--
-- Name: audit_logs; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.audit_logs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid CONSTRAINT audit_logs_tenant_id_not_null1 NOT NULL,
    actor_id uuid,
    action core.audit_action CONSTRAINT audit_logs_action_not_null1 NOT NULL,
    target_table character varying(100) CONSTRAINT audit_logs_target_table_not_null1 NOT NULL,
    target_record_id uuid CONSTRAINT audit_logs_target_record_id_not_null1 NOT NULL,
    old_payload jsonb,
    new_payload jsonb,
    ip_address text,
    user_agent text,
    created_at timestamp with time zone DEFAULT now() CONSTRAINT audit_logs_created_at_not_null1 NOT NULL,
    CONSTRAINT audit_logs_action_not_null CHECK ((action IS NOT NULL)),
    CONSTRAINT audit_logs_created_at_not_null CHECK ((created_at IS NOT NULL)),
    CONSTRAINT audit_logs_target_record_id_not_null CHECK ((target_record_id IS NOT NULL)),
    CONSTRAINT audit_logs_target_table_not_null CHECK ((target_table IS NOT NULL)),
    CONSTRAINT audit_logs_tenant_id_not_null CHECK ((tenant_id IS NOT NULL))
)
PARTITION BY RANGE (created_at);


ALTER TABLE core.audit_logs OWNER TO postgres;

--
-- Name: TABLE audit_logs; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.audit_logs IS 'Immutable, append-only audit trail of all data-mutating operations across every regulated table in the database. Written by Rust service middleware on every INSERT, UPDATE, and DELETE. Range-partitioned by created_at (monthly) through 2027. old_payload/new_payload capture full before/after state as JSONB. actor_id SET NULL preserves records when a user is deleted. Never update or delete rows in this table — add new partitions monthly and DETACH + archive old ones per the retention schedule. Satisfies FERPA §99.32, HIPAA audit controls, and SOC 2 CC7.2.';


--
-- Name: COLUMN audit_logs.actor_id; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.audit_logs.actor_id IS 'The user who performed the action. NULL for system-generated events (scheduled jobs, cascade deletes, automated processes). SET NULL on user deletion — the historical record is preserved but the account reference is cleared.';


--
-- Name: COLUMN audit_logs.target_table; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.audit_logs.target_table IS 'Schema-qualified table name of the affected record (e.g., ''sis.enrollments'', ''finance.student_transactions''). Used with target_record_id to reconstruct the full audit trail for any record across any schema.';


--
-- Name: COLUMN audit_logs.old_payload; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.audit_logs.old_payload IS 'Full JSONB snapshot of the row before the operation. NULL for INSERT events (no prior state exists).';


--
-- Name: COLUMN audit_logs.new_payload; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.audit_logs.new_payload IS 'Full JSONB snapshot of the row after the operation. NULL for DELETE events (no subsequent state exists).';


