--
-- Name: departments; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.departments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    code character varying NOT NULL,
    name character varying NOT NULL,
    head_user_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.departments OWNER TO postgres;

--
-- Name: TABLE departments; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.departments IS 'Organizational units within a tenant (academic departments, administrative offices, service units). head_user_id points to the department head. Used as a FK target by hr.staff_profiles, finance.gl_accounts, workflow.forms, policy.documents, and collab.workspaces for organizational scoping.';


--
-- Name: edfi_sync_logs; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.edfi_sync_logs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    edfi_api_base_url character varying(512) NOT NULL,
    edfi_school_year smallint NOT NULL,
    external_credential_id uuid,
    resource_types text[] DEFAULT '{}'::text[] NOT NULL,
    records_posted integer DEFAULT 0 NOT NULL,
    records_put integer DEFAULT 0 NOT NULL,
    records_deleted integer DEFAULT 0 NOT NULL,
    records_failed integer DEFAULT 0 NOT NULL,
    error_detail jsonb,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone
);


ALTER TABLE core.edfi_sync_logs OWNER TO postgres;

--
-- Name: TABLE edfi_sync_logs; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.edfi_sync_logs IS 'Ed-Fi ODS/API sync log for K-12 state longitudinal data reporting. K-12 districts in states that mandate Ed-Fi reporting must push student, enrollment, attendance, grade, and assessment data to their state Ed-Fi API endpoint. This table tracks each sync run so the district can demonstrate compliance to state auditors.';


--
-- Name: emergency_contacts; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.emergency_contacts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    first_name character varying(100) NOT NULL,
    last_name character varying(100) NOT NULL,
    relationship character varying(100) NOT NULL,
    phone_number character varying(50) NOT NULL,
    email_address character varying(255),
    is_primary boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.emergency_contacts OWNER TO postgres;

--
-- Name: TABLE emergency_contacts; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.emergency_contacts IS 'Emergency contact persons for a user. is_primary marks the first contact to attempt. Uses cross_tenant_user_isolation RLS so contacts are visible in any of the user''s tenant contexts.';


--
-- Name: external_id_registry; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.external_id_registry (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_system core.external_system NOT NULL,
    entity_type character varying(50) NOT NULL,
    internal_id uuid NOT NULL,
    external_id character varying(255) NOT NULL,
    external_id_2 character varying(255),
    migration_job_id uuid,
    is_active boolean DEFAULT true NOT NULL,
    last_synced_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.external_id_registry OWNER TO postgres;

--
-- Name: TABLE external_id_registry; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.external_id_registry IS 'Bidirectional ID mapping between external systems and eduSuite. Solves the migration de-duplication problem: before inserting a record, the migration service checks this table — if the external ID is found, the record already exists and only needs updating, not inserting. Also drives ongoing sync: when Banner fires a student update event, the sync service looks up the internal_id and updates the correct record. entity_type uses eduSuite schema table names for consistency: ''sis.students'', ''sis.course_sections'', ''finance.vendors'', etc.';


--
-- Name: external_system_credentials; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.external_system_credentials (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_system core.external_system NOT NULL,
    credential_type core.external_credential_type NOT NULL,
    name character varying(100) NOT NULL,
    description text,
    credentials_enc jsonb NOT NULL,
    base_url character varying(512),
    token_expires_at timestamp with time zone,
    granted_scopes text[],
    last_verified_at timestamp with time zone,
    last_failed_at timestamp with time zone,
    failure_reason text,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.external_system_credentials OWNER TO postgres;

--
-- Name: TABLE external_system_credentials; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.external_system_credentials IS 'Encrypted credentials for outbound calls to external platforms. credentials_enc is a JSONB envelope encrypted by the platform KMS — the Rust integration service decrypts at call time, never stores plaintext. idx_external_system_credentials_expiring drives the token refresh worker that proactively refreshes OAuth tokens before they expire. Supports every credential pattern needed for Banner, Canvas, Workday, Stripe, Zoom, Turnitin, and the NSC clearinghouse.';


--
-- Name: feature_flags; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.feature_flags (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid,
    flag_name character varying(100) NOT NULL,
    is_enabled boolean DEFAULT false NOT NULL,
    config jsonb,
    description text,
    enabled_by_user_id uuid,
    expires_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.feature_flags OWNER TO postgres;

--
-- Name: TABLE feature_flags; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.feature_flags IS 'Per-tenant feature flags for gradual rollout and beta features. Resolution order: tenant-specific flag overrides platform-wide default. The Rust middleware checks: SELECT is_enabled FROM core.feature_flags WHERE flag_name = $1 AND (tenant_id = $2 OR tenant_id IS NULL) ORDER BY tenant_id NULLS LAST LIMIT 1. expires_at enables time-boxed beta access that auto-reverts.';


--
-- Name: ims_rostering_syncs; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.ims_rostering_syncs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_system core.external_system NOT NULL,
    external_credential_id uuid,
    sync_type character varying(30) DEFAULT 'full'::character varying NOT NULL,
    entities_synced text[] DEFAULT '{}'::text[] NOT NULL,
    records_sent integer DEFAULT 0 NOT NULL,
    records_accepted integer DEFAULT 0 NOT NULL,
    records_rejected integer DEFAULT 0 NOT NULL,
    error_detail jsonb,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    initiated_by_service character varying(100)
);


ALTER TABLE core.ims_rostering_syncs OWNER TO postgres;

--
-- Name: TABLE ims_rostering_syncs; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.ims_rostering_syncs IS 'IMS OneRoster 1.2 sync log for K-12 district rostering integrations. K-12 districts must sync roster data to Google Classroom, Clever, ClassLink, and state systems daily. This table tracks each sync run and records errors from the receiving system so the district IT team can diagnose and correct issues without a support ticket.';


--
-- Name: migration_field_mappings; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.migration_field_mappings (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_system core.external_system NOT NULL,
    entity_type character varying(50) NOT NULL,
    source_field character varying(200) NOT NULL,
    target_field character varying(200) NOT NULL,
    transform_type character varying(30) DEFAULT 'direct'::character varying NOT NULL,
    value_map jsonb,
    source_date_format character varying(50),
    default_value text,
    transform_expression text,
    is_required boolean DEFAULT false NOT NULL,
    skip_if_null boolean DEFAULT true NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.migration_field_mappings OWNER TO postgres;

--
-- Name: TABLE migration_field_mappings; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.migration_field_mappings IS 'Field-level mapping configuration between source system and eduSuite. Handles the real complexity of migrations: Banner stores enrollment status as EN/W/D/AU; eduSuite uses enrolled/withdrawn/dropped/audit. The value_map JSONB stores the complete translation dictionary. Date format differences (Banner YYYYMMDD vs ISO 8601) are handled by transform_type = date_format with source_date_format = "%Y%m%d". These mappings are re-used for every migration job of the same type, so defining them once covers initial migration and all delta syncs.';


--
-- Name: migration_jobs; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.migration_jobs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    job_name character varying(100) NOT NULL,
    external_system core.external_system NOT NULL,
    entity_type character varying(50) NOT NULL,
    status core.migration_status DEFAULT 'draft'::core.migration_status NOT NULL,
    source_config jsonb DEFAULT '{}'::jsonb NOT NULL,
    is_dry_run boolean DEFAULT true NOT NULL,
    allow_overwrite boolean DEFAULT false NOT NULL,
    records_discovered integer DEFAULT 0 NOT NULL,
    records_validated integer DEFAULT 0 NOT NULL,
    records_imported integer DEFAULT 0 NOT NULL,
    records_updated integer DEFAULT 0 NOT NULL,
    records_skipped integer DEFAULT 0 NOT NULL,
    records_failed integer DEFAULT 0 NOT NULL,
    started_at timestamp with time zone,
    completed_at timestamp with time zone,
    failed_at timestamp with time zone,
    failure_reason text,
    initiated_by_user_id uuid,
    initiated_by_service character varying(100),
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT migration_jobs_counts_non_negative CHECK (((records_discovered >= 0) AND (records_validated >= 0) AND (records_imported >= 0) AND (records_failed >= 0)))
);


ALTER TABLE core.migration_jobs OWNER TO postgres;

--
-- Name: TABLE migration_jobs; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.migration_jobs IS 'Data migration job tracking. One row per import run. is_dry_run = true runs full validation without writing records — the tenant can see exactly what will happen before committing. allow_overwrite = false (default) means re-running a job after a partial import will skip records already in external_id_registry, preventing duplicates. allow_overwrite = true updates existing records — used for delta sync during the parallel-operation phase.';


--
-- Name: migration_validation_results; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.migration_validation_results (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    job_id uuid NOT NULL,
    external_id character varying(255) NOT NULL,
    source_row_number integer,
    is_valid boolean NOT NULL,
    validation_errors jsonb,
    target_internal_id uuid,
    is_existing_record boolean DEFAULT false NOT NULL,
    transformed_record jsonb,
    validated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.migration_validation_results OWNER TO postgres;

--
-- Name: TABLE migration_validation_results; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.migration_validation_results IS 'Per-record validation results from migration dry-runs and live imports. validation_errors JSONB stores structured errors with field names and human-readable messages so the tenant''s IT staff know exactly which source records need fixing before the live import. transformed_record stores the record as it would be written, enabling the tenant to review what their data will look like in eduSuite before committing. Rows are deleted after successful import to prevent unbounded table growth.';


--
-- Name: module_activation_log; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.module_activation_log (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
