ALTER TABLE core.module_activation_log OWNER TO postgres;

--
-- Name: TABLE module_activation_log; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.module_activation_log IS 'Immutable audit log of module subscription lifecycle events. Drives the "land and expand" cohort analysis: which module did tenants start with? How long before they added the next module? Which modules have highest expansion rates from trial to paid?';


--
-- Name: module_catalog; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.module_catalog (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    module_name core.module_name NOT NULL,
    display_name character varying(100) NOT NULL,
