);


ALTER TABLE core.module_catalog OWNER TO postgres;

--
-- Name: TABLE module_catalog; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.module_catalog IS 'Master list of subscribable eduSuite modules. Managed by the platform team. requires_modules enforces dependency rules: a tenant subscribing to lms must also have sis active (lms needs enrollment data). The Rust subscription service validates dependencies on every module change.';


--
-- Name: COLUMN module_catalog.is_platform_service; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.module_catalog.is_platform_service IS 'Platform services are always included with any subscription at no additional module charge. They are infrastructure, not features. The subscription UI does not show platform services as purchasable items.';


--
-- Name: COLUMN module_catalog.recommended_modules; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.module_catalog.recommended_modules IS 'Modules that pair well with this one — shown in the subscription UI as "better together" suggestions. Never enforced as hard gates. A tenant can always subscribe to any module without the recommended ones.';


--
-- Name: module_recommendations; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.module_recommendations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    module_name core.module_name NOT NULL,
    recommended_module core.module_name NOT NULL,
    recommendation_text text NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    CONSTRAINT module_recommendations_no_self CHECK ((module_name <> recommended_module))
);


ALTER TABLE core.module_recommendations OWNER TO postgres;

--
-- Name: TABLE module_recommendations; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.module_recommendations IS 'Better-together module pairing suggestions shown in the subscription UI. Never enforced as hard gates — a tenant can always subscribe to any module without its recommended companions. recommendation_text is the copy shown to the tenant in the UI when they are browsing modules they have not yet subscribed to.';


--
-- Name: tenant_memberships; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.tenant_memberships (
