);


ALTER TABLE core.tenant_subscriptions OWNER TO postgres;

--
-- Name: TABLE tenant_subscriptions; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.tenant_subscriptions IS 'Active module subscriptions per tenant. The Rust API middleware checks WHERE tenant_id = $1 AND module_name = $2 AND status = ''active'' on every request to enforce module-level access. stripe_subscription_id links to the Stripe billing record. max_students and max_staff enforce tier limits at the application layer. The module_name column is denormalized (also in module_catalog) to avoid a JOIN on every API request.';


--
-- Name: tenants; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.tenants (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(255) NOT NULL,
    domain character varying(255) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    country_iso_alpha2 character(2),
    subdivision_code character varying(10),
    is_tax_exempt boolean DEFAULT false NOT NULL,
    tax_exempt_type character varying(50),
    tax_exempt_number character varying(100),
    base_currency_code character(3) DEFAULT 'USD'::bpchar NOT NULL,
    fiscal_year_end_month smallint DEFAULT 6 NOT NULL,
    CONSTRAINT tenants_fiscal_month_range CHECK (((fiscal_year_end_month >= 1) AND (fiscal_year_end_month <= 12)))
);


ALTER TABLE core.tenants OWNER TO postgres;

--
-- Name: TABLE tenants; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.tenants IS 'The root multi-tenancy record. Each row represents one school, district, or institution. domain is unique across the platform and drives subdomain routing. Every tenant-scoped table enforces tenant_id = current_setting(''app.current_tenant_id'')::uuid via RESTRICTIVE RLS policy.';


--
-- Name: COLUMN tenants.country_iso_alpha2; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.tenants.country_iso_alpha2 IS 'Primary country of operation (ISO 3166-1 alpha-2). Determines the base tax regime: US triggers sales tax framework, EU/UK triggers VAT, Canada triggers GST/HST, etc. Required before any tax configuration.';


--
-- Name: COLUMN tenants.is_tax_exempt; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.tenants.is_tax_exempt IS 'Whether this institution has a general tax-exempt status. US 501(c)(3) educational institutions are exempt from federal income tax and often from state sales tax on purchases (but not always on sales). Drives both AP (purchase exemption certificates) and AR (sales tax collection).';


--
-- Name: COLUMN tenants.base_currency_code; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON COLUMN core.tenants.base_currency_code IS 'ISO 4217 currency code for this tenant''s functional currency. Used as the reporting currency for all GL entries. Transactions in other currencies are converted at the exchange rate stored in finance.currency_exchange_rates.';


--
-- Name: user_addresses; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.user_addresses (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    type core.address_type NOT NULL,
    street_1 character varying(255) NOT NULL,
    street_2 character varying(255),
    city character varying(100) NOT NULL,
    state_province character varying(100) NOT NULL,
    postal_code character varying(20) NOT NULL,
    is_current boolean DEFAULT true NOT NULL,
    effective_start_date date DEFAULT CURRENT_DATE NOT NULL,
    effective_end_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    country_iso_alpha2 character(2),
    subdivision_code character varying(10),
    timezone_identifier character varying(100),
    is_verified boolean DEFAULT false NOT NULL,
    verification_source character varying(50),
    last_verified_at timestamp with time zone,
    delivery_point_status character varying(50),
    latitude numeric(10,7),
    longitude numeric(10,7),
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.user_addresses OWNER TO postgres;

--
-- Name: TABLE user_addresses; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.user_addresses IS 'Physical addresses with full temporal validity (effective_start_date / effective_end_date). is_current flags the active address. Linked to reference.subdivisions and reference.countries for standardization. delivery_point_status records USPS CASS/DPV certification result. latitude/longitude enable geospatial queries via PostGIS.';


--
-- Name: user_emails; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.user_emails (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    email_address character varying(255) NOT NULL,
    type core.email_type DEFAULT 'personal'::core.email_type NOT NULL,
    is_primary boolean DEFAULT false NOT NULL,
    is_verified boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.user_emails OWNER TO postgres;

--
-- Name: TABLE user_emails; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.user_emails IS 'Email addresses associated with a user. A user may have multiple addresses (personal, institutional, alumni). is_primary marks the default delivery address. is_verified tracks email confirmation status via auth_governance.email_verification_tokens. The global unique constraint on email_address prevents address sharing across users.';


--
-- Name: user_name_history; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.user_name_history (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    historical_first_name character varying(100) NOT NULL,
    historical_middle_name character varying(100),
    historical_last_name character varying(100) NOT NULL,
    reason core.name_change_reason NOT NULL,
    changed_by_user_id uuid,
    changed_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.user_name_history OWNER TO postgres;

--
-- Name: TABLE user_name_history; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.user_name_history IS 'Immutable log of legal name changes. Captures the historical name, the reason (e.g., legal_name_change, correction, marriage), and the staff member who made the change. Append-only; no updates ever. Required for FERPA transcript accuracy and Title IX compliance.';


--
-- Name: user_phones; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.user_phones (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    phone_number character varying(50) NOT NULL,
    country_code character varying(10) DEFAULT '+1'::character varying NOT NULL,
    type core.phone_type DEFAULT 'mobile'::core.phone_type NOT NULL,
    is_primary boolean DEFAULT false NOT NULL,
    can_receive_sms boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE core.user_phones OWNER TO postgres;

--
-- Name: TABLE user_phones; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.user_phones IS 'Phone numbers associated with a user. can_receive_sms controls whether the comms engine may use this number for SMS delivery. country_code and phone_number are stored separately for E.164 formatting.';


--
-- Name: user_roles; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.user_roles (
    tenant_id uuid NOT NULL,
    user_id uuid NOT NULL,
    role core.system_role NOT NULL,
    granted_at timestamp with time zone DEFAULT now() NOT NULL,
    granted_by_user_id uuid,
    expires_at timestamp with time zone,
    revoked_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT user_roles_expiry_after_grant CHECK (((expires_at IS NULL) OR (expires_at > granted_at)))
);


ALTER TABLE core.user_roles OWNER TO postgres;

--
-- Name: TABLE user_roles; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.user_roles IS 'Fine-grained role grants within a tenant. A user may hold multiple rows here (e.g., faculty + advisor + department_chair). PK is (tenant_id, user_id, role) — a triple must be unique. granted_by_user_id provides the audit trail for privilege escalation. expires_at supports time-bounded grants (e.g., acting department head). revoked_at soft-revokes without losing history. Partial indexes on revoked_at IS NULL keep active-role lookups fast.';


--
-- Name: vw_migration_status; Type: VIEW; Schema: core; Owner: postgres
--

CREATE VIEW core.vw_migration_status AS
 SELECT mj.tenant_id,
    t.name AS tenant_name,
    mj.id AS job_id,
    mj.job_name,
    mj.external_system,
    mj.entity_type,
    mj.status,
    mj.is_dry_run,
    mj.records_discovered,
    mj.records_imported,
    mj.records_failed,
    mj.records_skipped,
        CASE
            WHEN (mj.records_discovered > 0) THEN round((((mj.records_imported)::numeric / (mj.records_discovered)::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS completion_pct,
        CASE
            WHEN (mj.records_discovered > 0) THEN round((((mj.records_failed)::numeric / (mj.records_discovered)::numeric) * (100)::numeric), 2)
            ELSE (0)::numeric
        END AS error_rate_pct,
    mj.started_at,
    mj.completed_at,
    mj.failure_reason,
    ( SELECT count(*) AS count
           FROM core.external_id_registry eir
          WHERE ((eir.tenant_id = mj.tenant_id) AND (eir.migration_job_id = mj.id))) AS ids_registered
   FROM (core.migration_jobs mj
     JOIN core.tenants t ON ((t.id = mj.tenant_id)));


ALTER VIEW core.vw_migration_status OWNER TO postgres;

--
-- Name: VIEW vw_migration_status; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON VIEW core.vw_migration_status IS 'Migration job dashboard with completion percentage and error rate. ids_registered shows how many external ID mappings have been created, confirming that the external_id_registry is being populated correctly (which prevents duplicate record creation on re-runs).';


--
-- Name: vw_module_adoption; Type: VIEW; Schema: core; Owner: postgres
--

CREATE VIEW core.vw_module_adoption AS
 SELECT t.id AS tenant_id,
    t.name AS tenant_name,
    mc.module_name,
    mc.display_name,
    mc.display_order,
    ts.status,
    ts.tier,
    ts.activated_at,
        CASE
            WHEN (ts.id IS NULL) THEN 'not_subscribed'::text
            ELSE (ts.status)::text
        END AS adoption_status
   FROM ((core.tenants t
     CROSS JOIN core.module_catalog mc)
     LEFT JOIN core.tenant_subscriptions ts ON (((ts.tenant_id = t.id) AND (ts.module_name = mc.module_name))))
  WHERE ((mc.is_available = true) AND (mc.is_platform_service = false))
  ORDER BY t.name, mc.display_order;


ALTER VIEW core.vw_module_adoption OWNER TO postgres;

--
-- Name: vw_tenant_active_modules; Type: VIEW; Schema: core; Owner: postgres
--

CREATE VIEW core.vw_tenant_active_modules AS
 SELECT ts.tenant_id,
    t.name AS tenant_name,
    ts.module_name,
    mc.display_name,
    mc.is_platform_service,
    ts.tier,
    ts.status,
    ts.max_students,
    ts.max_api_calls_per_day,
    ts.activated_at,
    ts.stripe_subscription_id
   FROM ((core.tenant_subscriptions ts
     JOIN core.tenants t ON ((t.id = ts.tenant_id)))
     JOIN core.module_catalog mc ON ((mc.id = ts.module_id)))
  WHERE (ts.status = 'active'::core.subscription_status);


ALTER VIEW core.vw_tenant_active_modules OWNER TO postgres;

--
-- Name: webhook_deliveries; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.webhook_deliveries (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    endpoint_id uuid NOT NULL,
    outbox_event_id uuid NOT NULL,
    event_name character varying(150) NOT NULL,
    attempt_number smallint DEFAULT 1 NOT NULL,
    status core.webhook_delivery_status DEFAULT 'pending'::core.webhook_delivery_status NOT NULL,
    request_headers jsonb,
    request_body text,
    response_status_code smallint,
    response_body text,
    response_duration_ms integer,
    attempted_at timestamp with time zone DEFAULT now() NOT NULL,
    next_retry_at timestamp with time zone,
    completed_at timestamp with time zone,
    failure_reason text,
    CONSTRAINT webhook_deliveries_attempt_positive CHECK ((attempt_number > 0))
);


ALTER TABLE core.webhook_deliveries OWNER TO postgres;

--
-- Name: TABLE webhook_deliveries; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.webhook_deliveries IS 'Per-attempt webhook delivery log. Append-only — retries create new rows. Provides the tenant with a full delivery audit trail in their dashboard. response_body is truncated to 4KB to prevent unbounded storage growth. The Rust delivery service queries WHERE status IN (pending, retrying) AND next_retry_at <= now() to find deliveries due for retry.';


--
-- Name: webhook_endpoints; Type: TABLE; Schema: core; Owner: postgres
--

CREATE TABLE core.webhook_endpoints (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    endpoint_url character varying(2048) NOT NULL,
    signing_secret_enc text NOT NULL,
    event_name_patterns text[] DEFAULT '{}'::text[] NOT NULL,
    filter_expression jsonb,
    custom_headers jsonb,
    max_retries smallint DEFAULT 5 NOT NULL,
    retry_backoff_secs integer DEFAULT 60 NOT NULL,
    timeout_secs smallint DEFAULT 30 NOT NULL,
    module_name core.module_name,
    is_active boolean DEFAULT true NOT NULL,
    consecutive_failures integer DEFAULT 0 NOT NULL,
    last_success_at timestamp with time zone,
    last_failure_at timestamp with time zone,
    last_failure_reason text,
    auto_disable_threshold smallint DEFAULT 10 NOT NULL,
    disabled_at timestamp with time zone,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT webhook_endpoints_timeout_positive CHECK (((timeout_secs > 0) AND (max_retries >= 0))),
    CONSTRAINT webhook_endpoints_url_not_localhost CHECK ((((endpoint_url)::text !~~ '%localhost%'::text) AND ((endpoint_url)::text !~~ '%127.0.0.1%'::text)))
);


ALTER TABLE core.webhook_endpoints OWNER TO postgres;

--
-- Name: TABLE webhook_endpoints; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON TABLE core.webhook_endpoints IS 'Tenant-configured webhook endpoints for push event delivery. The Rust event delivery service reads this table to fan out events from event_bus.outbox to external systems. signing_secret_enc is encrypted at rest using the platform key management service. consecutive_failures drives auto-disable: an endpoint that fails auto_disable_threshold times in a row is disabled and the tenant alerted. The localhost CHECK prevents SSRF attacks via internal network webhooks.';


--
-- Name: vw_webhook_health; Type: VIEW; Schema: core; Owner: postgres
--

CREATE VIEW core.vw_webhook_health AS
 SELECT tenant_id,
    id AS endpoint_id,
    name,
    endpoint_url,
    event_name_patterns,
    consecutive_failures,
    last_success_at,
    last_failure_at,
    last_failure_reason,
    is_active,
    disabled_at,
        CASE
            WHEN (disabled_at IS NOT NULL) THEN 'disabled'::text
            WHEN (consecutive_failures = 0) THEN 'healthy'::text
            WHEN (consecutive_failures < 3) THEN 'degraded'::text
            WHEN (consecutive_failures < auto_disable_threshold) THEN 'failing'::text
            ELSE 'critical'::text
        END AS health_status,
    ( SELECT ((count(*) FILTER (WHERE (wd.status = 'succeeded'::core.webhook_delivery_status)))::numeric / (NULLIF(count(*), 0))::numeric)
           FROM core.webhook_deliveries wd
          WHERE ((wd.endpoint_id = we.id) AND (wd.attempted_at > (now() - '24:00:00'::interval)))) AS success_rate_24h
   FROM core.webhook_endpoints we;


ALTER VIEW core.vw_webhook_health OWNER TO postgres;

--
-- Name: VIEW vw_webhook_health; Type: COMMENT; Schema: core; Owner: postgres
--

COMMENT ON VIEW core.vw_webhook_health IS 'Webhook endpoint health dashboard. health_status (healthy/degraded/failing/critical/disabled) drives the tenant integration dashboard. success_rate_24h computes a rolling 24-hour delivery success rate from webhook_deliveries for each endpoint.';


