--
-- Name: vw_current_consents; Type: VIEW; Schema: data_governance; Owner: postgres
--

CREATE VIEW data_governance.vw_current_consents AS
 SELECT DISTINCT ON (cr.tenant_id, cr.user_id, cr.consent_type_id) cr.tenant_id,
    cr.user_id,
    cr.consent_type_id,
    ct.consent_key,
    ct.display_name,
    cr.status,
    cr.consent_version,
    cr.recorded_at AS status_as_of,
    cr.expires_at,
    cr.guardian_user_id
   FROM (data_governance.consent_records cr
     JOIN data_governance.consent_types ct ON ((cr.consent_type_id = ct.id)))
  ORDER BY cr.tenant_id, cr.user_id, cr.consent_type_id, cr.recorded_at DESC;


