COMMENT ON TABLE dms.document_acls IS 'Access control list entry on an individual document. Same structure as folder_acls but scoped to a document, enabling per-document permission overrides when inherits_permissions = false.';


--
-- Name: document_links; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.document_links (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    document_id uuid NOT NULL,
