);


ALTER TABLE dms.document_links OWNER TO postgres;

--
-- Name: TABLE document_links; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.document_links IS 'Polymorphic association between a document and any record in any schema, identified by target_table (e.g., ''sis.student_documents'') and target_record_id. Enables the DMS to serve as the file backend for student transcripts, HR contracts, policy versions, board attachments, and any other document-bearing entity without requiring a FK column on every table.';


--
-- Name: document_versions; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.document_versions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    document_id uuid NOT NULL,
    version_number integer NOT NULL,
    file_name character varying(255) NOT NULL,
    mime_type character varying(100) NOT NULL,
    file_size_bytes bigint NOT NULL,
    storage_key character varying(1024),
    extracted_ocr_text text,
    uploaded_by_id uuid,
    uploaded_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(file_name, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(extracted_ocr_text, ''::text)), 'B'::"char"))) STORED
);


ALTER TABLE dms.document_versions OWNER TO postgres;

--
-- Name: TABLE document_versions; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.document_versions IS 'A specific file version of a document. version_number increments monotonically. storage_key is the object storage path. extracted_ocr_text and fts_doc support full-text search across document contents. The unique constraint enforces version uniqueness per document.';


--
-- Name: documents; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.documents (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    folder_id uuid,
    retention_policy_id uuid,
    title character varying(255) NOT NULL,
    document_status dms.document_status DEFAULT 'active'::dms.document_status NOT NULL,
    scheduled_destruction_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    inherits_permissions boolean DEFAULT true NOT NULL
);


ALTER TABLE dms.documents OWNER TO postgres;

--
-- Name: TABLE documents; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.documents IS 'A logical document record. The current file lives in the most recent document_versions row. document_status tracks lifecycle (active, archived, pending_destruction, destroyed). retention_policy_id links to the governing retention schedule. scheduled_destruction_date is computed from the retention policy and set by the data governance service. inherits_permissions controls ACL inheritance from the parent folder.';


--
-- Name: folder_acls; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.folder_acls (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    folder_id uuid NOT NULL,
    granted_to_user_id uuid,
    granted_to_system_role core.system_role,
    permission_level dms.permission_level NOT NULL,
    created_by_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT chk_folder_acl_target CHECK ((((granted_to_user_id IS NOT NULL) AND (granted_to_system_role IS NULL)) OR ((granted_to_user_id IS NULL) AND (granted_to_system_role IS NOT NULL))))
);


ALTER TABLE dms.folder_acls OWNER TO postgres;

--
-- Name: TABLE folder_acls; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.folder_acls IS 'Access control list entry on a folder. Grants a permission_level (read, write, admin) to either a specific user (granted_to_user_id) or a system_role (granted_to_system_role). The chk_folder_acl_target constraint enforces exactly one grantee type. The unique constraints prevent duplicate grants for the same folder+user and folder+role pairs.';


--
-- Name: folders; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.folders (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    parent_folder_id uuid,
    name character varying(255) NOT NULL,
    owning_department_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    inherits_permissions boolean DEFAULT true NOT NULL
);


ALTER TABLE dms.folders OWNER TO postgres;

--
-- Name: TABLE folders; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.folders IS 'A named folder in the document hierarchy. Supports unlimited nesting via parent_folder_id. owning_department_id assigns departmental ownership for access control default assignment. inherits_permissions controls whether child documents inherit this folder''s ACL or define their own. The unique constraint scopes folder names to (tenant, parent_folder_id).';


--
-- Name: retention_policies; Type: TABLE; Schema: dms; Owner: postgres
--

CREATE TABLE dms.retention_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    trigger_event dms.retention_trigger NOT NULL,
    retention_years integer DEFAULT 0 NOT NULL,
    requires_approval_before_destruction boolean DEFAULT true CONSTRAINT retention_policies_requires_approval_before_destructio_not_null NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE dms.retention_policies OWNER TO postgres;

--
-- Name: TABLE retention_policies; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON TABLE dms.retention_policies IS 'Document-level retention schedule definitions. retention_years specifies how long after trigger_event the document must be kept. requires_approval_before_destruction gates automated destruction. Note: for regulation-level retention schedules (FERPA, HIPAA, etc.) see data_governance.retention_schedules; this table handles the document-operational configuration that references those schedules.';


--
-- Name: vw_resolved_document_permissions; Type: VIEW; Schema: dms; Owner: postgres
--

CREATE VIEW dms.vw_resolved_document_permissions AS
 WITH RECURSIVE folder_tree AS (
         SELECT folders.id AS folder_id,
            folders.id AS root_folder_id,
            folders.inherits_permissions
           FROM dms.folders
          WHERE (folders.parent_folder_id IS NULL)
        UNION ALL
         SELECT f.id AS folder_id,
            ft.root_folder_id,
            f.inherits_permissions
           FROM (dms.folders f
             JOIN folder_tree ft ON ((f.parent_folder_id = ft.folder_id)))
        )
 SELECT doc.tenant_id,
    doc.id AS document_id,
    COALESCE(doc_acl.granted_to_user_id, folder_acl.granted_to_user_id) AS user_id,
    COALESCE(doc_acl.granted_to_system_role, folder_acl.granted_to_system_role) AS system_role,
    COALESCE(doc_acl.permission_level, folder_acl.permission_level) AS effective_permission
   FROM ((dms.documents doc
     LEFT JOIN dms.document_acls doc_acl ON (((doc.id = doc_acl.document_id) AND (doc.inherits_permissions = false))))
     LEFT JOIN dms.folder_acls folder_acl ON (((doc.folder_id = folder_acl.folder_id) AND (doc.inherits_permissions = true))));


ALTER VIEW dms.vw_resolved_document_permissions OWNER TO postgres;

--
-- Name: VIEW vw_resolved_document_permissions; Type: COMMENT; Schema: dms; Owner: postgres
--

COMMENT ON VIEW dms.vw_resolved_document_permissions IS 'Resolves the effective permission for each (document, user/role) pair, walking the ACL inheritance chain from document → folder → parent folders. Returns the most permissive applicable grant. Consumed by the Rust DMS service to perform a single authorization check without recursive queries in application code.';


--
