COMMENT ON TABLE event_bus.event_types IS 'Canonical event catalog. Platform-level — not tenant-scoped. All event_name values in outbox rows should match a row here. Payload schemas are informational; enforcement is in the Rust type system.';


--
-- Name: outbox; Type: TABLE; Schema: event_bus; Owner: postgres
--

CREATE TABLE event_bus.outbox (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    event_name character varying(150) NOT NULL,
    payload_version character varying(20) DEFAULT '1.0'::character varying NOT NULL,
    aggregate_type character varying(128) NOT NULL,
    aggregate_id uuid NOT NULL,
    payload jsonb NOT NULL,
    correlation_id uuid,
    causation_id uuid,
    producer_service character varying(100) NOT NULL,
    actor_user_id uuid,
    status event_bus.outbox_status DEFAULT 'pending'::event_bus.outbox_status NOT NULL,
    attempt_count smallint DEFAULT 0 NOT NULL,
    max_attempts smallint DEFAULT 5 NOT NULL,
    next_attempt_at timestamp with time zone DEFAULT now() NOT NULL,
    locked_by character varying(100),
    locked_at timestamp with time zone,
    processed_at timestamp with time zone,
    dead_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT outbox_attempt_count_lte_max CHECK ((attempt_count <= (max_attempts + 1))),
    CONSTRAINT outbox_attempt_count_non_negative CHECK ((attempt_count >= 0)),
    CONSTRAINT outbox_dead_requires_status CHECK (((dead_at IS NULL) OR (status = 'dead'::event_bus.outbox_status))),
    CONSTRAINT outbox_max_attempts_positive CHECK ((max_attempts > 0)),
    CONSTRAINT outbox_processed_requires_status CHECK (((processed_at IS NULL) OR (status = 'processed'::event_bus.outbox_status)))
)
PARTITION BY RANGE (created_at);


ALTER TABLE event_bus.outbox OWNER TO postgres;

--
-- Name: TABLE outbox; Type: COMMENT; Schema: event_bus; Owner: postgres
--

COMMENT ON TABLE event_bus.outbox IS 'Core outbox table. Append-only by application services. Range-partitioned by created_at (monthly). Relay polls via vw_pending_events with SELECT FOR UPDATE SKIP LOCKED. Terminal statuses (processed, dead) are enforced immutable by trigger.';


--
-- Name: outbox_y2026m04; Type: TABLE; Schema: event_bus; Owner: postgres
--

CREATE TABLE event_bus.outbox_y2026m04 (
