    CONSTRAINT saga_instances_failure_needs_reason CHECK (((status <> ALL (ARRAY['failed'::event_bus.saga_status, 'compensating'::event_bus.saga_status, 'compensated'::event_bus.saga_status])) OR (failure_reason IS NOT NULL)))
);


