--
-- Name: vw_dead_letter_dashboard; Type: VIEW; Schema: event_bus; Owner: postgres
--

CREATE VIEW event_bus.vw_dead_letter_dashboard AS
 SELECT dl.id,
    dl.tenant_id,
    t.name AS tenant_name,
    dl.event_name,
    dl.aggregate_type,
    dl.aggregate_id,
    dl.producer_service,
    dl.failing_subscriber,
    dl.last_error,
    dl.total_attempts,
    dl.is_acknowledged,
    dl.requeued_at,
    dl.died_at,
    round((EXTRACT(epoch FROM (now() - dl.died_at)) / 3600.0), 1) AS hours_dead
   FROM (event_bus.dead_letters dl
     JOIN core.tenants t ON ((t.id = dl.tenant_id)))
  WHERE ((dl.is_acknowledged = false) AND (dl.requeued_at IS NULL))
  ORDER BY dl.died_at;


ALTER VIEW event_bus.vw_dead_letter_dashboard OWNER TO postgres;

--
-- Name: vw_pending_events; Type: VIEW; Schema: event_bus; Owner: postgres
--

CREATE VIEW event_bus.vw_pending_events AS
 SELECT id,
    tenant_id,
    event_name,
    payload_version,
    aggregate_type,
    aggregate_id,
    payload,
    correlation_id,
    causation_id,
    producer_service,
    actor_user_id,
    attempt_count,
    max_attempts,
    next_attempt_at,
    created_at,
    (EXTRACT(epoch FROM (now() - created_at)))::integer AS age_seconds
   FROM event_bus.outbox o
  WHERE ((status = 'pending'::event_bus.outbox_status) AND (next_attempt_at <= now()))
  ORDER BY next_attempt_at, created_at;


ALTER VIEW event_bus.vw_pending_events OWNER TO postgres;

