--
-- Name: economic_nexus_monitoring; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.economic_nexus_monitoring (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    jurisdiction_id uuid NOT NULL,
