    transaction_threshold integer,
    revenue_threshold_pct numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (revenue_threshold > (0)::numeric) THEN round(((trailing_12m_revenue / revenue_threshold) * (100)::numeric), 2)
    ELSE (0)::numeric
END) STORED,
    nexus_triggered boolean DEFAULT false NOT NULL,
    calculated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT economic_nexus_monitoring_revenue_non_negative CHECK (((trailing_12m_revenue >= (0)::numeric) AND (trailing_12m_transactions >= 0)))
);


ALTER TABLE finance.economic_nexus_monitoring OWNER TO postgres;

--
-- Name: TABLE economic_nexus_monitoring; Type: COMMENT; Schema: finance; Owner: postgres
