-- Name: TABLE endowment_fund_records; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.endowment_fund_records IS 'Annual endowment fund activity per FASB ASC 958-205 and UPMIFA. is_underwater is a generated column — an underwater endowment (market value < historic gift value) requires additional disclosures in the financial statements. The partial index on is_underwater enables the CFO dashboard to instantly surface at-risk endowment funds. rolling_average_market_value drives the spending policy calculation at year-end (spending_policy_pct × rolling_average = spending_appropriation).';


--
-- Name: expense_line_items; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.expense_line_items (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    expense_report_id uuid NOT NULL,
    gl_account_id uuid NOT NULL,
    category finance.expense_category NOT NULL,
    transaction_date date NOT NULL,
    merchant_name character varying(255),
    amount numeric(10,2) NOT NULL,
    receipt_url character varying(1024),
    notes text,
    is_approved boolean DEFAULT true,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.expense_line_items OWNER TO postgres;

--
-- Name: TABLE expense_line_items; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.expense_line_items IS 'Individual receipts within an expense report. is_approved can be set per line item to allow partial approvals. category and merchant_name support expense policy enforcement and reporting.';


--
-- Name: expense_reports; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.expense_reports (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    employee_id uuid NOT NULL,
    travel_authorization_id uuid NOT NULL,
    title character varying NOT NULL,
    total_requested_amount numeric(10,2) DEFAULT 0.00 NOT NULL,
    total_approved_amount numeric(10,2) DEFAULT 0.00 NOT NULL,
    status finance.expense_status,
    submitted_at timestamp with time zone,
    paid_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.expense_reports OWNER TO postgres;

--
-- Name: TABLE expense_reports; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.expense_reports IS 'An employee expense reimbursement request. Must be linked to an approved travel_authorization. Status: draft → submitted → approved → paid → rejected. total_requested_amount vs total_approved_amount tracks any disallowed items.';


--
-- Name: fafsa_records; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.fafsa_records (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    aid_year character varying(9) NOT NULL,
    student_aid_index integer NOT NULL,
    pell_eligibility_flag boolean DEFAULT false NOT NULL,
    verification_required boolean DEFAULT false NOT NULL,
    received_date date NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    isir_transaction_number smallint,
    dependency_status finance.dependency_status DEFAULT 'U'::finance.dependency_status NOT NULL,
    efc_primary integer,
    reject_codes text[],
    c_flag boolean DEFAULT false NOT NULL,
    selected_for_verification boolean DEFAULT false NOT NULL,
    verification_group character varying(1),
    nslds_match_flags jsonb,
    isir_received_date date
);


ALTER TABLE finance.fafsa_records OWNER TO postgres;

--
-- Name: TABLE fafsa_records; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.fafsa_records IS 'FAFSA application data received from the Department of Education via the Institutional Student Information Record (ISIR). student_aid_index (SAI, formerly EFC) drives aid packaging. pell_eligibility_flag and verification_required are set from the ISIR. One record per student per aid year.';


--
-- Name: COLUMN fafsa_records.isir_transaction_number; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fafsa_records.isir_transaction_number IS 'Transaction number from the ISIR (Institutional Student Information Record). Increments each time ED issues a corrected ISIR for the same student/aid year. Required by NSLDS to trace aid transactions back to the governing ISIR. Range: 01-99.';


--
-- Name: COLUMN fafsa_records.dependency_status; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fafsa_records.dependency_status IS 'Student dependency status as determined by FAFSA: D=Dependent, I=Independent, U=Unknown. Required field in NSLDS enrollment reporting and drives aggregate loan limit eligibility.';


--
-- Name: COLUMN fafsa_records.c_flag; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fafsa_records.c_flag IS 'Whether this ISIR carries a C-flag (Comment Code indicating potential eligibility issue — typically SSN mismatch, default, or citizenship question). C-flagged ISIRs require resolution before aid can be disbursed.';


--
-- Name: COLUMN fafsa_records.verification_group; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fafsa_records.verification_group IS 'Verification tracking group (V1-V5, S, W) assigned by ED when the student is selected for verification. Required for verification reporting to ED via the Verification/Exclusion Report.';


--
-- Name: COLUMN fafsa_records.nslds_match_flags; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fafsa_records.nslds_match_flags IS 'JSONB snapshot of NSLDS data match flags from the ISIR: default status, overpayment flags, aggregate loan totals, discharge flags. Stored as-received from the ISIR batch for audit.';


--
-- Name: financial_aid_awards; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.financial_aid_awards (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    term_id uuid NOT NULL,
    fund_name character varying(100) NOT NULL,
    aid_type finance.aid_source_type NOT NULL,
    offered_amount numeric(10,2) NOT NULL,
    accepted_amount numeric(10,2) DEFAULT 0.00 NOT NULL,
    disbursed_amount numeric(10,2) DEFAULT 0.00 NOT NULL,
    status character varying(50) DEFAULT 'offered'::character varying NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    nslds_loan_type finance.nslds_loan_type,
    loan_sequence_number smallint,
    loan_period_begin_date date,
    loan_period_end_date date,
    grade_level_at_award smallint,
    capitalized_interest numeric(10,2),
    last_reported_to_nslds timestamp with time zone,
    CONSTRAINT financial_aid_awards_loan_sequence_positive CHECK (((loan_sequence_number IS NULL) OR (loan_sequence_number > 0)))
);


ALTER TABLE finance.financial_aid_awards OWNER TO postgres;

--
-- Name: TABLE financial_aid_awards; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.financial_aid_awards IS 'An individual aid award within a student''s financial aid package for a specific term. Tracks offered, accepted, and disbursed amounts separately to support award revision workflows. aid_type: pell_grant, subsidized_loan, unsubsidized_loan, institutional_grant, scholarship, work_study.';


--
-- Name: COLUMN financial_aid_awards.nslds_loan_type; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.financial_aid_awards.nslds_loan_type IS 'Federal loan type code for NSLDS reporting: SUB, UNSUB, PLUS, GPLUS, PERK. NULL for non-loan awards (grants, work-study, scholarships). Required in every NSLDS loan record transmission.';


--
-- Name: COLUMN financial_aid_awards.loan_sequence_number; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.financial_aid_awards.loan_sequence_number IS 'Loan sequence number within the student''s loan history at this institution. Required by NSLDS for loan identification. Assigned sequentially per student per loan type at the time of origination.';


--
-- Name: COLUMN financial_aid_awards.loan_period_begin_date; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.financial_aid_awards.loan_period_begin_date IS 'The first date of the academic period for which the loan was originated. Distinct from disbursement date. Required in NSLDS loan records.';


--
-- Name: COLUMN financial_aid_awards.grade_level_at_award; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.financial_aid_awards.grade_level_at_award IS 'Student''s grade level at the time the award was packaged: 1=Freshman, 2=Sophomore, 3=Junior, 4=Senior, 5=5th year undergrad, 6=Graduate. Drives Stafford aggregate loan limit enforcement.';


--
-- Name: COLUMN financial_aid_awards.last_reported_to_nslds; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.financial_aid_awards.last_reported_to_nslds IS 'Timestamp of last NSLDS submission including this award record. NULL = never reported. Used to identify new and changed records for incremental NSLDS updates.';


--
-- Name: fiscal_years; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.fiscal_years (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(50) NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    status finance.fiscal_year_status DEFAULT 'planning'::finance.fiscal_year_status NOT NULL,
    accounting_framework finance.accounting_framework,
    audit_status finance.audit_status DEFAULT 'not_required'::finance.audit_status,
    is_comparative_year boolean DEFAULT false NOT NULL,
    period_closed_at timestamp with time zone,
    closed_by_user_id uuid
);


ALTER TABLE finance.fiscal_years OWNER TO postgres;

--
-- Name: TABLE fiscal_years; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.fiscal_years IS 'Defines the institution''s fiscal year boundaries and lifecycle status (open, closing, closed). All budget lines, payroll runs, and GL entries are scoped to a fiscal year. The unique constraint prevents overlapping year names per tenant.';


--
-- Name: COLUMN fiscal_years.audit_status; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fiscal_years.audit_status IS 'External audit status. The financial statement generator requires opinion_issued before a year can be marked final.';


--
-- Name: COLUMN fiscal_years.period_closed_at; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.fiscal_years.period_closed_at IS 'When the fiscal year was formally closed. Once closed, no journal entries can be posted without a controller override.';


--
-- Name: fixed_assets; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.fixed_assets (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    asset_tag character varying(50),
    serial_number character varying(100),
    description text NOT NULL,
    asset_class finance.asset_class NOT NULL,
    acquisition_date date NOT NULL,
    acquisition_cost numeric(15,2) NOT NULL,
    acquisition_method character varying(50) DEFAULT 'purchase'::character varying NOT NULL,
    vendor_id uuid,
    purchase_order_id uuid,
    donated_fmv numeric(15,2),
    placed_in_service_date date,
    was_below_threshold boolean DEFAULT false NOT NULL,
    department_id uuid,
    building_id uuid,
    room_id uuid,
    location_description character varying(255),
    ops_vehicle_id uuid,
    depreciation_method finance.depreciation_method DEFAULT 'straight_line'::finance.depreciation_method NOT NULL,
    useful_life_years numeric(5,2),
    useful_life_units integer,
    salvage_value numeric(15,2) DEFAULT 0 NOT NULL,
    macrs_property_class character varying(10),
    macrs_convention character varying(20) DEFAULT 'half_year'::character varying NOT NULL,
    macrs_election_179 boolean DEFAULT false NOT NULL,
    macrs_election_179_amount numeric(15,2),
    macrs_bonus_depreciation_pct numeric(5,2),
    accumulated_depreciation numeric(15,2) DEFAULT 0 NOT NULL,
    net_book_value numeric(15,2) GENERATED ALWAYS AS ((acquisition_cost - accumulated_depreciation)) STORED,
    disposal_date date,
    disposal_method character varying(50),
    disposal_proceeds numeric(15,2),
    disposal_gain_loss numeric(15,2),
    asset_gl_account_id uuid NOT NULL,
    accum_depr_gl_account_id uuid,
    depr_expense_gl_account_id uuid,
    condition_rating smallint,
    condition_assessed_date date,
    net_asset_class finance.net_asset_class,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT fixed_assets_acquisition_cost_positive CHECK ((acquisition_cost > (0)::numeric)),
    CONSTRAINT fixed_assets_condition_rating_range CHECK (((condition_rating IS NULL) OR ((condition_rating >= 1) AND (condition_rating <= 5)))),
    CONSTRAINT fixed_assets_disposal_requires_date CHECK (((disposal_method IS NULL) OR (disposal_date IS NOT NULL))),
    CONSTRAINT fixed_assets_land_no_depreciation CHECK (((asset_class <> 'land'::finance.asset_class) OR (depreciation_method = 'no_depreciation'::finance.depreciation_method))),
    CONSTRAINT fixed_assets_salvage_lt_cost CHECK ((salvage_value < acquisition_cost)),
    CONSTRAINT fixed_assets_salvage_non_negative CHECK ((salvage_value >= (0)::numeric)),
    CONSTRAINT fixed_assets_useful_life_positive CHECK (((useful_life_years IS NULL) OR (useful_life_years > (0)::numeric)))
);


ALTER TABLE finance.fixed_assets OWNER TO postgres;

--
-- Name: TABLE fixed_assets; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.fixed_assets IS 'Capital asset register. Supports all depreciation methods required by GAAP, GASB, FASB, and IRS MACRS. net_book_value is a GENERATED column (acquisition_cost - accumulated_depreciation) always consistent with the accumulated depreciation on the record. The land/no_depreciation CHECK constraint prevents accidentally depreciating land or art — the most common capital asset error. MACRS elections (179 expensing, bonus depreciation) are stored per-asset since they are elected at the asset level for tax returns.';


--
-- Name: funds; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.funds (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    fund_code character varying(20) NOT NULL,
    name character varying(255) NOT NULL,
    fund_type finance.fund_type NOT NULL,
    is_restricted boolean DEFAULT false NOT NULL,
    gasb_fund_category finance.gasb_fund_category,
    gasb_fund_type finance.gasb_fund_type,
    net_asset_class finance.net_asset_class,
    fiscal_year_id uuid,
    description text,
    is_major_fund boolean DEFAULT false NOT NULL,
    endowment_corpus_amount numeric(15,2),
    spending_policy_pct numeric(5,2),
    is_active boolean DEFAULT true NOT NULL,
    CONSTRAINT funds_spending_policy_range CHECK (((spending_policy_pct IS NULL) OR ((spending_policy_pct >= (0)::numeric) AND (spending_policy_pct <= (100)::numeric))))
);


ALTER TABLE finance.funds OWNER TO postgres;

--
-- Name: TABLE funds; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.funds IS 'Fund accounting buckets (unrestricted, restricted, plant). fund_code is the human-readable identifier used in chart of accounts strings. is_restricted flags donor-restricted or grant-restricted funds that require separate tracking and reporting.';


--
-- Name: COLUMN funds.net_asset_class; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.funds.net_asset_class IS 'FASB ASC 958 net asset classification for private NPO institutions. without_donor_restrictions: board-designated or undesignated. with_donor_restrictions_temp: releases when time/purpose conditions met. with_donor_restrictions_perm: endowment corpus — principal never expendable.';


--
-- Name: COLUMN funds.is_major_fund; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.funds.is_major_fund IS 'GASB 34: major fund = meets 10%/5% criteria. Major funds are reported separately; non-major funds are aggregated in an "Other" column.';


--
-- Name: COLUMN funds.spending_policy_pct; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.funds.spending_policy_pct IS 'Annual endowment spending rate as percentage (e.g. 4.5 = 4.5%). Applied to the 12-quarter rolling average market value per UPMIFA.';


--
-- Name: gl_accounts; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.gl_accounts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    account_number character varying(50) NOT NULL,
    account_name character varying(255) NOT NULL,
    type finance.gl_account_type NOT NULL,
    department_id uuid,
    current_balance numeric(14,2) DEFAULT 0.00 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    coa_id uuid,
    parent_account_id uuid,
    account_code character varying(50),
    normal_balance finance.normal_balance,
    fsli_code character varying(20),
    reporting_order integer,
    is_control_account boolean DEFAULT false NOT NULL,
    is_contra boolean DEFAULT false NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    description text
);


ALTER TABLE finance.gl_accounts OWNER TO postgres;

--
-- Name: TABLE gl_accounts; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.gl_accounts IS 'Simplified GL account records for direct departmental use (purchase orders, expense reports, payroll). Carries a current_balance maintained by the finance service. For the full chart-of-accounts structure see finance.ledger_accounts.';


--
-- Name: COLUMN gl_accounts.normal_balance; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.gl_accounts.normal_balance IS 'Debit or credit polarity. Assets and expenses: debit. Liabilities, equity, revenues: credit. Required for trial balance validation and financial statement line classification.';


--
-- Name: COLUMN gl_accounts.fsli_code; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.gl_accounts.fsli_code IS 'Financial Statement Line Item code. Maps this account to a specific line on the applicable financial statement. The financial statement generator groups accounts by fsli_code. Codes are framework-specific.';


--
-- Name: COLUMN gl_accounts.is_control_account; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.gl_accounts.is_control_account IS 'Whether this account has a subsidiary ledger (AR, AP, Fixed Assets). The GL balance must equal the sum of the subsidiary — enforced by triggers.';


--
-- Name: COLUMN gl_accounts.is_contra; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.gl_accounts.is_contra IS 'Contra accounts reduce their paired account: accumulated depreciation reduces fixed assets; allowance for doubtful accounts reduces AR.';


--
-- Name: grant_budgets; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.grant_budgets (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    grant_id uuid NOT NULL,
    gl_account_id uuid NOT NULL,
    budget_category character varying(100) NOT NULL,
    allocated_amount numeric(12,2) DEFAULT 0.00 NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.grant_budgets OWNER TO postgres;

--
-- Name: TABLE grant_budgets; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.grant_budgets IS 'Budget line items for a sponsored grant, broken down by budget_category (personnel, fringe, travel, supplies, indirect). allocated_amount tracks the approved budget per category. Each line links to a GL account for expenditure tracking.';


--
-- Name: inter_fund_transfers; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.inter_fund_transfers (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    fiscal_year_id uuid NOT NULL,
    transfer_date date NOT NULL,
    from_fund_id uuid NOT NULL,
    to_fund_id uuid NOT NULL,
    amount numeric(15,4) NOT NULL,
    transfer_type character varying(50) NOT NULL,
    description text NOT NULL,
    authorized_by_user_id uuid,
    journal_entry_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT inter_fund_transfers_amount_positive CHECK ((amount > (0)::numeric)),
    CONSTRAINT inter_fund_transfers_different_funds CHECK ((from_fund_id <> to_fund_id))
);


ALTER TABLE finance.inter_fund_transfers OWNER TO postgres;

--
-- Name: TABLE inter_fund_transfers; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.inter_fund_transfers IS 'GASB inter-fund transfers. Transfers eliminate in the government-wide statements but appear in the fund financial statements. transfer_type classification is required for GASB 34 disclosure. Operating transfers are the most common; residual equity transfers occur when a fund is closed and its balance transferred to another.';


--
-- Name: journal_entries; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.journal_entries (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    fiscal_year_id uuid NOT NULL,
    entry_date date NOT NULL,
    reference_number character varying(50),
    description text NOT NULL,
    source finance.journal_source DEFAULT 'manual'::finance.journal_source NOT NULL,
    status finance.journal_status DEFAULT 'draft'::finance.journal_status NOT NULL,
    total_debits numeric(18,4) DEFAULT 0 NOT NULL,
    total_credits numeric(18,4) DEFAULT 0 NOT NULL,
    accounting_framework finance.accounting_framework,
    reverses_entry_id uuid,
    source_vendor_payment_id uuid,
    source_payroll_run_id uuid,
    source_student_transaction_id uuid,
    source_depreciation_run_id uuid,
    prepared_by_user_id uuid,
    approved_by_user_id uuid,
    approved_at timestamp with time zone,
    posted_at timestamp with time zone,
    posted_by_user_id uuid,
    trial_balance_snapshot_id uuid,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT journal_entries_balanced CHECK (((status <> 'posted'::finance.journal_status) OR (total_debits = total_credits))),
    CONSTRAINT journal_entries_debits_non_negative CHECK (((total_debits >= (0)::numeric) AND (total_credits >= (0)::numeric))),
    CONSTRAINT journal_entries_not_posted_and_voided CHECK ((NOT ((status = 'posted'::finance.journal_status) AND (posted_at IS NULL))))
);


ALTER TABLE finance.journal_entries OWNER TO postgres;

--
-- Name: TABLE journal_entries; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.journal_entries IS 'General ledger journal entry headers. One row per accounting entry. total_debits and total_credits are maintained by the maintain_journal_balance trigger as journal_lines are added. The balanced CHECK constraint prevents posting an unbalanced entry. Posted entries are immutable — corrections require reversing entries. System-generated entries (payroll, depreciation, AP) link to their source records via the source_* FK columns for drill-down from financials to source.';


--
-- Name: journal_lines; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.journal_lines (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    journal_entry_id uuid NOT NULL,
    line_number smallint NOT NULL,
    gl_account_id uuid NOT NULL,
    fund_id uuid,
    debit_amount numeric(18,4),
    credit_amount numeric(18,4),
    description text,
    grant_budget_id uuid,
    is_encumbrance boolean DEFAULT false NOT NULL,
    net_asset_class finance.net_asset_class,
    department_id uuid,
    project_code character varying(50),
    CONSTRAINT journal_lines_credit_positive CHECK (((credit_amount IS NULL) OR (credit_amount > (0)::numeric))),
    CONSTRAINT journal_lines_debit_positive CHECK (((debit_amount IS NULL) OR (debit_amount > (0)::numeric))),
    CONSTRAINT journal_lines_one_side CHECK ((((debit_amount IS NOT NULL) AND (credit_amount IS NULL)) OR ((debit_amount IS NULL) AND (credit_amount IS NOT NULL))))
);


ALTER TABLE finance.journal_lines OWNER TO postgres;

--
-- Name: TABLE journal_lines; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.journal_lines IS 'Individual debit and credit lines within a journal entry. The one_side CHECK ensures each line is either a debit or a credit — never both, never neither. Positive-only amounts with the debit/credit column providing polarity is the standard accounting model. fund_id enables GASB fund accounting: the same entry can post to multiple funds simultaneously (inter-fund activity). net_asset_class enables FASB 958 NPO reporting by net asset class.';


--
-- Name: ledger_accounts; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.ledger_accounts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    account_string character varying(100) NOT NULL,
    account_type finance.account_type NOT NULL,
    name character varying(255) NOT NULL,
    fund_id uuid NOT NULL,
    owning_department_id uuid,
    is_active boolean DEFAULT true NOT NULL
);


ALTER TABLE finance.ledger_accounts OWNER TO postgres;

--
-- Name: TABLE ledger_accounts; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.ledger_accounts IS 'The detailed chart of accounts. account_string is the full fund-department-object code string used in journal entries. Each account belongs to a fund and owning department. account_type (revenue, expense, asset, liability, equity) drives the financial statement classification.';


--
-- Name: nslds_reporting_runs; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.nslds_reporting_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    report_type character varying(30) NOT NULL,
    term_id uuid,
    aid_year character varying(9),
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    record_count integer DEFAULT 0 NOT NULL,
    accepted_count integer,
    rejected_count integer,
    error_detail jsonb,
    file_reference character varying(1024),
    ed_batch_id character varying(100),
    transmitted_at timestamp with time zone,
    response_received_at timestamp with time zone,
    initiated_by_user_id uuid,
    initiated_by_service character varying(100),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT nslds_reporting_runs_counts_non_negative CHECK (((record_count >= 0) AND ((accepted_count IS NULL) OR (accepted_count >= 0)) AND ((rejected_count IS NULL) OR (rejected_count >= 0)))),
    CONSTRAINT nslds_reporting_runs_type_check CHECK (((report_type)::text = ANY ((ARRAY['enrollment'::character varying, 'loan_origination'::character varying, 'loan_update'::character varying, 'loan_disbursement'::character varying, 'pell'::character varying, 'overpayment'::character varying, 'teach_grant'::character varying])::text[])))
);


ALTER TABLE finance.nslds_reporting_runs OWNER TO postgres;

--
-- Name: TABLE nslds_reporting_runs; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.nslds_reporting_runs IS 'Audit log of every NSLDS reporting batch: enrollment, loan origination, disbursement updates, and Pell grant reporting. One row per transmitted file to the Common Origination and Disbursement (COD) system or NSLDS. error_detail (JSONB) stores the parsed ED error response when status = rejected, enabling the financial aid office to diagnose and correct specific record errors without retrieving the full response file.';


--
-- Name: pay_stub_line_items; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.pay_stub_line_items (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
