    historical_name character varying(255) NOT NULL
);


ALTER TABLE finance.pay_stub_line_items OWNER TO postgres;

--
-- Name: TABLE pay_stub_line_items; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.pay_stub_line_items IS 'Individual earnings, deduction, and benefit line items on a pay stub. historical_name snapshots the payroll item type name at the time of payment so renaming a payroll item type does not retroactively alter historical pay stubs.';


--
-- Name: pay_stubs; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.pay_stubs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
