    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.pay_stubs OWNER TO postgres;

--
-- Name: TABLE pay_stubs; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.pay_stubs IS 'An individual employee''s earnings record within a payroll run. gross_pay and net_pay are totals; the line item detail lives in pay_stub_line_items. Immutable once the run is disbursed.';


--
-- Name: payroll_item_types; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.payroll_item_types (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying NOT NULL,
    category finance.line_item_category NOT NULL,
