    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.payroll_item_types OWNER TO postgres;

--
-- Name: TABLE payroll_item_types; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.payroll_item_types IS 'Configurable payroll components: earnings (base_salary, overtime), deductions (health_insurance, retirement_403b), and employer liabilities (fica_employer). liability_gl_account_id links each item type to its GL liability account for automatic journal entry generation.';


--
-- Name: payroll_runs; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.payroll_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    run_date date NOT NULL,
    total_gross_pay numeric(14,2) NOT NULL,
