    status character varying(50) DEFAULT 'processing'::character varying,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.payroll_runs OWNER TO postgres;

--
-- Name: TABLE payroll_runs; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.payroll_runs IS 'A payroll processing run for a specific pay period. Status: pending → processing → approved → disbursed. total_gross_pay is the aggregate of all pay stubs in the run. Linked to the GL account debited for payroll expense.';


--
-- Name: purchase_orders; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.purchase_orders (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    po_number character varying(50) NOT NULL,
    requester_id uuid NOT NULL,
    vendor_id uuid NOT NULL,
    gl_account_id uuid NOT NULL,
    status finance.po_status DEFAULT 'draft'::finance.po_status NOT NULL,
    total_amount numeric(12,2) DEFAULT 0.00 NOT NULL,
    justification text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(po_number, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(justification, ''::text)), 'B'::"char"))) STORED
);


ALTER TABLE finance.purchase_orders OWNER TO postgres;

--
-- Name: TABLE purchase_orders; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.purchase_orders IS 'A procurement request and commitment document. Links to a vendor, GL account, and requester. Status flows through draft → submitted → approved → partially_received → received → closed. total_amount encumbers against the GL account budget line at approval.';


--
-- Name: COLUMN purchase_orders.fts_doc; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.purchase_orders.fts_doc IS 'Generated tsvector for PO search by po_number (A) and justification (B).';


--
-- Name: receiving_reports; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.receiving_reports (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
