);


ALTER TABLE finance.receiving_reports OWNER TO postgres;

--
-- Name: TABLE receiving_reports; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.receiving_reports IS 'Records physical receipt of goods against a purchase order. Three-way match (PO → receiving report → invoice) is verified by setting vendor_invoices.is_three_way_match_verified = true. packing_slip_number and delivery_date support physical receiving workflows.';


--
-- Name: sap_appeals; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.sap_appeals (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    sap_evaluation_id uuid NOT NULL,
    workflow_submission_id uuid NOT NULL,
    supporting_document_id uuid,
    appeal_status character varying(50) DEFAULT 'pending_committee_review'::character varying NOT NULL,
    probation_expires_term_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.sap_appeals OWNER TO postgres;

--
-- Name: TABLE sap_appeals; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.sap_appeals IS 'A student appeal of a SAP suspension or ineligibility determination. Links to the SAP evaluation being appealed, a supporting document, and the workflow submission that routes the appeal for review. probation_expires_term_id is set when the appeal is approved with a probationary reinstatement.';


--
-- Name: sap_evaluation_runs; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.sap_evaluation_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    term_id uuid NOT NULL,
    trigger_type sis.gpa_recalc_trigger NOT NULL,
    student_id uuid,
    is_dry_run boolean DEFAULT false NOT NULL,
    students_evaluated integer DEFAULT 0 NOT NULL,
    students_good_standing integer DEFAULT 0 NOT NULL,
    students_on_warning integer DEFAULT 0 NOT NULL,
    students_suspended integer DEFAULT 0 NOT NULL,
    students_on_plan integer DEFAULT 0 NOT NULL,
    students_max_timeframe integer DEFAULT 0 NOT NULL,
    students_skipped integer DEFAULT 0 NOT NULL,
    initiated_by_service character varying(100),
    initiated_by_user_id uuid,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    failed_at timestamp with time zone,
    failure_reason text,
    CONSTRAINT sap_evaluation_runs_counts_non_negative CHECK (((students_evaluated >= 0) AND (students_good_standing >= 0) AND (students_on_warning >= 0) AND (students_suspended >= 0) AND (students_on_plan >= 0) AND (students_max_timeframe >= 0) AND (students_skipped >= 0))),
    CONSTRAINT sap_evaluation_runs_not_both_complete_failed CHECK ((NOT ((completed_at IS NOT NULL) AND (failed_at IS NOT NULL))))
);


ALTER TABLE finance.sap_evaluation_runs OWNER TO postgres;

--
-- Name: TABLE sap_evaluation_runs; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.sap_evaluation_runs IS 'Batch job tracking for SAP evaluations. students_skipped counts students below min_credits_for_evaluation threshold. Mirrors the pattern of sis.gpa_recalculation_runs for operational consistency. Per-student results are in finance.sap_evaluations (the existing table).';


--
-- Name: sap_evaluations; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.sap_evaluations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    evaluation_term_id uuid NOT NULL,
    snapshot_cumulative_gpa numeric(4,3) NOT NULL,
    snapshot_attempted_credits numeric(6,2) NOT NULL,
    snapshot_earned_credits numeric(6,2) NOT NULL,
    snapshot_pace_percentage numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (snapshot_attempted_credits = (0)::numeric) THEN (0)::numeric
    ELSE ((snapshot_earned_credits / snapshot_attempted_credits) * (100)::numeric)
END) STORED,
    resulting_sap_status finance.sap_status NOT NULL,
    evaluated_at timestamp with time zone DEFAULT now() NOT NULL,
    is_manual_override boolean DEFAULT false NOT NULL,
    override_reason text,
    overridden_by_id uuid,
    sap_policy_id uuid,
    run_id uuid,
    is_financial_aid_recipient boolean DEFAULT true NOT NULL,
    gpa_component_met boolean,
    pace_component_met boolean,
    max_timeframe_component_met boolean,
    snapshot_max_timeframe_credits numeric(7,2),
    consecutive_warning_terms smallint DEFAULT 0 NOT NULL,
    notification_sent_at timestamp with time zone,
    academic_standing_record_id uuid,
    CONSTRAINT sap_evaluations_consecutive_non_negative CHECK ((consecutive_warning_terms >= 0))
);


ALTER TABLE finance.sap_evaluations OWNER TO postgres;

--
-- Name: TABLE sap_evaluations; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.sap_evaluations IS 'A Satisfactory Academic Progress evaluation for one student at the end of one term. Snapshots cumulative_gpa, earned_credits, and attempted_credits at evaluation time. resulting_sap_status: satisfactory, warning, suspension, ineligible. is_manual_override allows a financial aid officer to override the automated calculation with a documented reason.';


--
-- Name: COLUMN sap_evaluations.sap_policy_id; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.sap_policy_id IS 'The SAP policy whose thresholds governed this evaluation. Self-describing — the evaluation does not depend on the policy ''s current values to be auditable after a policy change.';


--
-- Name: COLUMN sap_evaluations.gpa_component_met; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.gpa_component_met IS 'Whether the student met the qualitative GPA threshold at evaluation. NULL when not yet evaluated. All three component flags must be true for resulting_sap_status = ''good_standing''.';


--
-- Name: COLUMN sap_evaluations.pace_component_met; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.pace_component_met IS 'Whether the student met the quantitative pace threshold (credits earned / credits attempted >= policy minimum). snapshot_pace_percentage / sap_policy.min_pace_percentage drives this flag.';


--
-- Name: COLUMN sap_evaluations.max_timeframe_component_met; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.max_timeframe_component_met IS 'Whether the student has not exceeded the maximum timeframe. snapshot_attempted_credits <= snapshot_max_timeframe_credits drives this flag.';


--
-- Name: COLUMN sap_evaluations.consecutive_warning_terms; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.consecutive_warning_terms IS 'How many consecutive terms the student has been in a non-good-standing status at the time of this evaluation. Drives the warning → suspension escalation.';


--
-- Name: COLUMN sap_evaluations.academic_standing_record_id; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_evaluations.academic_standing_record_id IS 'The sis.student_academic_standing row for the same student and term. Provides the direct link between SAP status and institutional academic standing for the same evaluation period. NULL when the standing determination has not yet run or the student is not enrolled.';


--
-- Name: sap_policies; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.sap_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(150) NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    academic_program_id uuid,
    min_cumulative_gpa numeric(4,3) DEFAULT 2.000 NOT NULL,
    min_pace_percentage numeric(5,2) DEFAULT 67.00 NOT NULL,
    max_timeframe_multiplier numeric(4,2) DEFAULT 1.50 NOT NULL,
    evaluation_frequency character varying(50) DEFAULT 'every_term'::character varying NOT NULL,
    min_credits_for_evaluation numeric(6,2) DEFAULT 6.00 NOT NULL,
    transfer_credits_count_in_pace boolean DEFAULT true NOT NULL,
    remedial_credits_count_in_pace boolean DEFAULT false NOT NULL,
    warning_terms_before_suspension smallint DEFAULT 1 NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    timeframe_warning_1_pct numeric(5,2) DEFAULT 75.00 NOT NULL,
    timeframe_warning_2_pct numeric(5,2) DEFAULT 90.00 NOT NULL,
    timeframe_warning_3_pct numeric(5,2) DEFAULT 100.00 NOT NULL,
    CONSTRAINT sap_policies_gpa_range CHECK (((min_cumulative_gpa >= (0)::numeric) AND (min_cumulative_gpa <= 4.0))),
    CONSTRAINT sap_policies_min_credits_positive CHECK ((min_credits_for_evaluation >= (0)::numeric)),
    CONSTRAINT sap_policies_pace_range CHECK (((min_pace_percentage >= (0)::numeric) AND (min_pace_percentage <= (100)::numeric))),
    CONSTRAINT sap_policies_timeframe_positive CHECK ((max_timeframe_multiplier > (0)::numeric)),
    CONSTRAINT sap_policies_warning_pcts_ordered CHECK (((timeframe_warning_1_pct <= timeframe_warning_2_pct) AND (timeframe_warning_2_pct <= timeframe_warning_3_pct))),
    CONSTRAINT sap_policies_warning_pcts_range CHECK (((timeframe_warning_1_pct >= (0)::numeric) AND (timeframe_warning_3_pct <= (150)::numeric))),
    CONSTRAINT sap_policies_warning_terms_positive CHECK ((warning_terms_before_suspension > 0))
);


ALTER TABLE finance.sap_policies OWNER TO postgres;

--
-- Name: TABLE sap_policies; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.sap_policies IS 'SAP threshold configuration per tenant and optionally per program. Three component thresholds: min_cumulative_gpa (qualitative), min_pace_percentage (quantitative), max_timeframe_multiplier (timeframe). Resolution: program-specific policy overrides tenant default (is_default). remedial_credits_count_in_pace = false reflects the common interpretation that remedial hours are excluded from the pace denominator.';


--
-- Name: COLUMN sap_policies.timeframe_warning_1_pct; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_policies.timeframe_warning_1_pct IS 'First timeframe warning threshold as a percentage of max_timeframe_credits. Default 75% — student has used three-quarters of their allowed timeframe. Reaching this triggers a ''sis.timeframe.warning_threshold_reached'' event with threshold_level = 1 for advisor outreach.';


--
-- Name: COLUMN sap_policies.timeframe_warning_2_pct; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_policies.timeframe_warning_2_pct IS 'Second timeframe warning threshold. Default 90% — student is approaching max timeframe. Triggers more urgent advisor intervention.';


--
-- Name: COLUMN sap_policies.timeframe_warning_3_pct; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sap_policies.timeframe_warning_3_pct IS 'Third timeframe warning threshold. Default 100% — student has reached max timeframe. At this point the CPOS sweep will flag enrollments as ineligible_max_timeframe and SAP will result in max_timeframe_exceeded.';


--
-- Name: sponsored_grants; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.sponsored_grants (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    sponsor_id uuid NOT NULL,
    principal_investigator_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    grant_number character varying(100),
    status finance.grant_status DEFAULT 'proposal_draft'::finance.grant_status NOT NULL,
    total_awarded numeric(14,2),
    indirect_cost_rate numeric(5,4) DEFAULT 0.000 NOT NULL,
    start_date date,
    end_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(title, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, (COALESCE(grant_number, ''::character varying))::text), 'A'::"char"))) STORED
);


ALTER TABLE finance.sponsored_grants OWNER TO postgres;

--
-- Name: TABLE sponsored_grants; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.sponsored_grants IS 'Externally sponsored research or program grants. principal_investigator_id links to the faculty/staff PI. sponsor_id references an external organization. indirect_cost_rate is the F&A rate negotiated with the sponsor. Grant budget detail is in finance.grant_budgets.';


--
-- Name: COLUMN sponsored_grants.fts_doc; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.sponsored_grants.fts_doc IS 'Generated tsvector for grant search by title (A) and grant_number (A). Both carry weight A because either may be the primary search term.';


--
-- Name: student_accounts; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.student_accounts (
