ALTER TABLE finance.student_accounts OWNER TO postgres;

--
-- Name: TABLE student_accounts; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.student_accounts IS 'One account per student per tenant — the student''s financial ledger. current_balance is maintained by the finance service as transactions are posted. is_hold_active blocks registration when true (unpaid balance, returned payment, etc.).';


--
-- Name: student_transactions; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.student_transactions (
