);


ALTER TABLE finance.student_transactions OWNER TO postgres;

--
-- Name: TABLE student_transactions; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.student_transactions IS 'Immutable ledger entries against a student account. Positive amounts are charges; negative amounts are credits/payments. type ENUM: tuition, fee, payment, financial_aid_credit, refund, penalty. reference_number links to the source document (enrollment, award, etc.).';


--
-- Name: tax_1099_records; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_1099_records (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    vendor_id uuid NOT NULL,
    tax_year smallint NOT NULL,
    form_type character varying(10) NOT NULL,
    box_1_nonemployee_comp numeric(12,2) DEFAULT 0 NOT NULL,
    box_2_royalties numeric(12,2) DEFAULT 0 NOT NULL,
    box_3_other_income numeric(12,2) DEFAULT 0 NOT NULL,
    box_4_fed_tax_withheld numeric(12,2) DEFAULT 0 NOT NULL,
    box_6_medical numeric(12,2) DEFAULT 0 NOT NULL,
    box_7_payer_made_direct_sales boolean DEFAULT false NOT NULL,
    state_tax_withheld numeric(12,2) DEFAULT 0 NOT NULL,
    state_code character(2),
    status character varying(20) DEFAULT 'draft'::character varying NOT NULL,
    irs_transmitted_at timestamp with time zone,
