    CONSTRAINT tax_1099_records_tax_year_reasonable CHECK (((tax_year >= 2020) AND (tax_year <= 2099)))
);


ALTER TABLE finance.tax_1099_records OWNER TO postgres;

--
-- Name: TABLE tax_1099_records; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_1099_records IS 'Annual IRS 1099 records for US vendor payments. One row per vendor per form type per tax year. Generated from vendor_tax_details (is_1099_eligible = true) and vendor_payments where ytd_payments >= $600. Supports 1099-NEC (non-employee compensation), 1099-MISC (miscellaneous), and 1099-INT (interest). is_corrected = true creates a corrected return when payment amounts or recipient information was reported incorrectly.';


--
-- Name: tax_filing_periods; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_filing_periods (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    nexus_id uuid NOT NULL,
    jurisdiction_id uuid NOT NULL,
    period_start date NOT NULL,
    period_end date NOT NULL,
    due_date date NOT NULL,
    total_taxable_sales numeric(15,4) DEFAULT 0 NOT NULL,
    total_exempt_sales numeric(15,4) DEFAULT 0 NOT NULL,
    total_tax_collected numeric(15,4) DEFAULT 0 NOT NULL,
    total_taxable_purchases numeric(15,4) DEFAULT 0 NOT NULL,
    total_input_vat_recoverable numeric(15,4) DEFAULT 0 NOT NULL,
    total_tax_due numeric(15,4) DEFAULT 0 NOT NULL,
    status character varying(20) DEFAULT 'open'::character varying NOT NULL,
    filed_at timestamp with time zone,
    filed_by_user_id uuid,
    confirmation_number character varying(100),
    payment_amount numeric(15,4),
    payment_date date,
    payment_reference character varying(100),
    return_document_id uuid,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tax_filing_periods_amounts_non_negative CHECK (((total_taxable_sales >= (0)::numeric) AND (total_tax_collected >= (0)::numeric) AND (total_tax_due >= (0)::numeric))),
    CONSTRAINT tax_filing_periods_dates_valid CHECK (((period_end > period_start) AND (due_date >= period_end)))
);


ALTER TABLE finance.tax_filing_periods OWNER TO postgres;

--
-- Name: TABLE tax_filing_periods; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_filing_periods IS 'Tax filing calendar and return data per jurisdiction per period. Aggregate totals are maintained by the Rust tax service as transactions are posted. When status = ready_to_file the return can be generated. For VAT jurisdictions: total_input_vat_recoverable is the input tax the institution can deduct from its VAT liability. For US sales tax: total_input_vat_recoverable is always 0 (US sales tax is not a creditable tax system).';


--
-- Name: tax_jurisdictions; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_jurisdictions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    jurisdiction_code character varying(20) NOT NULL,
    name character varying(255) NOT NULL,
    level finance.jurisdiction_level NOT NULL,
    tax_regime finance.tax_regime NOT NULL,
    country_iso_alpha2 character(2) NOT NULL,
    subdivision_code character varying(10),
    county_name character varying(100),
    city_name character varying(100),
    fips_code character varying(10),
    has_edu_exemption boolean DEFAULT false NOT NULL,
    edu_exempt_on_sales boolean DEFAULT false NOT NULL,
    edu_exempt_on_purchases boolean DEFAULT false NOT NULL,
    has_reverse_charge boolean DEFAULT false NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    notes text
);


ALTER TABLE finance.tax_jurisdictions OWNER TO postgres;

--
-- Name: TABLE tax_jurisdictions; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_jurisdictions IS 'Master list of tax jurisdictions across all supported regimes. Hierarchical: a US sale may trigger federal (none on sales), state, county, city, and special district taxes simultaneously — all as separate rows here, combined by the tax engine at calculation time. has_edu_exemption flags jurisdictions with educational carve-outs; the specific exemption conditions are in tax_rates and the tenant''s tax_registrations (exemption certificate numbers).';


--
-- Name: tax_nexus; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_nexus (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    jurisdiction_id uuid NOT NULL,
    nexus_type finance.nexus_type NOT NULL,
    established_date date NOT NULL,
    trigger_revenue_amount numeric(15,2),
    trigger_transaction_count integer,
    is_registered boolean DEFAULT false NOT NULL,
    registration_id uuid,
    filing_frequency finance.tax_filing_frequency,
    physical_presence_desc text,
    is_active boolean DEFAULT true NOT NULL,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.tax_nexus OWNER TO postgres;

--
-- Name: TABLE tax_nexus; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_nexus IS 'Records where a tenant has sales tax / VAT collection obligations. Physical nexus arises from having offices, employees, or inventory. Economic nexus (post-Wayfair) arises when revenue or transaction volume exceeds a state threshold — typically $100,000 or 200 transactions in a 12-month period, though thresholds vary by state. Educational institutions with 501(c)(3) status may have nexus but still be exempt from collection on tuition — the nexus record and the edu_exempt_on_sales flag on tax_jurisdictions work together.';


--
-- Name: tax_product_rules; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_product_rules (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    transaction_type finance.transaction_type,
    charge_code character varying(50),
    jurisdiction_id uuid,
    product_category finance.tax_product_category NOT NULL,
    is_input_vat_recoverable boolean DEFAULT true NOT NULL,
    input_vat_recovery_pct numeric(5,2) DEFAULT 100 NOT NULL,
    valid_from date DEFAULT CURRENT_DATE NOT NULL,
    valid_to date,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tax_product_rules_dates_valid CHECK (((valid_to IS NULL) OR (valid_to > valid_from))),
    CONSTRAINT tax_product_rules_has_identifier CHECK (((transaction_type IS NOT NULL) OR (charge_code IS NOT NULL))),
    CONSTRAINT tax_product_rules_recovery_pct_range CHECK (((input_vat_recovery_pct >= (0)::numeric) AND (input_vat_recovery_pct <= (100)::numeric)))
);


ALTER TABLE finance.tax_product_rules OWNER TO postgres;

--
-- Name: TABLE tax_product_rules; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_product_rules IS 'Maps transaction types and charge codes to tax product categories. Jurisdiction-specific overrides handle state-level differences: textbooks are exempt in some US states but taxable in others. input_vat_recovery_pct handles partial recovery for mixed-use institutions (common in UK/EU where some activities are business and some are exempt educational activities).';


--
-- Name: tax_rates; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tax_rates (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    jurisdiction_id uuid NOT NULL,
    product_category finance.tax_product_category,
    rate numeric(8,6) NOT NULL,
    valid_from date NOT NULL,
    valid_to date,
    rate_tier character varying(30) DEFAULT 'standard'::character varying NOT NULL,
    applies_to_exempt boolean DEFAULT false NOT NULL,
    is_compounding boolean DEFAULT false NOT NULL,
    gl_account_id uuid,
    source_reference character varying(255),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tax_rates_dates_valid CHECK (((valid_to IS NULL) OR (valid_to > valid_from))),
    CONSTRAINT tax_rates_rate_non_negative CHECK (((rate >= (0)::numeric) AND (rate <= (1)::numeric)))
);


ALTER TABLE finance.tax_rates OWNER TO postgres;

--
-- Name: TABLE tax_rates; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tax_rates IS 'Effectively dated tax rates per jurisdiction per product category. The tax engine queries: SELECT rate FROM finance.tax_rates WHERE jurisdiction_id = $j AND (product_category = $cat OR product_category IS NULL) AND valid_from <= $transaction_date AND (valid_to IS NULL OR valid_to > $transaction_date) ORDER BY product_category NULLS LAST LIMIT 1. Product-category-specific rates take precedence over NULL (catch-all) rates. valid_to IS NULL means the rate is currently in effect. is_compounding = true handles Quebec QST which applies to the GST-inclusive price, creating a compounded tax (9.975% on 105% of base).';


--
-- Name: tenant_tax_registrations; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.tenant_tax_registrations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    registration_type finance.tax_registration_type NOT NULL,
    registration_number character varying(100) NOT NULL,
    country_iso_alpha2 character(2),
    subdivision_code character varying(10),
    effective_date date DEFAULT CURRENT_DATE NOT NULL,
    expiration_date date,
    is_primary boolean DEFAULT false NOT NULL,
    exemption_cert_number character varying(100),
    exemption_cert_url character varying(1024),
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tenant_tax_registrations_dates_valid CHECK (((expiration_date IS NULL) OR (expiration_date > effective_date)))
);


ALTER TABLE finance.tenant_tax_registrations OWNER TO postgres;

--
-- Name: TABLE tenant_tax_registrations; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.tenant_tax_registrations IS 'All tax registration numbers for a tenant across all jurisdictions. A US institution with physical or economic nexus in multiple states will have one row per state sales tax permit plus one EIN row. A UK institution will have a VAT number row. Exemption certificate details are stored here for AP workflows that require presenting exemption certificates to vendors.';


--
-- Name: transaction_tax_lines; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.transaction_tax_lines (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_transaction_id uuid,
    vendor_invoice_id uuid,
    purchase_order_id uuid,
    expense_line_item_id uuid,
    jurisdiction_id uuid NOT NULL,
    tax_rate_id uuid NOT NULL,
    taxable_amount numeric(15,4) NOT NULL,
    rate_applied numeric(8,6) NOT NULL,
    tax_amount numeric(15,4) GENERATED ALWAYS AS (round((taxable_amount * rate_applied), 4)) STORED NOT NULL,
    currency_code character(3) DEFAULT 'USD'::bpchar NOT NULL,
    application_method finance.tax_application_method DEFAULT 'standard'::finance.tax_application_method NOT NULL,
    is_reverse_charge boolean DEFAULT false NOT NULL,
    is_exempt boolean DEFAULT false NOT NULL,
    exemption_certificate_ref character varying(100),
    gl_account_id uuid,
    is_posted_to_gl boolean DEFAULT false NOT NULL,
    posted_at timestamp with time zone,
    calculated_at timestamp with time zone DEFAULT now() NOT NULL,
    calculated_by_service character varying(100),
    CONSTRAINT transaction_tax_lines_one_source CHECK (((((
CASE
    WHEN (student_transaction_id IS NOT NULL) THEN 1
    ELSE 0
END +
CASE
    WHEN (vendor_invoice_id IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN (purchase_order_id IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN (expense_line_item_id IS NOT NULL) THEN 1
    ELSE 0
END) = 1)),
    CONSTRAINT transaction_tax_lines_rate_non_negative CHECK ((rate_applied >= (0)::numeric)),
    CONSTRAINT transaction_tax_lines_taxable_amount_non_negative CHECK ((taxable_amount >= (0)::numeric))
);


ALTER TABLE finance.transaction_tax_lines OWNER TO postgres;

--
-- Name: TABLE transaction_tax_lines; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.transaction_tax_lines IS 'Per-jurisdiction tax calculation records for every taxable transaction. tax_amount is a generated column (taxable_amount × rate_applied) ensuring the stored amount is always mathematically consistent with the rate. A US student paying room and board may generate 3 rows: state, county, city. A UK vendor invoice may generate 1 VAT row (or 0 if reverse charge applies). is_posted_to_gl tracks whether the tax has been journaled to the liability/expense GL account. is_exempt records when an exemption certificate was presented to zero out an otherwise-taxable line.';


--
-- Name: travel_authorizations; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.travel_authorizations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    employee_id uuid NOT NULL,
    gl_account_id uuid NOT NULL,
    destination character varying NOT NULL,
    purpose text NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    estimated_cost numeric(10,2) NOT NULL,
    status finance.expense_status DEFAULT 'draft'::finance.expense_status NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    approved_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.travel_authorizations OWNER TO postgres;

--
-- Name: TABLE travel_authorizations; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.travel_authorizations IS 'Pre-trip approval required before an employee may submit expenses. Links to the GL account to be charged. Status: draft → submitted → approved → denied → completed. Completed when the linked expense report is paid.';


--
-- Name: trial_balance_snapshots; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.trial_balance_snapshots (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
