    generated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.trial_balance_snapshots OWNER TO postgres;

--
-- Name: TABLE trial_balance_snapshots; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.trial_balance_snapshots IS 'Point-in-time trial balance snapshots. is_balanced = true is a prerequisite for generating audited financial statements. account_balances JSONB stores full account detail so each snapshot is self-contained and reproducible even if corrections are made to the underlying journal.';


--
-- Name: va_certifications; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.va_certifications (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    veteran_profile_id uuid NOT NULL,
    term_id uuid NOT NULL,
    certified_by_id uuid,
    credits_certified numeric(4,2) NOT NULL,
    tuition_reported numeric(10,2) NOT NULL,
    fees_reported numeric(10,2) NOT NULL,
    certification_date date NOT NULL,
    amendment_date date,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    enrollment_intensity_va finance.va_enrollment_intensity,
    training_time_percentage numeric(5,2),
    is_amendment boolean DEFAULT false NOT NULL,
    amends_certification_id uuid,
    va_confirmation_number character varying(50),
    ch33_housing_rate numeric(10,2),
    ch33_book_stipend numeric(10,2),
    program_of_study character varying(255)
);


ALTER TABLE finance.va_certifications OWNER TO postgres;

--
-- Name: TABLE va_certifications; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.va_certifications IS 'A VA enrollment certification submitted to the VA by the certifying official for one student for one term. Records credits_certified, tuition_reported, and fees_reported. amendment_date records when a correction certification was filed.';


--
-- Name: COLUMN va_certifications.enrollment_intensity_va; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.va_certifications.enrollment_intensity_va IS 'VA training time classification for this certification. Uses VA thresholds which differ from NSC: full_time is typically 12+ credits for undergrad but varies for graduate programs and clock-hour programs. Drives the housing allowance (MHA) calculation for Chapter 33 students.';


--
-- Name: COLUMN va_certifications.training_time_percentage; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.va_certifications.training_time_percentage IS 'Percentage of full-time enrollment for VA purposes (0-100). For Chapter 33: 100% = full MHA; 50% = half MHA. For Chapter 30/35/1606: determines the monthly benefit rate tier. Computed by the SCO service from credits_certified and the program''s full-time credit load.';


--
-- Name: COLUMN va_certifications.is_amendment; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.va_certifications.is_amendment IS 'Whether this is an amended certification correcting a prior submission. VA requires amendments when enrollment changes after initial certification (withdrawals, grade changes affecting credit load, etc.).';


--
-- Name: COLUMN va_certifications.amends_certification_id; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.va_certifications.amends_certification_id IS 'If is_amendment = true, the original certification this record corrects. The VA uses this linkage to adjust benefit payments retroactively.';


--
-- Name: COLUMN va_certifications.va_confirmation_number; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.va_certifications.va_confirmation_number IS 'VA''s confirmation number returned after the SCO submits the certification through VA-ONCE or the Education Case Management System (ECMS). Required for amendment and inquiry submissions.';


--
-- Name: vendor_invoices; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.vendor_invoices (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
