    is_three_way_match_verified boolean DEFAULT false NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.vendor_invoices OWNER TO postgres;

--
-- Name: TABLE vendor_invoices; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.vendor_invoices IS 'Supplier invoices matched against purchase orders. is_three_way_match_verified must be true before payment is released. due_date drives AP aging and cash management forecasting. Status: received → under_review → approved → paid → disputed.';


--
-- Name: vendor_payments; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.vendor_payments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    invoice_id uuid NOT NULL,
