    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE finance.vendor_payments OWNER TO postgres;

--
-- Name: TABLE vendor_payments; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.vendor_payments IS 'Records a payment disbursement against an invoice. payment_date and amount_paid support bank reconciliation. Links to the GL account debited.';


--
-- Name: vendor_tax_details; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.vendor_tax_details (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    vendor_id uuid NOT NULL,
    tax_classification finance.vendor_tax_classification DEFAULT 'unknown'::finance.vendor_tax_classification NOT NULL,
    country_iso_alpha2 character(2),
    tax_id_type finance.tax_registration_type,
    tax_id_number character varying(100),
    vat_registration_number character varying(50),
    gst_registration_number character varying(50),
    is_1099_eligible boolean DEFAULT false NOT NULL,
    ytd_payments_1099 numeric(12,2) DEFAULT 0 NOT NULL,
    w8_form_type character varying(20),
    w8_received_date date,
    w8_expiration_date date,
    withholding_rate numeric(5,4),
    treaty_country character(2),
    treaty_article character varying(50),
    charges_vat_gst boolean DEFAULT false NOT NULL,
    vendor_vat_country character(2),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT vendor_tax_details_withholding_range CHECK (((withholding_rate IS NULL) OR ((withholding_rate >= (0)::numeric) AND (withholding_rate <= (1)::numeric))))
);


ALTER TABLE finance.vendor_tax_details OWNER TO postgres;

--
-- Name: TABLE vendor_tax_details; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.vendor_tax_details IS 'Structured tax profile for each vendor. Replaces the bare tax_id_number varchar on finance.vendors with a complete record covering: 1099 eligibility and YTD payment tracking for US domestic vendors; W-8 form tracking and withholding rates for foreign vendors; VAT/GST registration for EU/UK/AU/CA vendors. tax_classification = unknown blocks payment until classified — a safety guard preventing 1099-required payments from slipping through. w8_expiration_date triggers a renewal workflow 90 days before expiry.';


--
-- Name: vendors; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.vendors (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying NOT NULL,
    tax_id_number character varying,
    payment_terms character varying,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(name, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, (COALESCE(payment_terms, ''::character varying))::text), 'C'::"char"))) STORED
);


ALTER TABLE finance.vendors OWNER TO postgres;

--
-- Name: TABLE vendors; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.vendors IS 'External supplier records. tax_id_number supports 1099 reporting. payment_terms (e.g., Net30) drives AP aging calculations. is_active gates use in new purchase orders.';


--
-- Name: COLUMN vendors.fts_doc; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON COLUMN finance.vendors.fts_doc IS 'Generated tsvector for vendor search by name (A) and payment_terms (C). tax_id_number is excluded from FTS — it is PII and searched only by exact match.';


--
-- Name: veteran_profiles; Type: TABLE; Schema: finance; Owner: postgres
--

CREATE TABLE finance.veteran_profiles (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    va_file_number character varying,
    primary_chapter finance.va_benefit_chapter NOT NULL,
    eligibility_percentage integer,
    months_of_entitlement_remaining numeric(4,2),
    dd214_on_file boolean DEFAULT false NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT percentage_check CHECK (((eligibility_percentage >= 0) AND (eligibility_percentage <= 100)))
);


ALTER TABLE finance.veteran_profiles OWNER TO postgres;

--
-- Name: TABLE veteran_profiles; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON TABLE finance.veteran_profiles IS 'VA education benefit eligibility record for a student. primary_chapter is the VA benefit chapter used (e.g., Chapter 33, Chapter 30). eligibility_percentage and months_of_entitlement_remaining drive the VA certifying official''s certification calculations. dd214_on_file confirms the discharge document has been received.';


--
-- Name: vw_1099_preparation; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_1099_preparation AS
 SELECT vtd.tenant_id,
    v.id AS vendor_id,
    v.name AS vendor_name,
    vtd.tax_classification,
    vtd.tax_id_number,
    vtd.is_1099_eligible,
    vtd.ytd_payments_1099,
    vtd.w8_form_type,
    vtd.w8_expiration_date,
    vtd.withholding_rate,
        CASE
            WHEN (vtd.tax_classification = 'unknown'::finance.vendor_tax_classification) THEN 'BLOCK — classify vendor before payment'::text
            WHEN (vtd.is_1099_eligible AND (vtd.ytd_payments_1099 >= (600)::numeric)) THEN 'REQUIRES 1099-NEC'::text
            WHEN ((vtd.tax_classification = ANY (ARRAY['foreign_individual'::finance.vendor_tax_classification, 'foreign_entity'::finance.vendor_tax_classification])) AND (vtd.w8_form_type IS NULL)) THEN 'BLOCK — W-8 required before payment'::text
            WHEN ((vtd.tax_classification = ANY (ARRAY['foreign_individual'::finance.vendor_tax_classification, 'foreign_entity'::finance.vendor_tax_classification])) AND (vtd.w8_expiration_date < CURRENT_DATE)) THEN 'BLOCK — W-8 expired, renewal required'::text
            ELSE 'OK'::text
        END AS compliance_status
   FROM (finance.vendor_tax_details vtd
     JOIN finance.vendors v ON ((v.id = vtd.vendor_id)));


ALTER VIEW finance.vw_1099_preparation OWNER TO postgres;

--
-- Name: VIEW vw_1099_preparation; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_1099_preparation IS 'Vendor tax compliance status for 1099 preparation and payment blocking. compliance_status = BLOCK prevents payment processing for unclassified vendors and foreign vendors with missing or expired W-8 forms. Consumed by the AP approval workflow and the year-end 1099 preparation module.';


--
-- Name: vw_ar_aging; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_ar_aging AS
 SELECT tenant_id,
    id AS invoice_id,
    invoice_number,
    customer_name,
    invoice_date,
    due_date,
    total_amount,
    amount_paid,
    amount_outstanding,
    (CURRENT_DATE - due_date) AS days_past_due,
        CASE
            WHEN (due_date >= CURRENT_DATE) THEN 'current'::text
            WHEN ((CURRENT_DATE - due_date) <= 30) THEN '1_30_days'::text
            WHEN ((CURRENT_DATE - due_date) <= 60) THEN '31_60_days'::text
            WHEN ((CURRENT_DATE - due_date) <= 90) THEN '61_90_days'::text
            ELSE 'over_90_days'::text
        END AS aging_bucket,
    status,
    grant_id
   FROM finance.ar_invoices ai
  WHERE (((status)::text = ANY ((ARRAY['open'::character varying, 'partial'::character varying, 'overdue'::character varying])::text[])) AND (amount_outstanding > (0)::numeric));


ALTER VIEW finance.vw_ar_aging OWNER TO postgres;

--
-- Name: VIEW vw_ar_aging; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_ar_aging IS 'Accounts receivable aging report. Five standard aging buckets: current, 1-30, 31-60, 61-90, over 90 days past due. The CFO report groups by aging_bucket and sums amount_outstanding for the standard aging schedule. Only includes open invoices with outstanding balances.';


--
-- Name: vw_depreciation_schedule; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_depreciation_schedule AS
 SELECT fa.tenant_id,
    fa.id AS asset_id,
    fa.asset_tag,
    fa.description,
    fa.asset_class,
    fa.depreciation_method,
    fa.acquisition_date,
    fa.placed_in_service_date,
    fa.acquisition_cost,
    fa.salvage_value,
    fa.useful_life_years,
    fa.accumulated_depreciation,
    fa.net_book_value,
    fa.disposal_date,
    ( SELECT count(*) AS count
           FROM finance.asset_depreciation_schedules ads
          WHERE (ads.asset_id = fa.id)) AS total_periods_scheduled,
    ( SELECT count(*) AS count
           FROM finance.asset_depreciation_schedules ads
          WHERE ((ads.asset_id = fa.id) AND (ads.is_posted = true))) AS periods_posted,
    ( SELECT sum(ads.depreciation_amount) AS sum
           FROM finance.asset_depreciation_schedules ads
          WHERE ((ads.asset_id = fa.id) AND (ads.is_posted = false))) AS remaining_depreciation,
    (fa.net_book_value <= fa.salvage_value) AS is_fully_depreciated,
    fa.macrs_property_class,
    fa.macrs_election_179,
    fa.macrs_bonus_depreciation_pct,
    d.name AS department_name
   FROM (finance.fixed_assets fa
     LEFT JOIN core.departments d ON ((d.id = fa.department_id)));


ALTER VIEW finance.vw_depreciation_schedule OWNER TO postgres;

--
-- Name: VIEW vw_depreciation_schedule; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_depreciation_schedule IS 'CFO-facing depreciation schedule combining fixed asset master data with schedule summary statistics. remaining_depreciation shows the total future depreciation expense the institution will recognize. is_fully_depreciated flags assets that are on the books but fully expensed — common in educational institutions where equipment is kept long past its book life.';


--
-- Name: vw_endowment_summary; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_endowment_summary AS
 SELECT efr.tenant_id,
    f.name AS fund_name,
    f.fund_code,
    f.net_asset_class,
    f.spending_policy_pct,
    fy.name AS fiscal_year,
    efr.beginning_market_value,
    efr.new_gifts,
    efr.investment_return,
    efr.spending_distributions,
    efr.management_fees,
    efr.ending_market_value,
    efr.historic_gift_value,
    efr.is_underwater,
    efr.rolling_average_market_value,
    efr.spending_appropriation,
        CASE
            WHEN (efr.beginning_market_value > (0)::numeric) THEN round(((efr.investment_return / efr.beginning_market_value) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS investment_return_pct,
        CASE
            WHEN (efr.rolling_average_market_value > (0)::numeric) THEN round(((efr.spending_distributions / efr.rolling_average_market_value) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS actual_spending_rate_pct
   FROM ((finance.endowment_fund_records efr
     JOIN finance.funds f ON ((f.id = efr.fund_id)))
     JOIN finance.fiscal_years fy ON ((fy.id = efr.fiscal_year_id)));


ALTER VIEW finance.vw_endowment_summary OWNER TO postgres;

--
-- Name: VIEW vw_endowment_summary; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_endowment_summary IS 'CFO endowment dashboard. investment_return_pct and actual_spending_rate_pct are computed from snapshots rather than live data so they are always consistent with the year-end financial statements. is_underwater flags require FASB 958 additional disclosures.';


--
-- Name: vw_nexus_alerts; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_nexus_alerts AS
 SELECT enm.tenant_id,
    tj.jurisdiction_code,
    tj.name AS jurisdiction_name,
    tj.subdivision_code,
    enm.period_end_date,
    enm.trailing_12m_revenue,
    enm.revenue_threshold,
    enm.revenue_threshold_pct,
    enm.trailing_12m_transactions,
    enm.transaction_threshold,
    enm.nexus_triggered,
        CASE
            WHEN enm.nexus_triggered THEN 'NEXUS TRIGGERED — register immediately'::text
            WHEN (enm.revenue_threshold_pct >= (90)::numeric) THEN 'CRITICAL — approaching threshold'::text
            WHEN (enm.revenue_threshold_pct >= (75)::numeric) THEN 'WARNING — monitor closely'::text
            ELSE 'OK'::text
        END AS alert_level,
    tn.is_registered AS is_registered_in_jurisdiction
   FROM ((finance.economic_nexus_monitoring enm
     JOIN finance.tax_jurisdictions tj ON ((tj.id = enm.jurisdiction_id)))
     LEFT JOIN finance.tax_nexus tn ON (((tn.tenant_id = enm.tenant_id) AND (tn.jurisdiction_id = enm.jurisdiction_id))))
  WHERE ((enm.revenue_threshold_pct >= (75)::numeric) OR (enm.nexus_triggered = true));


ALTER VIEW finance.vw_nexus_alerts OWNER TO postgres;

--
-- Name: VIEW vw_nexus_alerts; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_nexus_alerts IS 'Economic nexus threshold monitoring alerts. Returns only jurisdictions at 75%+ of threshold or where nexus has already triggered. alert_level drives the compliance dashboard color coding and the automated alert emails to the CFO and controller.';


--
-- Name: academic_terms; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.academic_terms (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(50) NOT NULL,
    academic_year integer NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    status sis.term_status DEFAULT 'planning'::sis.term_status NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    alias character varying(10) NOT NULL,
    census_date date,
    nsc_academic_year character varying(9),
    nsc_reporting_period character varying(2),
    nslds_reporting_period character varying(2),
    enrollment_reporting_due date
);


ALTER TABLE sis.academic_terms OWNER TO postgres;

--
-- Name: TABLE academic_terms; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.academic_terms IS 'Institutional calendar terms (semesters, quarters, trimesters). alias is the short display label (e.g., "FA26"). status: upcoming → enrollment_open → in_session → grading → closed. start_date and end_date define the instructional period.';


--
-- Name: COLUMN academic_terms.census_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_terms.census_date IS 'The date at which enrollment status is frozen for federal reporting. NSC enrollment snapshots and Title IV enrollment reporting are based on this date, not term start or end. Set by the registrar when the term is created. Required before any NSC submission can be generated.';


--
-- Name: COLUMN academic_terms.nsc_reporting_period; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_terms.nsc_reporting_period IS 'NSC academic period code: 01=Spring, 02=Summer, 03=Fall. Included in every NSC enrollment reporting record for this term.';


--
-- Name: COLUMN academic_terms.nslds_reporting_period; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.academic_terms.nslds_reporting_period IS 'Department of Education enrollment reporting period code. May differ from nsc_reporting_period for non-standard calendars.';


--
-- Name: student_profiles; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.student_profiles (
    user_id uuid NOT NULL,
    tenant_id uuid NOT NULL,
    enrollment_year integer NOT NULL,
    expected_graduation_year integer,
    cumulative_gpa numeric(3,2) DEFAULT 0.00,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    term_gpa numeric(4,3),
    gpa_last_calculated_at timestamp with time zone,
    academic_standing_status sis.academic_standing_status DEFAULT 'good_standing'::sis.academic_standing_status,
    expected_graduation_term_id uuid,
    first_enrollment_term_id uuid,
    cumulative_credits_attempted numeric(7,2) DEFAULT 0 NOT NULL,
    cumulative_credits_earned numeric(7,2) DEFAULT 0 NOT NULL,
    current_timeframe_pct numeric(6,2),
    nsc_student_id character varying(20),
    ssn_last_four character varying(4),
    middle_initial character varying(1),
    is_nsc_opted_out boolean DEFAULT false NOT NULL,
    CONSTRAINT student_profiles_credits_attempted_non_negative CHECK ((cumulative_credits_attempted >= (0)::numeric)),
    CONSTRAINT student_profiles_credits_earned_non_negative CHECK ((cumulative_credits_earned >= (0)::numeric)),
    CONSTRAINT student_profiles_cumulative_gpa_range CHECK (((cumulative_gpa IS NULL) OR ((cumulative_gpa >= (0)::numeric) AND (cumulative_gpa <= 4.0)))),
    CONSTRAINT student_profiles_term_gpa_range CHECK (((term_gpa IS NULL) OR ((term_gpa >= (0)::numeric) AND (term_gpa <= 4.0)))),
    CONSTRAINT student_profiles_timeframe_pct_non_negative CHECK (((current_timeframe_pct IS NULL) OR (current_timeframe_pct >= (0)::numeric)))
);


ALTER TABLE sis.student_profiles OWNER TO postgres;

--
-- Name: TABLE student_profiles; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_profiles IS 'The institutional student record. Links one-to-one with core.users within a tenant. enrollment_year, cumulative_gpa, and expected_graduation_year are maintained by the SIS service. The detailed academic history lives in enrollments, transcript_records, and student_programs.';


--
-- Name: COLUMN student_profiles.term_gpa; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.term_gpa IS 'GPA for the most recently completed term. Updated by the Rust GPA service during end-of-term batch recalculation.';


--
-- Name: COLUMN student_profiles.gpa_last_calculated_at; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.gpa_last_calculated_at IS 'Timestamp of the most recent GPA recalculation for this student. Used to detect stale GPA values and prioritise recalculation queues.';


--
-- Name: COLUMN student_profiles.academic_standing_status; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.academic_standing_status IS 'Current academic standing. Updated by the Rust academic standing service after each end-of-term evaluation. Drives registration eligibility checks and financial aid SAP status.';


--
-- Name: COLUMN student_profiles.expected_graduation_term_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.expected_graduation_term_id IS 'The specific term the student is expected to graduate. Preferred over expected_graduation_year for precision — a student expected to graduate "Spring 2027" maps to a specific academic_terms row, enabling exact remaining-terms calculations. Set by the advisor or computed from enrollment plan.';


--
-- Name: COLUMN student_profiles.first_enrollment_term_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.first_enrollment_term_id IS 'The term in which the student first enrolled at this institution. The canonical start of the institutional timeframe clock. For transfer students this is the term of first enrollment here, not at the sending institution. Set at student profile creation.';


--
-- Name: COLUMN student_profiles.cumulative_credits_attempted; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.cumulative_credits_attempted IS 'Pre-computed sum of credits_attempted across all non-excluded transcript records. Maintained by the Rust GPA service after each recalculation. Avoids a full transcript_records scan on every registrar dashboard load.';


--
-- Name: COLUMN student_profiles.cumulative_credits_earned; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.cumulative_credits_earned IS 'Pre-computed sum of credits_earned across all transcript records where final_letter_grade is passing. Complement to cumulative_gpa.';


--
-- Name: COLUMN student_profiles.current_timeframe_pct; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.current_timeframe_pct IS 'Most recent timeframe percentage from sis.student_timeframe_snapshots. Denormalized here for fast single-row reads in the registrar dashboard and student portal. Updated by the GPA service after each term close.';


--
-- Name: COLUMN student_profiles.nsc_student_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.nsc_student_id IS 'The student identifier assigned by the National Student Clearinghouse after first enrollment submission. Returned by NSC in the response file. Must be included in all subsequent NSC submissions for this student to ensure correct matching. NULL until NSC confirms first receipt.';


--
-- Name: COLUMN student_profiles.ssn_last_four; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.ssn_last_four IS 'Last four digits of SSN. Used as a secondary match field in NSC and NSLDS submissions when the full SSN is not transmitted. Stored separately from the full SSN (which is in data_governance.pii_field_registry and never stored in plain text in application tables).';


--
-- Name: COLUMN student_profiles.is_nsc_opted_out; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_profiles.is_nsc_opted_out IS 'Whether the student has exercised their right to opt out of NSC enrollment disclosure under FERPA. When true, the student is excluded from NSC enrollment reporting submissions.';


--
-- Name: vw_nslds_aid_report; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_nslds_aid_report AS
 SELECT fa.tenant_id,
    fa.student_id,
    u.first_name,
    u.last_name,
    sp.ssn_last_four,
    fr.aid_year,
    fr.isir_transaction_number,
    fr.dependency_status,
    fr.pell_eligibility_flag,
    fr.verification_required,
    fr.verification_group,
    fa.id AS award_id,
    fa.aid_type,
    fa.nslds_loan_type,
    fa.loan_sequence_number,
    fa.loan_period_begin_date,
    fa.loan_period_end_date,
    fa.offered_amount,
    fa.accepted_amount,
    fa.disbursed_amount,
    fa.grade_level_at_award,
    fa.status AS award_status,
    fa.last_reported_to_nslds,
    t.name AS term_name,
    t.nslds_reporting_period
   FROM ((((finance.financial_aid_awards fa
     JOIN core.users u ON ((u.id = fa.student_id)))
     JOIN sis.student_profiles sp ON (((sp.user_id = fa.student_id) AND (sp.tenant_id = fa.tenant_id))))
     LEFT JOIN finance.fafsa_records fr ON (((fr.student_id = fa.student_id) AND (fr.tenant_id = fa.tenant_id) AND ((fr.aid_year)::text = ((to_char((( SELECT academic_terms.start_date
           FROM sis.academic_terms
          WHERE (academic_terms.id = fa.term_id)))::timestamp with time zone, 'YYYY'::text) || '-'::text) || to_char((( SELECT academic_terms.start_date
           FROM sis.academic_terms
          WHERE (academic_terms.id = fa.term_id)) + '1 year'::interval), 'YYYY'::text))))))
     LEFT JOIN sis.academic_terms t ON ((t.id = fa.term_id)));


ALTER VIEW finance.vw_nslds_aid_report OWNER TO postgres;

--
-- Name: VIEW vw_nslds_aid_report; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_nslds_aid_report IS 'NSLDS financial aid reporting data combining award records with ISIR context. Joins fafsa_records on a computed aid_year string to match the ED aid year format (YYYY-YYYY). last_reported_to_nslds = NULL identifies records pending first submission. Consumed by the Rust reporting service for loan origination, disbursement, and Pell grant reporting to COD and NSLDS.';


--
-- Name: vw_statement_of_financial_position; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_statement_of_financial_position AS
 SELECT ga.tenant_id,
    ga.type AS account_type,
    ga.fsli_code,
    ga.account_name,
    ga.account_code,
    ga.current_balance,
    ga.normal_balance,
    ga.is_contra,
    ga.reporting_order,
        CASE
            WHEN ga.is_contra THEN (- ga.current_balance)
            ELSE ga.current_balance
        END AS net_balance,
    f.net_asset_class,
    fy.name AS fiscal_year_name,
    fy.id AS fiscal_year_id
   FROM (((finance.gl_accounts ga
     LEFT JOIN finance.funds f ON ((f.id = ( SELECT ll.fund_id
           FROM finance.journal_lines ll
          WHERE (ll.gl_account_id = ga.id)
         LIMIT 1))))
     JOIN finance.charts_of_accounts coa ON ((coa.id = ga.coa_id)))
     JOIN finance.fiscal_years fy ON ((fy.id = coa.fiscal_year_id)))
  WHERE (ga.is_active = true)
  ORDER BY ga.type, ga.reporting_order, ga.account_code;


ALTER VIEW finance.vw_statement_of_financial_position OWNER TO postgres;

--
-- Name: VIEW vw_statement_of_financial_position; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_statement_of_financial_position IS 'Statement of Financial Position (FASB 958) / Balance Sheet data. net_balance respects contra account polarity. Group by account_type for the standard Assets / Liabilities / Net Assets presentation. Filter by net_asset_class for the FASB 958 net asset classification columns.';


--
-- Name: vw_tax_liability_summary; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_tax_liability_summary AS
 SELECT ttl.tenant_id,
    tj.jurisdiction_code,
    tj.name AS jurisdiction_name,
    tj.tax_regime,
    tj.level AS jurisdiction_level,
    date_trunc('month'::text, ttl.calculated_at) AS tax_month,
    count(*) AS transaction_count,
    sum(ttl.taxable_amount) AS total_taxable_amount,
    sum(ttl.tax_amount) AS total_tax_amount,
    sum(
        CASE
            WHEN ttl.is_exempt THEN ttl.taxable_amount
            ELSE (0)::numeric
        END) AS exempt_amount,
    sum(
        CASE
            WHEN ttl.is_posted_to_gl THEN ttl.tax_amount
            ELSE (0)::numeric
        END) AS posted_to_gl,
    sum(
        CASE
            WHEN (NOT ttl.is_posted_to_gl) THEN ttl.tax_amount
            ELSE (0)::numeric
        END) AS pending_gl_posting
   FROM (finance.transaction_tax_lines ttl
     JOIN finance.tax_jurisdictions tj ON ((tj.id = ttl.jurisdiction_id)))
  GROUP BY ttl.tenant_id, tj.jurisdiction_code, tj.name, tj.tax_regime, tj.level, (date_trunc('month'::text, ttl.calculated_at));


ALTER VIEW finance.vw_tax_liability_summary OWNER TO postgres;

--
-- Name: VIEW vw_tax_liability_summary; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_tax_liability_summary IS 'Monthly tax liability summary by jurisdiction. Shows total taxable amount, tax collected, exempt amounts, and GL posting status per jurisdiction per month. Consumed by the tax compliance dashboard and filing period preparation.';


--
-- Name: vw_va_certifications; Type: VIEW; Schema: finance; Owner: postgres
--

CREATE VIEW finance.vw_va_certifications AS
 SELECT vc.tenant_id,
    vp.student_id,
    u.first_name,
    u.last_name,
    vp.primary_chapter,
    vp.eligibility_percentage,
    vp.months_of_entitlement_remaining,
    vp.va_file_number,
    vc.id AS certification_id,
    vc.certification_date,
    vc.credits_certified,
    vc.tuition_reported,
    vc.fees_reported,
    vc.enrollment_intensity_va,
    vc.training_time_percentage,
    vc.is_amendment,
    vc.amends_certification_id,
    vc.va_confirmation_number,
    vc.ch33_housing_rate,
    vc.ch33_book_stipend,
    vc.program_of_study,
    vc.amendment_date,
    t.name AS term_name,
    t.start_date AS term_start,
    t.end_date AS term_end,
    (((u2.first_name)::text || ' '::text) || (u2.last_name)::text) AS certified_by
   FROM ((((finance.va_certifications vc
     JOIN finance.veteran_profiles vp ON ((vp.id = vc.veteran_profile_id)))
     JOIN core.users u ON ((u.id = vp.student_id)))
     JOIN sis.academic_terms t ON ((t.id = vc.term_id)))
     LEFT JOIN core.users u2 ON ((u2.id = vc.certified_by_id)))
  ORDER BY vc.certification_date DESC;


ALTER VIEW finance.vw_va_certifications OWNER TO postgres;

--
-- Name: VIEW vw_va_certifications; Type: COMMENT; Schema: finance; Owner: postgres
--

COMMENT ON VIEW finance.vw_va_certifications IS 'VA School Certifying Official (SCO) view of all certifications. Provides the full context needed for the SCO dashboard: student benefit chapter, entitlement remaining, training time, housing rates, and amendment history. Consumed by the Rust VA reporting module and the SCO dashboard UI.';


--
-- Name: budgeted_positions; Type: TABLE; Schema: hr; Owner: postgres
