ALTER TABLE hr.budgeted_positions OWNER TO postgres;

--
-- Name: TABLE budgeted_positions; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.budgeted_positions IS 'An authorized, funded staff or faculty position in the org chart. position_code is the human-readable identifier. fte specifies the full-time equivalency. Links to both a GL account and a ledger account for payroll encumbrance. Job requisitions must reference a budgeted position before a posting can be made.';


