ALTER TABLE hr.employee_supervisors OWNER TO postgres;

--
-- Name: TABLE employee_supervisors; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.employee_supervisors IS 'Reporting relationships. One row per (employee, supervisor) pair. The no_self_management CHECK constraint prevents self-reporting. Multiple rows allow matrixed reporting relationships.';


--
-- Name: employment_contracts; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.employment_contracts (
