COMMENT ON TABLE hr.employment_contracts IS 'A formal employment agreement specifying job_title, contract type (full_time, part_time, adjunct, at_will, fixed_term), salary or hourly rate, start/end dates, and the budgeted position being filled. is_active marks the currently effective contract. Historical contracts are retained for audit.';


--
-- Name: interview_panelists; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.interview_panelists (
    interview_id uuid NOT NULL,
    user_id uuid NOT NULL
);


ALTER TABLE hr.interview_panelists OWNER TO postgres;

--
-- Name: TABLE interview_panelists; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.interview_panelists IS 'Junction table linking an interview session to its panel members. Each panelist is a core.users record.';


--
-- Name: interviews; Type: TABLE; Schema: hr; Owner: postgres
