COMMENT ON TABLE hr.job_offers IS 'A formal employment offer extended to a job application. salary_grid_node_id links to the specific step/lane cell from the ratified salary schedule. expiration_date is the offer acceptance deadline. signed_document_id links to the countersigned offer letter in the DMS.';


--
-- Name: job_postings; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.job_postings (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    requisition_id uuid NOT NULL,
    public_title character varying(255) NOT NULL,
    markdown_description text NOT NULL,
    markdown_requirements text NOT NULL,
    markdown_benefits text,
    is_internal_only boolean DEFAULT false NOT NULL,
    is_published boolean DEFAULT false NOT NULL,
    open_date date DEFAULT CURRENT_DATE NOT NULL,
    close_date date,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS (((setweight(to_tsvector('english'::regconfig, (COALESCE(public_title, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(markdown_description, ''::text)), 'B'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(markdown_requirements, ''::text)), 'C'::"char"))) STORED
);


ALTER TABLE hr.job_postings OWNER TO postgres;

--
-- Name: TABLE job_postings; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.job_postings IS 'A published job advertisement derived from an approved requisition. is_internal_only gates visibility to current employees only. is_published controls whether the posting appears on the public careers page. fts_doc enables job search across title, description, and requirements.';


--
-- Name: job_requisitions; Type: TABLE; Schema: hr; Owner: postgres
--

