);


ALTER TABLE hr.job_requisitions OWNER TO postgres;

--
-- Name: TABLE job_requisitions; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.job_requisitions IS 'A formal request to fill a budgeted position. Requires workflow approval before a job posting can be created. hiring_manager_id is the department head requesting the hire.';


--
-- Name: leave_balances; Type: TABLE; Schema: hr; Owner: postgres
--

