    submitted_at timestamp with time zone DEFAULT now() NOT NULL,
    reviewed_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT valid_leave_dates CHECK ((end_date >= start_date))
);


ALTER TABLE hr.leave_requests OWNER TO postgres;

--
-- Name: TABLE leave_requests; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.leave_requests IS 'A formal request for time off. valid_leave_dates CHECK enforces end_date >= start_date. Status: pending → approved → denied → cancelled. Approved requests decrement leave_balances.hours_used.';


--
-- Name: performance_evaluations; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.performance_evaluations (
