    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE hr.performance_evaluations OWNER TO postgres;

--
-- Name: TABLE performance_evaluations; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.performance_evaluations IS 'An annual or periodic performance review. Links to an lms.rubric defining the scoring criteria. overall_score is computed from rubric criteria scores. employee_comments and evaluator_notes are stored separately. Acknowledged by employee via the workflow signature flow.';


--
-- Name: salary_grid_nodes; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.salary_grid_nodes (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    grid_id uuid NOT NULL,
    step_index integer NOT NULL,
    lane_name character varying(50) NOT NULL,
    base_salary numeric(10,2) NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE hr.salary_grid_nodes OWNER TO postgres;

--
-- Name: TABLE salary_grid_nodes; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.salary_grid_nodes IS 'An individual cell in a salary grid identified by lane_name (e.g., BA, BA+15, MA) and step_index (years of service step). base_salary is the annual compensation at this cell. Job offers reference a specific node to ensure compensation consistency with the ratified salary schedule.';


--
-- Name: salary_grids; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.salary_grids (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
