);


ALTER TABLE hr.salary_grids OWNER TO postgres;

--
-- Name: TABLE salary_grids; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.salary_grids IS 'A versioned salary schedule (step/lane table) governing compensation for a defined period. effective_start_date / effective_end_date allow multiple grids to exist for historical lookups and future contract planning.';


--
-- Name: staff_credentials; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.staff_credentials (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    staff_id uuid NOT NULL,
    credential_name character varying(255) NOT NULL,
