    status sis.credential_status DEFAULT 'active'::sis.credential_status NOT NULL,
    issued_date date NOT NULL,
    expiration_date date,
    document_url character varying(1024),
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE hr.staff_credentials OWNER TO postgres;

--
-- Name: TABLE staff_credentials; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.staff_credentials IS 'Professional licenses and certifications (teaching credentials, CPA, nursing license). expiration_date triggers renewal reminders via the comms journey engine. document_url links to the certificate stored in the DMS.';


--
-- Name: staff_profiles; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.staff_profiles (
