);


ALTER TABLE hr.staff_profiles OWNER TO postgres;

--
-- Name: TABLE staff_profiles; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.staff_profiles IS 'The institutional HR profile for an employee, linked one-to-one with core.users. hire_date, is_tenured, and primary_department_id are the key HR system fields. Additional detail (title, salary, contract type) lives in the active employment_contracts row.';


--
-- Name: timesheets; Type: TABLE; Schema: hr; Owner: postgres
--

CREATE TABLE hr.timesheets (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    staff_id uuid NOT NULL,
