    approved_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE hr.timesheets OWNER TO postgres;

--
-- Name: TABLE timesheets; Type: COMMENT; Schema: hr; Owner: postgres
--

COMMENT ON TABLE hr.timesheets IS 'A submitted and approved record of hours worked for a pay period. Linked to the employee''s active employment contract. Status: draft → submitted → approved → rejected. total_hours is validated against the contract''s expected hours.';


--
-- Name: announcements; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.announcements (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    author_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    markdown_body text NOT NULL,
    publish_at timestamp with time zone DEFAULT now() NOT NULL,
    force_push_notification boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS ((setweight(to_tsvector('english'::regconfig, (COALESCE(title, ''::character varying))::text), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(markdown_body, ''::text)), 'B'::"char"))) STORED
);


ALTER TABLE lms.announcements OWNER TO postgres;

--
-- Name: TABLE announcements; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.announcements IS 'Course-section-scoped announcements from instructors. publish_at enables scheduled announcements. force_push_notification bypasses user notification preferences to guarantee delivery for critical messages.';


--
-- Name: answer_choices; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.answer_choices (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    question_version_id uuid NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    choice_content text NOT NULL,
    choice_content_format character varying(10) DEFAULT 'markdown'::character varying NOT NULL,
    choice_image_url character varying(1024),
    is_correct boolean DEFAULT false NOT NULL,
    partial_credit_weight numeric(4,3) DEFAULT 0 NOT NULL,
    choice_feedback text,
    matching_right_content text,
    correct_position smallint,
    times_selected integer DEFAULT 0 NOT NULL,
    CONSTRAINT answer_choices_partial_credit_range CHECK (((partial_credit_weight >= (0)::numeric) AND (partial_credit_weight <= (1)::numeric)))
);


ALTER TABLE lms.answer_choices OWNER TO postgres;

--
-- Name: TABLE answer_choices; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.answer_choices IS 'Answer options for choice-based question types. Attached to question_versions so editing a question can change the choices without affecting historical attempts. partial_credit_weight enables sophisticated multiple_select scoring: a student who selects 3 of 4 correct choices gets proportional credit. times_selected drives distractor analysis in the item analytics dashboard.';


--
-- Name: assessment_accommodations; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_accommodations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    assessment_id uuid NOT NULL,
    student_id uuid NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    time_multiplier_override numeric(5,3),
    extended_time_minutes_override integer,
    distraction_free_override boolean,
    separate_setting_override boolean,
    reader_tool_override boolean,
    scribe_override boolean,
    calculator_override boolean,
    spell_check_override boolean,
    allows_breaks_override boolean,
    break_duration_minutes_override smallint,
    max_attempts_override smallint,
    override_reason text NOT NULL,
    approved_by_user_id uuid NOT NULL,
    approved_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone,
    CONSTRAINT assessment_accommodations_extra_time_positive CHECK (((extended_time_minutes_override IS NULL) OR (extended_time_minutes_override > 0))),
    CONSTRAINT assessment_accommodations_time_multiplier_positive CHECK (((time_multiplier_override IS NULL) OR (time_multiplier_override >= (1)::numeric)))
);


ALTER TABLE lms.assessment_accommodations OWNER TO postgres;

--
-- Name: TABLE assessment_accommodations; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessment_accommodations IS 'Per-assessment accommodation overrides for specific students. The Rust attempt-start service resolves accommodations in three steps: (1) load lms.student_accommodations for this student; (2) apply lms.assessment_accommodations overrides if present; (3) snapshot the resolved values onto lms.assessment_attempts. The attempt snapshot is the authoritative compliance record — it does not change if the accommodation record is later modified. approved_by_user_id is NOT NULL — every override requires a named approver for IEP/504 compliance audit trails.';


--
-- Name: assessment_analytics_snapshots; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_analytics_snapshots (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    assessment_id uuid NOT NULL,
    computed_at timestamp with time zone DEFAULT now() NOT NULL,
    total_students_enrolled integer DEFAULT 0 NOT NULL,
    total_attempts_submitted integer DEFAULT 0 CONSTRAINT assessment_analytics_snapshot_total_attempts_submitted_not_null NOT NULL,
    total_students_attempted integer DEFAULT 0 CONSTRAINT assessment_analytics_snapshot_total_students_attempted_not_null NOT NULL,
    mean_score_pct numeric(6,3),
    median_score_pct numeric(6,3),
    stddev_score_pct numeric(6,3),
    min_score_pct numeric(6,3),
    max_score_pct numeric(6,3),
    grade_distribution jsonb,
    pass_count integer,
    fail_count integer,
    pass_rate_pct numeric(5,2),
    mean_time_minutes numeric(6,2),
    median_time_minutes numeric(6,2),
    items_needing_review integer DEFAULT 0 NOT NULL,
    dimension_breakdowns jsonb,
    flagged_attempt_count integer DEFAULT 0 NOT NULL,
    invalidated_attempt_count integer DEFAULT 0 CONSTRAINT assessment_analytics_snapsho_invalidated_attempt_count_not_null NOT NULL
);


ALTER TABLE lms.assessment_analytics_snapshots OWNER TO postgres;

--
-- Name: TABLE assessment_analytics_snapshots; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessment_analytics_snapshots IS 'Cohort-level assessment analytics, computed and stored after each grading run. Stored rather than computed on demand because aggregating over all attempts and responses is expensive — this makes the instructor dashboard instant. dimension_breakdowns JSONB contains the class-wide breakdown by chapter, Bloom''s level, and standard, matching what individual students see in their own attempt_score_breakdowns.';


--
-- Name: assessment_attempts; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_attempts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    assessment_id uuid NOT NULL,
    student_id uuid NOT NULL,
    attempt_number smallint DEFAULT 1 NOT NULL,
    status lms.attempt_status DEFAULT 'in_progress'::lms.attempt_status NOT NULL,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    submitted_at timestamp with time zone,
    time_spent_seconds integer,
    effective_time_limit_minutes integer,
    break_time_seconds integer DEFAULT 0 NOT NULL,
    accommodation_time_multiplier numeric(5,3),
    accommodation_extra_minutes integer,
    accommodation_distraction_free boolean DEFAULT false NOT NULL,
    accommodation_reader_enabled boolean DEFAULT false NOT NULL,
    accommodation_scribe_enabled boolean DEFAULT false NOT NULL,
    accommodation_breaks_allowed boolean DEFAULT false NOT NULL,
    accommodation_notes text,
    raw_score numeric(8,2),
    adjusted_score numeric(8,2),
    score_pct numeric(6,3),
    is_passing boolean,
    is_auto_graded boolean DEFAULT false NOT NULL,
    is_human_reviewed boolean DEFAULT false NOT NULL,
    graded_by_user_id uuid,
    graded_at timestamp with time zone,
    score_released_at timestamp with time zone,
    question_sequence jsonb,
    ip_address inet,
    user_agent text,
    browser_fingerprint_hash character varying(64),
    is_flagged boolean DEFAULT false NOT NULL,
    flag_reason text,
    flag_reviewed_by_user_id uuid,
    flag_reviewed_at timestamp with time zone,
    flag_resolution character varying(20),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT assessment_attempts_attempt_number_positive CHECK ((attempt_number > 0)),
    CONSTRAINT assessment_attempts_scores_non_negative CHECK ((((raw_score IS NULL) OR (raw_score >= (0)::numeric)) AND ((adjusted_score IS NULL) OR (adjusted_score >= (0)::numeric)))),
    CONSTRAINT assessment_attempts_time_non_negative CHECK (((time_spent_seconds IS NULL) OR (time_spent_seconds >= 0)))
);


ALTER TABLE lms.assessment_attempts OWNER TO postgres;

--
-- Name: TABLE assessment_attempts; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessment_attempts IS 'One row per student per attempt. The atomic unit of the assessment system. question_sequence JSONB stores the shuffled order for this attempt — on resume, the same order is presented; on review, the instructor sees what the student saw. Accommodation fields snapshot what was actually applied — authoritative for IEP/504 compliance auditing, independent of what the accommodation record says today. browser_fingerprint_hash enables detection of the same student submitting from multiple devices simultaneously.';


--
-- Name: assessment_items; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_items (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    question_id uuid NOT NULL,
    question_version_id uuid,
    display_order smallint DEFAULT 0 NOT NULL,
    points numeric(7,2) DEFAULT 1 NOT NULL,
    shuffle_choices_override boolean,
    grading_note text,
    CONSTRAINT assessment_items_points_positive CHECK ((points > (0)::numeric))
);


ALTER TABLE lms.assessment_items OWNER TO postgres;

--
-- Name: TABLE assessment_items; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessment_items IS 'Fixed questions placed directly into an assessment section. question_version_id = NULL means always use the current version — appropriate for active exams where the instructor may refine wording before the exam opens. Setting a specific version_id locks the question to that exact wording, appropriate for released exams. Mix with assessment_pools in the same section: fixed anchor questions plus a random draw pool for variety.';


--
-- Name: assessment_pools; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_pools (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    bank_id uuid NOT NULL,
    questions_to_draw smallint DEFAULT 1 NOT NULL,
    points_per_question numeric(7,2) DEFAULT 1 NOT NULL,
    filter_question_types lms.question_type[],
    filter_tags jsonb,
    filter_blooms_levels lms.blooms_level[],
    filter_difficulty lms.difficulty_level[],
    filter_standard_ids uuid[],
    available_count integer DEFAULT 0 NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    CONSTRAINT assessment_pools_draw_positive CHECK ((questions_to_draw > 0)),
    CONSTRAINT assessment_pools_sufficient_questions CHECK (((available_count >= questions_to_draw) OR (available_count = 0)))
);


ALTER TABLE lms.assessment_pools OWNER TO postgres;

--
-- Name: TABLE assessment_pools; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessment_pools IS 'Random question draw pools for exam randomization. At attempt-start, the Rust assessment engine resolves which questions match all filter criteria and randomly selects questions_to_draw from the matching set. available_count is maintained by trigger — the CHECK constraint prevents publishing an assessment where a pool has fewer available questions than the draw count. filter_tags uses JSONB to support complex tag queries like chapter:5 AND topic:mitosis.';


--
-- Name: assessment_sections; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessment_sections (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    assessment_id uuid NOT NULL,
    title character varying(200),
    instructions text,
    display_order smallint DEFAULT 0 NOT NULL,
    time_limit_minutes integer,
    total_points numeric(8,2),
    shuffle_questions boolean DEFAULT false NOT NULL
);


ALTER TABLE lms.assessment_sections OWNER TO postgres;

--
-- Name: assessments; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assessments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    assignment_id uuid NOT NULL,
    section_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    instructions text,
    status lms.assessment_status DEFAULT 'draft'::lms.assessment_status NOT NULL,
    available_from timestamp with time zone,
    available_until timestamp with time zone,
    time_limit_minutes integer,
    time_limit_action lms.time_limit_action DEFAULT 'submit_automatically'::lms.time_limit_action NOT NULL,
    timer_starts_on character varying(20) DEFAULT 'first_access'::character varying NOT NULL,
    max_attempts smallint DEFAULT 1 NOT NULL,
    attempt_score_policy lms.attempt_score_policy DEFAULT 'highest'::lms.attempt_score_policy NOT NULL,
    attempt_cooldown_minutes integer DEFAULT 0 NOT NULL,
    show_score_immediately boolean DEFAULT false NOT NULL,
    show_correct_answers character varying(20) DEFAULT 'after_grading'::character varying NOT NULL,
    show_incorrect_only boolean DEFAULT false NOT NULL,
    shuffle_questions boolean DEFAULT false NOT NULL,
    shuffle_answer_choices boolean DEFAULT true NOT NULL,
    one_question_at_a_time boolean DEFAULT false NOT NULL,
    lock_answered_questions boolean DEFAULT false NOT NULL,
    show_question_numbers boolean DEFAULT true NOT NULL,
    allow_question_flagging boolean DEFAULT true NOT NULL,
    show_progress_bar boolean DEFAULT true NOT NULL,
    require_fullscreen boolean DEFAULT false NOT NULL,
    proctoring_tool_id uuid,
    allowed_ip_ranges text[],
    access_passcode character varying(100),
    disable_copy_paste boolean DEFAULT false NOT NULL,
    log_behavioral_events boolean DEFAULT true NOT NULL,
    total_points numeric(8,2) DEFAULT 100 NOT NULL,
    passing_score_pct numeric(5,2),
    auto_grade_on_submit boolean DEFAULT true NOT NULL,
    created_by_user_id uuid NOT NULL,
    published_by_user_id uuid,
    published_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT assessments_lock_requires_one_at_a_time CHECK (((NOT lock_answered_questions) OR one_question_at_a_time)),
    CONSTRAINT assessments_max_attempts_positive CHECK ((max_attempts > 0)),
    CONSTRAINT assessments_window_valid CHECK (((available_until IS NULL) OR (available_from IS NULL) OR (available_until > available_from)))
);


ALTER TABLE lms.assessments OWNER TO postgres;

--
-- Name: TABLE assessments; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assessments IS 'Exam/quiz configuration. Links to lms.assignments (the gradebook anchor) via assignment_id. Every field that makes an assessment different from a homework assignment lives here: timing, attempts, anti-cheat, presentation. lock_answered_questions CHECK enforces that you cannot lock questions unless one_question_at_a_time is also true. proctoring_tool_id links to an LTI 1.3 proctoring tool (Honorlock, Respondus, ExamSoft) — the LTI launch initiates the proctoring session.';


--
-- Name: assignment_groups; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assignment_groups (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    weight numeric(5,2) NOT NULL,
    drop_policy lms.drop_policy DEFAULT 'none'::lms.drop_policy NOT NULL,
    drop_count smallint DEFAULT 0 NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT assignment_groups_drop_count_non_negative CHECK ((drop_count >= 0)),
    CONSTRAINT assignment_groups_drop_count_with_policy CHECK (((drop_policy = 'none'::lms.drop_policy) OR (drop_count > 0))),
    CONSTRAINT assignment_groups_weight_range CHECK (((weight >= (0)::numeric) AND (weight <= (100)::numeric)))
);


ALTER TABLE lms.assignment_groups OWNER TO postgres;

--
-- Name: TABLE assignment_groups; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assignment_groups IS 'Weighted grading category buckets within a course section. Each assignment belongs to one group via lms.assignments.group_id. Weights across all groups in a section should sum to 100 (enforced by application). drop_policy and drop_count support lowest/highest score dropping.';


--
-- Name: assignment_standards; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assignment_standards (
    tenant_id uuid NOT NULL,
    assignment_id uuid NOT NULL,
    standard_id uuid NOT NULL
);


ALTER TABLE lms.assignment_standards OWNER TO postgres;

--
-- Name: TABLE assignment_standards; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assignment_standards IS 'Maps an assignment to one or more learning standards it addresses. Drives standards-based grading and mastery tracking.';


--
-- Name: assignments; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.assignments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    module_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    description text,
    type lms.assignment_type DEFAULT 'homework'::lms.assignment_type NOT NULL,
    category lms.assignment_category DEFAULT 'formative'::lms.assignment_category NOT NULL,
    max_score numeric(5,2) DEFAULT 100.00 NOT NULL,
    due_date timestamp with time zone NOT NULL,
    allow_late_submissions boolean DEFAULT false NOT NULL,
    is_published boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    rubric_id uuid,
    lti_resource_link_id uuid,
    lti_line_item_id character varying(255),
    learning_package_id uuid,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    group_id uuid,
    assessment_id uuid
);


ALTER TABLE lms.assignments OWNER TO postgres;

--
-- Name: TABLE assignments; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.assignments IS 'A gradable work item within a module. type ENUM: essay, quiz, file_upload, discussion, lti, scorm, peer_review. lti_resource_link_id links to an external tool launch. learning_package_id links to a SCORM or xAPI package. rubric_id enables rubric-based grading. allow_late_submissions and max_score are enforced by the grading service.';


--
-- Name: COLUMN assignments.group_id; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON COLUMN lms.assignments.group_id IS 'The assignment group (weighted category) this assignment belongs to. NULL means the assignment is unweighted or treated as extra credit.';


--
-- Name: COLUMN assignments.assessment_id; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON COLUMN lms.assignments.assessment_id IS 'If this assignment is a quiz or exam, links to lms.assessments for the full assessment configuration. NULL for non-assessment assignments. The inverse FK (assessments.assignment_id) also exists — both directions are maintained for query convenience from either side.';


--
-- Name: attempt_events; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.attempt_events (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    attempt_id uuid NOT NULL,
    event_type lms.attempt_event_type NOT NULL,
    occurred_at timestamp with time zone DEFAULT now() NOT NULL,
    elapsed_seconds integer,
    current_question_id uuid,
    event_metadata jsonb,
    severity character varying(10) DEFAULT 'info'::character varying NOT NULL,
    CONSTRAINT attempt_events_severity_valid CHECK (((severity)::text = ANY ((ARRAY['info'::character varying, 'warning'::character varying, 'critical'::character varying])::text[])))
)
PARTITION BY RANGE (occurred_at);


ALTER TABLE lms.attempt_events OWNER TO postgres;

--
-- Name: TABLE attempt_events; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.attempt_events IS 'Append-only behavioral event log. Partitioned by month for performance. Anti-cheat is a timeline, not a flag. The instructor sees: "At 14:32 (12 min into exam): tab_switch (severity: warning).  At 14:33 (13 min): window_focus. At 14:45: copy_attempt (warning)." Severity critical events (face_not_detected, multiple_faces) auto-set assessment_attempts.is_flagged = true via trigger. event_metadata carries context: {app_name: "Calculator"} for prohibited_app_detected; {x: 423, y: 217} for hotspot events.';


