--
-- Name: attempt_proctoring_sessions; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.attempt_proctoring_sessions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    attempt_id uuid NOT NULL,
    proctoring_tool_id uuid NOT NULL,
    external_session_id character varying(255) NOT NULL,
    review_url character varying(1024),
    risk_score smallint,
    proctor_flags jsonb,
    session_started_at timestamp with time zone,
    session_ended_at timestamp with time zone,
    human_reviewed boolean DEFAULT false NOT NULL,
    reviewed_by_user_id uuid,
    reviewed_at timestamp with time zone,
    review_notes text,
    CONSTRAINT attempt_proctoring_sessions_risk_range CHECK (((risk_score IS NULL) OR ((risk_score >= 0) AND (risk_score <= 100))))
);


ALTER TABLE lms.attempt_proctoring_sessions OWNER TO postgres;

--
-- Name: TABLE attempt_proctoring_sessions; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.attempt_proctoring_sessions IS 'Links attempts to external proctoring service sessions (Honorlock, Respondus, ExamSoft). risk_score is the proctoring service''s own AI-generated suspicion score — never used as the sole basis for action; always requires human review. The unreviewed partial index surfaces high-risk sessions first in the instructor''s proctoring review queue.';


--
-- Name: attempt_responses; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.attempt_responses (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    attempt_id uuid NOT NULL,
    question_id uuid NOT NULL,
    question_version_id uuid NOT NULL,
    display_order smallint NOT NULL,
    selected_choice_ids uuid[],
    response_text text,
    response_numeric numeric(18,6),
    response_file_url character varying(1024),
    response_structured jsonb,
    response_media_url character varying(1024),
    first_viewed_at timestamp with time zone,
    last_saved_at timestamp with time zone,
    time_spent_seconds integer,
    is_flagged_for_review boolean DEFAULT false NOT NULL,
    points_possible numeric(7,2) NOT NULL,
    points_earned numeric(7,2),
    is_correct boolean,
    partial_credit_pct numeric(5,2),
    auto_grade_confidence numeric(5,4),
    is_manually_graded boolean DEFAULT false NOT NULL,
    grader_feedback text,
    graded_by_user_id uuid,
    graded_at timestamp with time zone,
    answer_change_count smallint DEFAULT 0 NOT NULL,
    CONSTRAINT attempt_responses_points_le_possible CHECK (((points_earned IS NULL) OR (points_earned <= points_possible))),
    CONSTRAINT attempt_responses_points_non_negative CHECK (((points_possible > (0)::numeric) AND ((points_earned IS NULL) OR (points_earned >= (0)::numeric))))
);


ALTER TABLE lms.attempt_responses OWNER TO postgres;

--
-- Name: TABLE attempt_responses; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.attempt_responses IS 'Per-question responses within an attempt. The item grade ledger. question_version_id is NOT NULL — every response is permanently linked to the exact question wording the student saw. Item analysis that compares pre-edit vs post-edit performance is possible because of this link. first_viewed_at and time_spent_seconds enable time-on-task analysis: which questions do students spend the most time on? Which do they abandon? answer_change_count shows revision behaviour — often correlated with uncertainty.';


--
-- Name: attempt_score_breakdowns; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.attempt_score_breakdowns (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    attempt_id uuid NOT NULL,
    dimension_type character varying(20) NOT NULL,
    dimension_value character varying(100) NOT NULL,
    points_possible numeric(8,2) NOT NULL,
    points_earned numeric(8,2) DEFAULT 0 NOT NULL,
    question_count smallint DEFAULT 0 NOT NULL,
    correct_count smallint DEFAULT 0 NOT NULL,
    score_pct numeric(6,3) GENERATED ALWAYS AS (
CASE
    WHEN (points_possible > (0)::numeric) THEN round(((points_earned / points_possible) * (100)::numeric), 3)
    ELSE (0)::numeric
END) STORED,
    CONSTRAINT attempt_score_breakdowns_amounts_non_negative CHECK (((points_possible >= (0)::numeric) AND (points_earned >= (0)::numeric))),
    CONSTRAINT attempt_score_breakdowns_earned_le_possible CHECK ((points_earned <= points_possible))
);


ALTER TABLE lms.attempt_score_breakdowns OWNER TO postgres;

--
-- Name: TABLE attempt_score_breakdowns; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.attempt_score_breakdowns IS 'Per-attempt score breakdown by multiple dimensions simultaneously. The Rust grading service populates one row per dimension per attempt: (section, "Part A"), (tag, "Chapter 5"), (standard, "CCSS.ELA.RI.9-10.1"), (bloom, "analyze"), (difficulty, "hard"). score_pct is a generated column for fast dashboard rendering. Students see: "You scored 62% on Chapter 5 questions and 89% on Chapter 3." Instructors see: "The class averaged 41% on Bloom:evaluate questions — higher-order thinking needs more practice."';


