    event_type character varying(50) NOT NULL,
    profile character varying(50) DEFAULT 'GeneralProfile'::character varying NOT NULL,
    actor_id uuid,
    actor_type character varying(30) DEFAULT 'Person'::character varying NOT NULL,
    action character varying(50) NOT NULL,
    object_id character varying(255) NOT NULL,
    object_type character varying(50),
    result_score numeric(8,4),
    result_max_score numeric(8,4),
    result_passing boolean,
    course_section_id uuid,
    caliper_payload jsonb NOT NULL,
    occurred_at timestamp with time zone DEFAULT now() NOT NULL
)
PARTITION BY RANGE (occurred_at);


ALTER TABLE lms.caliper_events OWNER TO postgres;

--
-- Name: TABLE caliper_events; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.caliper_events IS 'IMS Caliper Analytics 1.2 learning event log. Partitioned by month. The Rust LMS service emits a Caliper event for every significant learning activity: content viewed, assignment submitted, grade posted. caliper_payload stores the full JSON-LD event for forwarding to external analytics platforms (Tableau, Power BI, custom data warehouse). Partitioning keeps query performance bounded as the table grows — a busy institution generates millions of events per month.';


