-- Name: TABLE course_modules; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.course_modules IS 'A content module within a course section. Ordered by order_index within the section. is_published controls student visibility. Modules group assignments, LTI resource links, and learning packages into logical instructional units.';


--
-- Name: discussion_posts; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.discussion_posts (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    topic_id uuid NOT NULL,
    parent_post_id uuid,
    author_id uuid NOT NULL,
    markdown_body text NOT NULL,
    word_count integer DEFAULT 0 NOT NULL,
    is_endorsed_by_instructor boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.discussion_posts OWNER TO postgres;

--
-- Name: TABLE discussion_posts; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.discussion_posts IS 'A student or instructor post within a discussion topic. parent_post_id enables threaded replies. is_endorsed_by_instructor flags answers marked as correct. word_count supports minimum word count grading requirements.';


--
-- Name: discussion_topics; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.discussion_topics (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    assignment_id uuid,
    author_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    prompt_markdown text NOT NULL,
    discussion_type lms.discussion_type DEFAULT 'standard_forum'::lms.discussion_type NOT NULL,
    is_locked_for_comments boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.discussion_topics OWNER TO postgres;

--
-- Name: TABLE discussion_topics; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.discussion_topics IS 'A discussion prompt within a course section. discussion_type: threaded, Q_and_A (students cannot see others'' posts until they post), announcement (instructor-only posting). assignment_id links when the discussion is a graded activity.';


--
-- Name: grade_history; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grade_history (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    grade_id uuid NOT NULL,
    submission_id uuid NOT NULL,
    score numeric NOT NULL,
    previous_score numeric,
    feedback_text text,
    change_reason lms.grade_change_reason NOT NULL,
    changed_by_user_id uuid NOT NULL,
    is_lti_generated boolean DEFAULT false NOT NULL,
    ip_address inet,
    changed_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT grade_history_previous_score_non_negative CHECK (((previous_score IS NULL) OR (previous_score >= (0)::numeric))),
    CONSTRAINT grade_history_score_non_negative CHECK ((score >= (0)::numeric))
);


ALTER TABLE lms.grade_history OWNER TO postgres;

--
-- Name: TABLE grade_history; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grade_history IS 'Immutable append-only log of every grade change. Written by trigger on every INSERT and UPDATE to lms.grades. Provides complete audit trail for grade disputes, FERPA inspection requests, and academic integrity investigations. Never update or delete rows in this table.';


--
-- Name: grade_roster_entries; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grade_roster_entries (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    roster_id uuid NOT NULL,
    enrollment_id uuid NOT NULL,
    student_id uuid NOT NULL,
    final_letter_grade character varying(5),
    final_quality_points numeric(4,2),
    final_percentage numeric(6,2),
    is_incomplete boolean DEFAULT false NOT NULL,
    incomplete_deadline date,
    incomplete_default_grade character varying(5),
    is_excused boolean DEFAULT false NOT NULL,
    is_registrar_override boolean DEFAULT false NOT NULL,
    override_reason text,
    transcript_record_id uuid,
    entered_by_user_id uuid,
    entered_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT grade_roster_entry_must_have_outcome CHECK (((final_letter_grade IS NOT NULL) OR (is_incomplete = true) OR (is_excused = true))),
    CONSTRAINT grade_roster_incomplete_requires_deadline CHECK (((is_incomplete = false) OR ((incomplete_deadline IS NOT NULL) AND (incomplete_default_grade IS NOT NULL)))),
    CONSTRAINT grade_roster_override_requires_reason CHECK (((is_registrar_override = false) OR (override_reason IS NOT NULL))),
    CONSTRAINT grade_roster_quality_points_non_negative CHECK (((final_quality_points IS NULL) OR (final_quality_points >= (0)::numeric)))
);


ALTER TABLE lms.grade_roster_entries OWNER TO postgres;

--
-- Name: TABLE grade_roster_entries; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grade_roster_entries IS 'Final grade entries within an end-of-term grade roster. One row per enrolled student per roster. final_letter_grade is entered by the instructor; posting writes it to sis.transcript_records and sets transcript_record_id. Entries on a locked roster are immutable — registrar override required. Incomplete grades carry a deadline and a default grade that posts automatically if the student does not resolve the incomplete.';


--
-- Name: grade_roster_submissions; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grade_roster_submissions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    term_id uuid NOT NULL,
    status lms.grade_roster_status DEFAULT 'open'::lms.grade_roster_status NOT NULL,
    opened_at timestamp with time zone DEFAULT now() NOT NULL,
    submission_deadline timestamp with time zone,
    submitted_at timestamp with time zone,
    submitted_by_user_id uuid,
    posted_at timestamp with time zone,
    posted_by_user_id uuid,
    locked_at timestamp with time zone,
    locked_by_user_id uuid,
    registrar_notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT grade_roster_locked_has_timestamp CHECK (((status <> 'locked'::lms.grade_roster_status) OR (locked_at IS NOT NULL))),
    CONSTRAINT grade_roster_posted_has_timestamp CHECK (((status <> ALL (ARRAY['posted'::lms.grade_roster_status, 'locked'::lms.grade_roster_status])) OR (posted_at IS NOT NULL))),
    CONSTRAINT grade_roster_submitted_has_timestamp CHECK (((status = 'open'::lms.grade_roster_status) OR (submitted_at IS NOT NULL)))
);


ALTER TABLE lms.grade_roster_submissions OWNER TO postgres;

--
-- Name: TABLE grade_roster_submissions; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grade_roster_submissions IS 'Formal end-of-term grade submission workflow. The registrar opens a roster (status: open) after the term ends. The instructor enters final grades in grade_roster_entries and submits (status: submitted). The registrar reviews and posts (status: posted), which triggers writing of sis.transcript_records. Locked rosters cannot be changed without registrar intervention. One roster per (section, term).';


--
-- Name: grades; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grades (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    submission_id uuid NOT NULL,
    grader_id uuid NOT NULL,
    score numeric(5,2) NOT NULL,
    feedback_text text,
    graded_at timestamp with time zone DEFAULT now() NOT NULL,
    is_lti_generated boolean DEFAULT false NOT NULL,
    lti_score_maximum numeric(5,2),
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.grades OWNER TO postgres;

--
-- Name: TABLE grades; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grades IS 'The grade record for a submission. is_lti_generated flags grades written back by an external LTI tool via the Assignment and Grades Services. lti_score_maximum carries the tool''s reported maximum for normalization. non_negative_scores CHECK prevents negative grades. One grade row per submission; grade revisions update this row.';


--
-- Name: grading_scale_entries; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grading_scale_entries (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    scale_id uuid NOT NULL,
    letter_grade character varying(5) NOT NULL,
    min_percentage numeric(5,2) NOT NULL,
    quality_points numeric(4,2) NOT NULL,
    counts_in_gpa boolean DEFAULT true NOT NULL,
    earns_credit boolean DEFAULT true NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    CONSTRAINT grading_scale_entries_pct_range CHECK (((min_percentage >= (0)::numeric) AND (min_percentage <= (100)::numeric))),
    CONSTRAINT grading_scale_entries_quality_points_non_negative CHECK ((quality_points >= (0)::numeric))
);


ALTER TABLE lms.grading_scale_entries OWNER TO postgres;

--
-- Name: TABLE grading_scale_entries; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grading_scale_entries IS 'Individual letter grade rows within a grading scale. min_percentage is the floor for the grade (e.g. 93.0 = A, 90.0 = A-). The highest min_percentage at or below the student score determines the letter grade.';


--
-- Name: grading_scales; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.grading_scales (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    applicable_grading_bases text[],
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.grading_scales OWNER TO postgres;

--
-- Name: TABLE grading_scales; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.grading_scales IS 'Tenant-configurable letter grade to GPA point mapping tables. A tenant may define multiple scales (undergraduate, graduate, pass/fail). Grade scale entries live in lms.grading_scale_entries.';


--
-- Name: group_sets; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.group_sets (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    formation_strategy lms.group_formation_strategy NOT NULL,
    max_members_per_group integer
);


ALTER TABLE lms.group_sets OWNER TO postgres;

--
-- Name: TABLE group_sets; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.group_sets IS 'A named collection of student groups within a section (e.g., "Project Teams", "Lab Partners"). formation_strategy ENUM: manual, random, self_select. max_members_per_group caps group size.';


--
-- Name: item_statistics; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.item_statistics (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    question_id uuid NOT NULL,
    question_version_id uuid NOT NULL,
    assessment_id uuid NOT NULL,
    attempt_count integer DEFAULT 0 NOT NULL,
    p_value numeric(5,4),
    discrimination_index numeric(5,4),
    point_biserial numeric(5,4),
    avg_time_seconds numeric(8,2),
    stddev_time_seconds numeric(8,2),
    flag_rate_pct numeric(5,2),
    answer_change_rate_pct numeric(5,2),
    distractor_analysis jsonb,
    computed_difficulty lms.difficulty_level,
    needs_review boolean DEFAULT false NOT NULL,
    needs_review_reason text,
    computed_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT item_statistics_discrimination_range CHECK (((discrimination_index IS NULL) OR ((discrimination_index >= ('-1'::integer)::numeric) AND (discrimination_index <= (1)::numeric)))),
    CONSTRAINT item_statistics_p_value_range CHECK (((p_value IS NULL) OR ((p_value >= (0)::numeric) AND (p_value <= (1)::numeric))))
);


ALTER TABLE lms.item_statistics OWNER TO postgres;

--
-- Name: TABLE item_statistics; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.item_statistics IS 'Psychometric item analysis per question per assessment. p_value (difficulty): > 0.85 = too easy, < 0.25 = too hard, 0.45–0.70 = ideal. discrimination_index: < 0.20 = poor item (does not differentiate), < 0 = problematic (high scorers getting wrong; low scorers right). distractor_analysis JSONB shows which wrong answers students are choosing — the most powerful tool for improving MCQ quality. needs_review = true surfaces items to the question bank owner for revision. These statistics feed back to questions.p_value and questions.discrimination_index for bank-wide filtering.';


--
-- Name: learning_packages; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.learning_packages (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    uploader_id uuid NOT NULL,
    title character varying(255) NOT NULL,
    standard lms.learning_object_standard NOT NULL,
    storage_prefix character varying(1024) NOT NULL,
    entry_point_url character varying(1024) NOT NULL,
    version integer NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.learning_packages OWNER TO postgres;

--
-- Name: TABLE learning_packages; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.learning_packages IS 'A SCORM 1.2, SCORM 2004, or xAPI (Tin Can) content package. storage_prefix is the object storage path root. entry_point_url is the relative URL of the package''s launch file. standard ENUM: scorm_1_2, scorm_2004, xapi.';


--
-- Name: learning_standards; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.learning_standards (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    code character varying(50) NOT NULL,
    description text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.learning_standards OWNER TO postgres;

--
-- Name: TABLE learning_standards; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.learning_standards IS 'Tenant-defined or imported learning standards (Common Core, NGSS, state standards). code is the official standard identifier. The unique constraint scopes codes to a tenant.';


--
-- Name: lti_deployments; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_deployments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    tool_id uuid NOT NULL,
    deployment_id character varying(255) NOT NULL,
    enable_names_and_roles boolean DEFAULT false NOT NULL,
    enable_assignments_and_grades boolean DEFAULT false NOT NULL,
    enable_deep_linking boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.lti_deployments OWNER TO postgres;

--
-- Name: TABLE lti_deployments; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_deployments IS 'A tenant-specific deployment of an LTI registered tool. deployment_id is the platform-issued deployment identifier included in LTI launch messages. Service flags (enable_deep_linking, enable_names_and_roles, enable_assignments_and_grades) control which LTI Advantage services are active for this deployment.';


--
-- Name: lti_launches; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_launches (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    tool_id uuid NOT NULL,
    user_id uuid,
    section_id uuid,
    launch_type character varying(30) DEFAULT 'resource_link'::character varying NOT NULL,
    resource_link_id character varying(255),
    resource_link_title character varying(255),
    launch_succeeded boolean DEFAULT true NOT NULL,
    failure_reason text,
    nonce character varying(100) NOT NULL,
    data_sent jsonb,
    launched_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.lti_launches OWNER TO postgres;

--
-- Name: TABLE lti_launches; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_launches IS 'Audit log of every LTI tool launch. data_sent records what PII was transmitted to the external tool — required for FERPA audit responses when a student requests to know what data was shared. nonce is single-use: the Rust launch handler deletes it immediately after verifying the launch to prevent replay attacks.';


--
-- Name: lti_registered_tools; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_registered_tools (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    client_id character varying(255) NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    oidc_initiation_url character varying(1024) NOT NULL,
    target_link_uri character varying(1024) NOT NULL,
    jwks_uri character varying(1024) NOT NULL,
    version lms.lti_version DEFAULT '1.3.0'::lms.lti_version NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.lti_registered_tools OWNER TO postgres;

--
-- Name: TABLE lti_registered_tools; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_registered_tools IS 'Platform-level LTI 1.3 tool registrations (not tenant-scoped). Stores the tool''s OIDC initiation URL, JWKS URI, target link URI, client_id (issued by the platform), and supported LTI version. Used by the LTI launch service to verify JWT signatures.';


--
-- Name: lti_resource_links; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_resource_links (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    deployment_id uuid NOT NULL,
    section_id uuid NOT NULL,
    module_id uuid,
    title character varying(255) NOT NULL,
    description text,
    presentation lms.lti_presentation_target DEFAULT 'iframe'::lms.lti_presentation_target NOT NULL,
    custom_parameters jsonb,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.lti_resource_links OWNER TO postgres;

--
-- Name: TABLE lti_resource_links; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_resource_links IS 'A specific placement of an LTI tool within a course module or section. Carries custom_parameters passed to the tool at launch and a presentation target (iframe, window, embed). One resource link may be referenced by multiple assignments.';


--
-- Name: lti_score_passbacks; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_score_passbacks (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    grade_id uuid NOT NULL,
    line_item_url character varying(1024) NOT NULL,
    score_given numeric NOT NULL,
    score_maximum numeric NOT NULL,
    direction character varying(10) DEFAULT 'outbound'::character varying NOT NULL,
    status lms.lti_passback_status DEFAULT 'pending'::lms.lti_passback_status NOT NULL,
    http_status_code smallint,
    response_body text,
    attempted_at timestamp with time zone DEFAULT now() NOT NULL,
    confirmed_at timestamp with time zone,
    CONSTRAINT lti_score_passbacks_direction_values CHECK (((direction)::text = ANY ((ARRAY['outbound'::character varying, 'inbound'::character varying])::text[]))),
    CONSTRAINT lti_score_passbacks_score_maximum_positive CHECK ((score_maximum > (0)::numeric)),
    CONSTRAINT lti_score_passbacks_score_range CHECK (((score_given >= (0)::numeric) AND (score_given <= score_maximum)))
);


ALTER TABLE lms.lti_score_passbacks OWNER TO postgres;

--
-- Name: TABLE lti_score_passbacks; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_score_passbacks IS 'Log of every LTI AGS score exchange — both scores sent to external tools (outbound) and scores written back by tools (inbound). score_given and score_maximum follow the LTI AGS normalized scoring spec. Used for debugging integration issues and reconciling grade discrepancies.';


--
-- Name: lti_tools; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.lti_tools (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    tool_name character varying(100) NOT NULL,
    tool_description text,
    oidc_initiation_url text NOT NULL,
    jwks_url text NOT NULL,
    deep_link_url text,
    target_link_uri text NOT NULL,
    platform_client_id character varying(255) NOT NULL,
    platform_deployment_id character varying(255) NOT NULL,
    platform_oidc_auth_url text DEFAULT 'https://auth.edusuite.io/lti/auth'::text NOT NULL,
    platform_jwks_url text DEFAULT 'https://auth.edusuite.io/.well-known/jwks'::text NOT NULL,
    platform_access_token_url text DEFAULT 'https://auth.edusuite.io/lti/token'::text NOT NULL,
    supports_deep_linking boolean DEFAULT false NOT NULL,
    supports_grades_passback boolean DEFAULT false NOT NULL,
    supports_names_roles boolean DEFAULT false NOT NULL,
    custom_params jsonb,
    placements text[] DEFAULT '{}'::text[] NOT NULL,
    privacy_level character varying(20) DEFAULT 'anonymous'::character varying NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.lti_tools OWNER TO postgres;

--
-- Name: TABLE lti_tools; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.lti_tools IS 'LTI 1.3 tool registrations. Implements the IMS Global LTI 1.3 platform role. eduSuite is the Platform (formerly Tool Consumer); external tools are the Tools (formerly Tool Providers). platform_client_id is unique per tool per tenant — it is the OAuth 2.0 client_id that the tool uses to authenticate with eduSuite''s OIDC endpoint. privacy_level controls what student PII is included in the LTI launch JWT (name, email, or nothing) — critical for FERPA compliance.';


--
-- Name: messages; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.messages (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    conversation_id uuid NOT NULL,
    sender_user_id uuid NOT NULL,
    message_text text NOT NULL,
    sent_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.messages OWNER TO postgres;

--
-- Name: TABLE messages; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.messages IS 'An individual message within a conversation. Append-only; messages are not editable after sending per academic integrity requirements.';


--
-- Name: originality_reports; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.originality_reports (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    submission_id uuid NOT NULL,
    provider character varying(100) NOT NULL,
    similarity_score numeric(5,2) NOT NULL,
    status lms.plagiarism_status DEFAULT 'pending'::lms.plagiarism_status NOT NULL,
    report_url character varying(1024) NOT NULL,
    checked_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.originality_reports OWNER TO postgres;

--
-- Name: TABLE originality_reports; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.originality_reports IS 'Academic integrity originality check results from an external provider (e.g., Turnitin). similarity_score is the percentage match to known sources. report_url links to the full provider report. Append-only once checked_at is set.';


--
-- Name: question_bank_members; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.question_bank_members (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    bank_id uuid NOT NULL,
    user_id uuid NOT NULL,
    permission lms.bank_permission DEFAULT 'use'::lms.bank_permission NOT NULL,
    granted_by_user_id uuid,
    granted_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE lms.question_bank_members OWNER TO postgres;

--
-- Name: TABLE question_bank_members; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.question_bank_members IS 'Access control for question banks. Permissions are additive within the bank — admin can do everything, view can only browse. The Rust service checks this table before any bank operation. Department admins are typically granted admin permission; adjunct instructors are typically granted use or contribute.';


--
-- Name: question_banks; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.question_banks (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(200) NOT NULL,
    description text,
    owner_user_id uuid,
    owner_department_id uuid,
    default_visibility character varying(20) DEFAULT 'members_only'::character varying NOT NULL,
    subject_area character varying(100),
    course_level character varying(50),
    total_questions integer DEFAULT 0 NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT question_banks_has_owner CHECK (((owner_user_id IS NOT NULL) OR (owner_department_id IS NOT NULL)))
);


ALTER TABLE lms.question_banks OWNER TO postgres;

--
-- Name: TABLE question_banks; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.question_banks IS 'Tenant-scoped collaborative question banks. Instructors across the institution share banks via membership (question_bank_members). total_questions is maintained by trigger for fast display. A bank can be owned by an individual or a department — department-owned banks are the normal case for collaborative exam writing.';


--
-- Name: question_standards; Type: TABLE; Schema: lms; Owner: postgres
--

