--
-- Name: TABLE question_versions; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.question_versions IS 'Versioned content of each question. Editing a question closes the current version (is_current = false, effective_end_date = today) and inserts a new current version. attempt_responses.question_version_id references the exact version the student saw — item analysis can distinguish pre- vs post-edit performance.';


--
-- Name: questions; Type: TABLE; Schema: lms; Owner: postgres
--

CREATE TABLE lms.questions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
