    difficulty lms.difficulty_level DEFAULT 'medium'::lms.difficulty_level,
    difficulty_is_computed boolean DEFAULT false NOT NULL,
    estimated_seconds smallint,
    current_version_id uuid,
    times_used integer DEFAULT 0 NOT NULL,
    times_answered integer DEFAULT 0 NOT NULL,
    p_value numeric(5,4),
    discrimination_index numeric(5,4),
    created_by_user_id uuid NOT NULL,
    last_edited_by_user_id uuid,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT questions_default_points_positive CHECK ((default_points > (0)::numeric)),
    CONSTRAINT questions_discrimination_range CHECK (((discrimination_index IS NULL) OR ((discrimination_index >= ('-1'::integer)::numeric) AND (discrimination_index <= (1)::numeric)))),
    CONSTRAINT questions_p_value_range CHECK (((p_value IS NULL) OR ((p_value >= (0)::numeric) AND (p_value <= (1)::numeric))))
);


ALTER TABLE lms.questions OWNER TO postgres;

--
-- Name: TABLE questions; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON TABLE lms.questions IS 'Question master records. Content lives in question_versions for SCD2 versioning. current_version_id points to the live version — attempt_responses reference the version that was live at attempt-start, ensuring historical accuracy. p_value and discrimination_index are computed by the item analysis service after each grading run and stored here for fast question bank filtering.';


