--
-- Name: COLUMN student_accommodations.applies_to_assessment_types; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON COLUMN lms.student_accommodations.applies_to_assessment_types IS 'Which assignment types this accommodation applies to. NULL = all types. Set to {exam, quiz} for time accommodations that only apply to timed assessments, not homework or essays.';


--
