--
-- Name: vw_accommodation_compliance; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_accommodation_compliance AS
 SELECT aa.tenant_id,
    aa.student_id,
    u.first_name,
    u.last_name,
    a.title AS assessment_title,
    aa.attempt_number,
    aa.started_at,
    sa.time_multiplier AS approved_time_multiplier,
    sa.extended_time_minutes AS approved_extra_minutes,
    sa.allows_scheduled_breaks AS approved_breaks,
    sa.accommodation_source,
    aa.accommodation_time_multiplier AS applied_time_multiplier,
    aa.accommodation_extra_minutes AS applied_extra_minutes,
    aa.accommodation_breaks_allowed AS applied_breaks,
    aa.effective_time_limit_minutes,
    (COALESCE(aa.accommodation_time_multiplier, (1)::numeric) >= COALESCE(sa.time_multiplier, (1)::numeric)) AS time_accommodation_applied,
    aa.accommodation_notes
   FROM (((lms.assessment_attempts aa
     JOIN lms.assessments a ON ((a.id = aa.assessment_id)))
     JOIN core.users u ON ((u.id = aa.student_id)))
     LEFT JOIN lms.student_accommodations sa ON (((sa.student_id = aa.student_id) AND (sa.tenant_id = aa.tenant_id) AND ((sa.applies_to_assessment_types IS NULL) OR ('exam'::lms.assignment_type = ANY (sa.applies_to_assessment_types)) OR ('quiz'::lms.assignment_type = ANY (sa.applies_to_assessment_types))))));


ALTER VIEW lms.vw_accommodation_compliance OWNER TO postgres;

--
-- Name: VIEW vw_accommodation_compliance; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_accommodation_compliance IS 'IEP/504 accommodation compliance audit view. Compares what was approved in student_accommodations with what was actually applied in the attempt snapshot. time_accommodation_applied = false indicates an accommodation may not have been correctly applied — surfaces to the DSP coordinator for review. Used for OCR compliance reporting and parent/guardian requests for accommodation verification.';


--
-- Name: vw_assessment_dashboard; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_assessment_dashboard AS
 SELECT a.tenant_id,
    a.id AS assessment_id,
    a.title,
    a.status,
    a.available_from,
    a.available_until,
    a.time_limit_minutes,
    a.max_attempts,
    a.total_points,
    a.passing_score_pct,
    count(aa.id) AS total_attempts,
    count(aa.id) FILTER (WHERE (aa.status = 'in_progress'::lms.attempt_status)) AS attempts_in_progress,
    count(aa.id) FILTER (WHERE (aa.status = 'submitted'::lms.attempt_status)) AS attempts_awaiting_grading,
    count(aa.id) FILTER (WHERE (aa.status = 'graded'::lms.attempt_status)) AS attempts_graded,
    count(aa.id) FILTER (WHERE (aa.is_flagged = true)) AS flagged_attempts,
    round(avg(aa.score_pct), 2) AS mean_score_pct,
    round(min(aa.score_pct), 2) AS min_score_pct,
    round(max(aa.score_pct), 2) AS max_score_pct,
    count(DISTINCT aa.student_id) AS students_attempted,
    ( SELECT snap.computed_at
           FROM lms.assessment_analytics_snapshots snap
          WHERE (snap.assessment_id = a.id)
          ORDER BY snap.computed_at DESC
         LIMIT 1) AS last_analytics_computed_at
   FROM (lms.assessments a
     LEFT JOIN lms.assessment_attempts aa ON ((aa.assessment_id = a.id)))
  GROUP BY a.tenant_id, a.id, a.title, a.status, a.available_from, a.available_until, a.time_limit_minutes, a.max_attempts, a.total_points, a.passing_score_pct;


ALTER VIEW lms.vw_assessment_dashboard OWNER TO postgres;

--
-- Name: VIEW vw_assessment_dashboard; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_assessment_dashboard IS 'Live instructor assessment dashboard. Counts are computed from assessment_attempts in real time for accuracy; the heavier score distribution statistics come from assessment_analytics_snapshots. Instructors see attempt counts, flagged submissions, and score range at a glance without opening each attempt individually.';


--
-- Name: course_sections; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.course_sections (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    course_id uuid NOT NULL,
    term_id uuid NOT NULL,
    instructor_id uuid NOT NULL,
    section_number character varying(10) NOT NULL,
    max_capacity integer DEFAULT 24 NOT NULL,
    waitlist_capacity integer DEFAULT 10 NOT NULL,
    is_published boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    instructional_format sis.instructional_format DEFAULT 'in_person'::sis.instructional_format NOT NULL,
    instruction_language character varying(10) DEFAULT 'en'::character varying NOT NULL,
    max_enrollment integer DEFAULT 30 NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    effective_start_date date DEFAULT CURRENT_DATE NOT NULL,
    effective_end_date date,
    is_current boolean DEFAULT true NOT NULL,
    superseded_at timestamp with time zone,
    superseded_by_id uuid,
    change_reason text,
    CONSTRAINT course_sections_current_consistency CHECK ((((is_current = true) AND (effective_end_date IS NULL)) OR ((is_current = false) AND (effective_end_date IS NOT NULL)))),
    CONSTRAINT course_sections_dates_valid CHECK (((effective_end_date IS NULL) OR (effective_end_date > effective_start_date)))
);


ALTER TABLE sis.course_sections OWNER TO postgres;

--
-- Name: TABLE course_sections; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.course_sections IS 'A specific offering of a course in a term, taught by an instructor in a specific instructional format. Tracks enrollment counts against max_enrollment and waitlist_capacity. is_published controls student-facing registration visibility. Linked to a collab workspace and an LMS section automatically on creation.';


--
-- Name: COLUMN course_sections.effective_start_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.course_sections.effective_start_date IS 'When this version of the section record became active. For accreditation audits: use the version with effective_start_date <= $term_end_date AND (effective_end_date IS NULL OR effective_end_date > $term_start_date) to find who taught the section during the instructional period.';


--
-- Name: vw_gradebook; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_gradebook AS
 SELECT sgs.tenant_id,
    sgs.section_id,
    sgs.student_id,
    u.first_name,
    u.last_name,
    a.id AS assignment_id,
    a.title AS assignment_title,
    a.max_score,
    ag.name AS group_name,
    ag.weight AS group_weight,
    sub.id AS submission_id,
    sub.status AS submission_status,
    sub.submitted_at,
    g.score,
    g.updated_at AS graded_at,
        CASE
            WHEN (a.max_score > (0)::numeric) THEN round(((g.score / a.max_score) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS assignment_percentage,
    g.feedback_text
   FROM ((((((lms.section_grade_summaries sgs
     JOIN core.users u ON ((u.id = sgs.student_id)))
     JOIN sis.course_sections cs ON ((cs.id = sgs.section_id)))
     JOIN lms.assignments a ON ((a.section_id = sgs.section_id)))
     LEFT JOIN lms.assignment_groups ag ON ((ag.id = a.group_id)))
     LEFT JOIN lms.submissions sub ON (((sub.assignment_id = a.id) AND (sub.student_id = sgs.student_id))))
     LEFT JOIN lms.grades g ON ((g.submission_id = sub.id)));


ALTER VIEW lms.vw_gradebook OWNER TO postgres;

--
-- Name: VIEW vw_gradebook; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_gradebook IS 'Instructor gradebook view. One row per (student, assignment) in a section. Shows submission status, raw score, percentage, and group weighting. Drives the gradebook spreadsheet UI. RLS enforced through base tables.';


--
-- Name: vw_lti_tool_usage; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_lti_tool_usage AS
 SELECT lt.tenant_id,
    lt.tool_name,
    lt.privacy_level,
    lt.supports_grades_passback,
    count(ll.id) AS total_launches,
    count(ll.id) FILTER (WHERE (ll.launched_at > (now() - '30 days'::interval))) AS launches_last_30_days,
    count(DISTINCT ll.user_id) AS unique_users,
    count(ll.id) FILTER (WHERE (NOT ll.launch_succeeded)) AS failed_launches,
    max(ll.launched_at) AS last_launched_at
   FROM (lms.lti_tools lt
     LEFT JOIN lms.lti_launches ll ON ((ll.tool_id = lt.id)))
  WHERE (lt.is_active = true)
  GROUP BY lt.tenant_id, lt.id, lt.tool_name, lt.privacy_level, lt.supports_grades_passback;


ALTER VIEW lms.vw_lti_tool_usage OWNER TO postgres;

--
-- Name: VIEW vw_lti_tool_usage; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_lti_tool_usage IS 'LTI tool usage statistics. Drives the admin tool usage dashboard. failed_launches identifies tools with authentication or configuration issues. unique_users shows actual adoption vs registered tools.';


--
-- Name: vw_question_bank_item_analysis; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_question_bank_item_analysis AS
 SELECT q.tenant_id,
    q.bank_id,
    qb.name AS bank_name,
    q.id AS question_id,
    qv.stem_content,
    q.question_type,
    q.blooms_level,
    q.difficulty,
    q.p_value,
    q.discrimination_index,
    q.times_used,
    q.times_answered,
    count(DISTINCT ist.assessment_id) AS assessments_used_in,
    avg(ist.avg_time_seconds) AS avg_time_seconds,
    bool_or(ist.needs_review) AS needs_review,
    string_agg(DISTINCT ist.needs_review_reason, '; '::text) AS review_reasons
   FROM (((lms.questions q
     JOIN lms.question_banks qb ON ((qb.id = q.bank_id)))
     LEFT JOIN lms.question_versions qv ON ((qv.id = q.current_version_id)))
     LEFT JOIN lms.item_statistics ist ON ((ist.question_id = q.id)))
  WHERE (q.is_active = true)
  GROUP BY q.tenant_id, q.bank_id, qb.name, q.id, qv.stem_content, q.question_type, q.blooms_level, q.difficulty, q.p_value, q.discrimination_index, q.times_used, q.times_answered;


ALTER VIEW lms.vw_question_bank_item_analysis OWNER TO postgres;

--
-- Name: VIEW vw_question_bank_item_analysis; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_question_bank_item_analysis IS 'Item analysis dashboard for question bank owners and department chairs. Shows every question with its psychometric statistics aggregated across all assessments it has appeared in. needs_review = true surfaces questions that need revision: low discrimination, p_value outliers, or instructor flags. stem_content from the current version shown for identification.';


--
-- Name: vw_student_attempt_history; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_student_attempt_history AS
 SELECT aa.tenant_id,
    aa.student_id,
    a.title AS assessment_title,
    aa.attempt_number,
    aa.status,
    aa.started_at,
    aa.submitted_at,
    aa.time_spent_seconds,
    aa.effective_time_limit_minutes,
    aa.raw_score,
    aa.adjusted_score,
    aa.score_pct,
    aa.is_passing,
        CASE a.attempt_score_policy
            WHEN 'highest'::lms.attempt_score_policy THEN (aa.adjusted_score = max(aa2.adjusted_score) OVER (PARTITION BY aa.assessment_id, aa.student_id))
            WHEN 'latest'::lms.attempt_score_policy THEN (aa.attempt_number = max(aa2.attempt_number) OVER (PARTITION BY aa.assessment_id, aa.student_id))
            WHEN 'first'::lms.attempt_score_policy THEN (aa.attempt_number = 1)
            ELSE false
        END AS is_counting_attempt,
    aa.is_flagged,
    aa.accommodation_time_multiplier,
    aa.accommodation_extra_minutes,
    aa.accommodation_distraction_free
   FROM ((lms.assessment_attempts aa
     JOIN lms.assessments a ON ((a.id = aa.assessment_id)))
     JOIN lms.assessment_attempts aa2 ON (((aa2.assessment_id = aa.assessment_id) AND (aa2.student_id = aa.student_id))));


ALTER VIEW lms.vw_student_attempt_history OWNER TO postgres;

--
-- Name: VIEW vw_student_attempt_history; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_student_attempt_history IS 'Complete attempt history per student per assessment. is_counting_attempt identifies which attempt determines the final grade based on the assessment''s attempt_score_policy. Students see their attempt timeline; instructors see the same view for any student to verify accommodations were applied correctly.';


--
-- Name: vw_student_grades; Type: VIEW; Schema: lms; Owner: postgres
--

CREATE VIEW lms.vw_student_grades AS
 SELECT tenant_id,
    student_id,
    section_id,
    enrollment_id,
    current_percentage,
    current_letter_grade,
    current_quality_points,
    graded_assignment_count,
    total_assignment_count,
    points_earned,
    points_possible,
    is_incomplete,
    last_calculated_at
   FROM lms.section_grade_summaries sgs;


ALTER VIEW lms.vw_student_grades OWNER TO postgres;

--
-- Name: VIEW vw_student_grades; Type: COMMENT; Schema: lms; Owner: postgres
--

COMMENT ON VIEW lms.vw_student_grades IS 'Student-facing current grade summary per enrolled section. Returns the pre-computed running grade from section_grade_summaries. RLS on the underlying table restricts rows to the current tenant.';


