CREATE TABLE policy.versions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    document_id uuid NOT NULL,
    workflow_submission_id uuid,
    version_number character varying(50) NOT NULL,
    status policy.version_status DEFAULT 'draft'::policy.version_status NOT NULL,
    markdown_content text NOT NULL,
    effective_date date NOT NULL,
    sunset_date date,
    approved_by_id uuid,
    approved_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    fts_doc tsvector GENERATED ALWAYS AS (setweight(to_tsvector('english'::regconfig, COALESCE(markdown_content, ''::text)), 'A'::"char")) STORED
);


