-- Name: TABLE versions; Type: COMMENT; Schema: policy; Owner: postgres
--

COMMENT ON TABLE policy.versions IS 'A versioned draft of a policy document. Content is stored as markdown_content. version_number increments monotonically per document. workflow_submission_id links to the approval workflow routing the version for review and signature. effective_date is set at approval time.';


--
-- Name: vw_active_public_manuals; Type: VIEW; Schema: policy; Owner: postgres
--

CREATE VIEW policy.vw_active_public_manuals AS
 SELECT m.tenant_id,
    m.id AS manual_id,
    m.name AS manual_name,
    c.id AS category_id,
    c.title AS category_title,
    c.slug AS category_slug,
    d.id AS document_id,
    d.policy_number,
    d.title AS policy_title,
    v.version_number,
    v.markdown_content,
    v.effective_date
   FROM (((policy.manuals m
     JOIN policy.categories c ON ((c.manual_id = m.id)))
     JOIN policy.documents d ON ((d.category_id = c.id)))
     JOIN policy.versions v ON (((v.document_id = d.id) AND (v.status = 'active'::policy.version_status) AND (v.effective_date <= CURRENT_DATE) AND ((v.sunset_date IS NULL) OR (v.sunset_date > CURRENT_DATE)))))
  WHERE (m.is_public = true);


ALTER VIEW policy.vw_active_public_manuals OWNER TO postgres;

--
-- Name: VIEW vw_active_public_manuals; Type: COMMENT; Schema: policy; Owner: postgres
--

COMMENT ON VIEW policy.vw_active_public_manuals IS 'Public-safe view returning active, published policy content. Joins manuals, categories, documents, and the current published version for each document. Filtered to is_public = true manuals and published version status. Consumed by the CMS and the public policy portal.';


