-- Name: TABLE ncaa_sports; Type: COMMENT; Schema: reference; Owner: postgres
--

COMMENT ON TABLE reference.ncaa_sports IS 'NCAA-recognized sports with gender and championship status. Referenced by sis.athletic_teams for IPEDS athletics reporting and NCAA compliance tracking.';


--
-- Name: postal_codes; Type: TABLE; Schema: reference; Owner: postgres
--

CREATE TABLE reference.postal_codes (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    country_iso_alpha2 character(2) NOT NULL,
    postal_code character varying(20) NOT NULL,
    primary_city character varying(100) NOT NULL,
    subdivision_code character varying(10),
    latitude numeric(10,7),
    longitude numeric(10,7),
    last_api_sync_date timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE reference.postal_codes OWNER TO postgres;

--
-- Name: TABLE postal_codes; Type: COMMENT; Schema: reference; Owner: postgres
--

COMMENT ON TABLE reference.postal_codes IS 'USPS and international postal code data with latitude/longitude centroids and primary city names. latitude/longitude enable distance calculations and geolocation defaulting in address capture. last_api_sync_date tracks when the record was last refreshed from the postal service API.';


--
-- Name: standardized_tests; Type: TABLE; Schema: reference; Owner: postgres
--

CREATE TABLE reference.standardized_tests (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    agency_id uuid,
    test_family character varying(50) NOT NULL,
    test_name character varying(255) NOT NULL,
