    score_max numeric(6,2),
    is_active boolean DEFAULT true NOT NULL
);


ALTER TABLE reference.standardized_tests OWNER TO postgres;

--
-- Name: TABLE standardized_tests; Type: COMMENT; Schema: reference; Owner: postgres
--

COMMENT ON TABLE reference.standardized_tests IS 'Registry of standardized assessments (SAT, ACT, AP, TOEFL, GRE, etc.) with score range metadata. agency_id links to the testing organization in reference.accreditors. test_family groups variants (e.g., "SAT" encompasses "SAT Evidence-Based Reading and Writing" and "SAT Math").';


--
-- Name: subdivisions; Type: TABLE; Schema: reference; Owner: postgres
--

CREATE TABLE reference.subdivisions (
