);


ALTER TABLE reference.subdivisions OWNER TO postgres;

--
-- Name: TABLE subdivisions; Type: COMMENT; Schema: reference; Owner: postgres
--

COMMENT ON TABLE reference.subdivisions IS 'ISO 3166-2 state, province, and territory codes within countries. Used to validate and standardize core.user_addresses.subdivision_code. category distinguishes state, province, territory, region, etc.';


--
-- Name: timezones; Type: TABLE; Schema: reference; Owner: postgres
--

CREATE TABLE reference.timezones (
    tz_identifier character varying(100) NOT NULL,
    utc_offset_string character varying(10) NOT NULL,
    is_active boolean DEFAULT true NOT NULL
);


ALTER TABLE reference.timezones OWNER TO postgres;

--
-- Name: TABLE timezones; Type: COMMENT; Schema: reference; Owner: postgres
--

COMMENT ON TABLE reference.timezones IS 'IANA timezone identifiers with human-readable UTC offset strings. Used to resolve display times for users in core.user_addresses and to schedule comms.journey_steps at local times.';


--
-- Name: academic_standing_policies; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.academic_standing_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(150) NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    academic_program_id uuid,
    warning_cumulative_gpa numeric(4,3) DEFAULT 1.80 NOT NULL,
    probation_cumulative_gpa numeric(4,3) DEFAULT 2.00 NOT NULL,
    suspension_term_gpa numeric(4,3) DEFAULT 2.00 NOT NULL,
    min_credits_for_evaluation numeric(5,2) DEFAULT 12.0 NOT NULL,
    terms_on_probation_before_suspension smallint DEFAULT 2 CONSTRAINT academic_standing_policies_terms_on_probation_before_s_not_null NOT NULL,
    suspension_terms_before_dismissal smallint DEFAULT 1 CONSTRAINT academic_standing_policies_suspension_terms_before_dis_not_null NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT academic_standing_policies_gpa_ordering CHECK ((warning_cumulative_gpa <= probation_cumulative_gpa)),
    CONSTRAINT academic_standing_policies_gpas_in_range CHECK (((warning_cumulative_gpa >= (0)::numeric) AND (probation_cumulative_gpa <= 4.0) AND (suspension_term_gpa >= (0)::numeric) AND (suspension_term_gpa <= 4.0))),
    CONSTRAINT academic_standing_policies_probation_terms_positive CHECK ((terms_on_probation_before_suspension > 0)),
    CONSTRAINT academic_standing_policies_suspension_terms_positive CHECK ((suspension_terms_before_dismissal > 0))
);


ALTER TABLE sis.academic_standing_policies OWNER TO postgres;

--
-- Name: TABLE academic_standing_policies; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.academic_standing_policies IS 'GPA threshold configuration for academic standing determinations. warning_cumulative_gpa <= probation_cumulative_gpa is enforced by constraint — a student cannot go straight to probation without passing through warning. Resolution: program-specific policy overrides tenant default (is_default).';


--
-- Name: advising_appointments; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.advising_appointments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    advisor_id uuid NOT NULL,
    student_id uuid NOT NULL,
    scheduled_time timestamp with time zone NOT NULL,
    duration_minutes integer DEFAULT 30 NOT NULL,
    status sis.advising_status DEFAULT 'scheduled'::sis.advising_status NOT NULL,
    shared_notes text,
    internal_private_notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.advising_appointments OWNER TO postgres;

--
-- Name: TABLE advising_appointments; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.advising_appointments IS 'A scheduled academic advising session between a student and advisor. Status: scheduled, completed, no_show, cancelled. internal_private_notes are advisor-only; shared_notes are visible to the student. duration_minutes drives calendar blocking.';


--
-- Name: articulation_rules; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.articulation_rules (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_course_id uuid NOT NULL,
    internal_course_id uuid NOT NULL,
    status sis.articulation_status NOT NULL,
    effective_start_date date,
    test_id uuid,
    required_score numeric(6,2),
    min_grade_symbol character varying(30),
    min_grade_scale_id uuid,
    CONSTRAINT articulation_rules_min_grade_needs_scale CHECK (((min_grade_symbol IS NULL) OR (min_grade_scale_id IS NOT NULL)))
);


ALTER TABLE sis.articulation_rules OWNER TO postgres;

--
-- Name: TABLE articulation_rules; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.articulation_rules IS 'Pre-approved equivalency rules mapping external courses to internal courses, optionally with a minimum required_score from a standardized test. Speeds transfer evaluation by automating known equivalencies. The unique constraint prevents conflicting rules for the same external→internal pair.';


--
-- Name: COLUMN articulation_rules.min_grade_symbol; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.articulation_rules.min_grade_symbol IS 'Minimum external grade symbol required for this articulation to apply. NULL = any accepted grade satisfies the rule. e.g. "C" means the student must have earned at least a C at the sending institution for this equivalency to be granted.';


--
-- Name: COLUMN articulation_rules.min_grade_scale_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.articulation_rules.min_grade_scale_id IS 'The external grading scale that min_grade_symbol belongs to. Required when min_grade_symbol is set.';


--
-- Name: athlete_term_records; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.athlete_term_records (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    user_id uuid NOT NULL,
    term_id uuid NOT NULL,
    team_id uuid NOT NULL,
    roster_status sis.roster_status DEFAULT 'active_roster'::sis.roster_status NOT NULL,
    did_compete boolean DEFAULT false NOT NULL,
    waiver_granted boolean DEFAULT false NOT NULL,
    waiver_document_id uuid
);


ALTER TABLE sis.athlete_term_records OWNER TO postgres;

--
-- Name: TABLE athlete_term_records; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.athlete_term_records IS 'Term-by-term NCAA eligibility and roster status for a student athlete. did_compete records whether the athlete competed in this term (consuming a season of eligibility). roster_status: active, redshirt, medical_hardship, transfer. waiver_document_id links to any NCAA waiver documentation in the DMS.';


--
-- Name: athletic_teams; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.athletic_teams (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    sport_id uuid NOT NULL,
    division sis.ncaa_division NOT NULL,
    head_coach_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.athletic_teams OWNER TO postgres;

--
-- Name: TABLE athletic_teams; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.athletic_teams IS 'An athletic team within a tenant. sport_id references reference.ncaa_sports. division maps to the NCAA division the team competes in. head_coach_id links to the staff member.';


--
-- Name: attendance_records; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.attendance_records (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    section_id uuid NOT NULL,
    student_id uuid NOT NULL,
