    recorded_by_id uuid NOT NULL,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.attendance_records OWNER TO postgres;

--
-- Name: awarded_credential_majors; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.awarded_credential_majors (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    credential_id uuid NOT NULL,
    program_id uuid NOT NULL,
    cip_code_snapshot character varying(20) NOT NULL,
    major_title character varying(255) NOT NULL,
    is_primary_major boolean DEFAULT true NOT NULL,
    display_order smallint DEFAULT 1 NOT NULL
);


ALTER TABLE sis.awarded_credential_majors OWNER TO postgres;

--
-- Name: TABLE awarded_credential_majors; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.awarded_credential_majors IS 'Per-major breakdown of an awarded credential for NSC DegreeVerify multi-major reporting. One row per major when a student completes more than one major under a single credential. Single-major credentials have exactly one row here with is_primary_major = true. CIP code and major title are snapshotted at conferral time.';


--
-- Name: awarded_credentials; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.awarded_credentials (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    program_id uuid NOT NULL,
    conferral_date date NOT NULL,
    honors_designation character varying(100),
    diploma_dispatched_at date,
    digital_badge_url character varying(1024),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    nsc_degree_designation sis.nsc_degree_designation,
    diploma_title character varying(255),
    nsc_submitted_at timestamp with time zone,
    nsc_submission_id uuid,
    nsc_accepted_at timestamp with time zone,
    nsc_match_status character varying(50),
    ipeds_award_level_snapshot integer,
    cip_code_snapshot character varying(20)
);


ALTER TABLE sis.awarded_credentials OWNER TO postgres;

--
-- Name: TABLE awarded_credentials; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.awarded_credentials IS 'The official record of a conferred academic credential. conferral_date is the official award date. honors_designation captures Latin honors (cum_laude, magna_cum_laude, summa_cum_laude). digital_badge_url links to the Open Badges credential. diploma_dispatched_at records physical diploma mailing. Immutable once the credential is conferred.';


--
-- Name: COLUMN awarded_credentials.nsc_submitted_at; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.awarded_credentials.nsc_submitted_at IS 'When this credential was transmitted to NSC DegreeVerify. NULL = not yet submitted. Used to identify credentials pending submission.';


--
-- Name: COLUMN awarded_credentials.nsc_submission_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.awarded_credentials.nsc_submission_id IS 'FK to sis.nsc_submission_logs — the specific submission batch that included this credential.';


--
-- Name: COLUMN awarded_credentials.nsc_match_status; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.awarded_credentials.nsc_match_status IS 'NSC''s match result for this credential: MATCH, NOMATCH, DUPLICATE, or an error code from NSC''s response file.';


--
-- Name: COLUMN awarded_credentials.ipeds_award_level_snapshot; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.awarded_credentials.ipeds_award_level_snapshot IS 'IPEDS award level code at the time of conferral. Snapshotted because the credential_types table may be updated after conferral.';


--
-- Name: COLUMN awarded_credentials.cip_code_snapshot; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.awarded_credentials.cip_code_snapshot IS 'CIP code at the time of conferral. Snapshotted for the same reason.';


--
-- Name: corequisite_rules; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.corequisite_rules (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    course_id uuid NOT NULL,
    required_concurrent_course_id uuid NOT NULL,
    is_bidirectional boolean DEFAULT false NOT NULL,
    prior_completion_waives boolean DEFAULT true NOT NULL,
    waiver_min_grade_symbol character varying(5),
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT corequisite_rules_no_self_reference CHECK ((course_id <> required_concurrent_course_id))
);


ALTER TABLE sis.corequisite_rules OWNER TO postgres;

--
-- Name: TABLE corequisite_rules; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.corequisite_rules IS 'Courses that must be taken simultaneously. is_bidirectional = true means each course requires the other. prior_completion_waives = true means a prior passing grade in the required concurrent course satisfies the corequisite (most common). Used by the PQ sweep to drop students who drop a corequisite mid-term.';


--
-- Name: course_attributes; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.course_attributes (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(50) NOT NULL,
    abbreviation character varying(10) NOT NULL,
    created_at timestamp with time zone NOT NULL
);


ALTER TABLE sis.course_attributes OWNER TO postgres;

--
-- Name: course_repeat_policies; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.course_repeat_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    academic_program_id uuid,
    name character varying(150) NOT NULL,
    is_default boolean DEFAULT false NOT NULL,
    max_attempts smallint,
    grade_policy sis.repeat_grade_policy DEFAULT 'highest_grade'::sis.repeat_grade_policy NOT NULL,
    forgiveness_level sis.repeat_forgiveness_level DEFAULT 'gpa_only'::sis.repeat_forgiveness_level NOT NULL,
    repeated_credits_count_toward_max boolean DEFAULT false CONSTRAINT course_repeat_policies_repeated_credits_count_toward_m_not_null NOT NULL,
    requires_withdrawal_for_repeat boolean DEFAULT false NOT NULL,
    repeat_if_grade_below character varying(5),
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT course_repeat_policies_max_attempts_positive CHECK (((max_attempts IS NULL) OR (max_attempts > 0)))
);


ALTER TABLE sis.course_repeat_policies OWNER TO postgres;

--
-- Name: TABLE course_repeat_policies; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.course_repeat_policies IS 'Tenant-level and program-level course repeat rules. Controls max attempts, which grade counts (highest/most recent/average), forgiveness level (GPA-only vs full), and repeat eligibility conditions. Resolution: course-level override > program-level > tenant default (is_default).';


--
-- Name: cpos_overrides; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.cpos_overrides (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    enrollment_id uuid NOT NULL,
    overriding_reason sis.cpos_eligibility_reason NOT NULL,
    justification text NOT NULL,
    restores_title_iv boolean DEFAULT true NOT NULL,
    granted_by_user_id uuid NOT NULL,
    workflow_submission_id uuid,
    expires_at timestamp with time zone,
    is_active boolean DEFAULT true NOT NULL,
    granted_at timestamp with time zone DEFAULT now() NOT NULL,
    revoked_at timestamp with time zone,
    revoked_by_user_id uuid,
    revoke_reason text,
    CONSTRAINT cpos_overrides_revoked_needs_reason CHECK (((revoked_at IS NULL) OR (revoke_reason IS NOT NULL)))
);


ALTER TABLE sis.cpos_overrides OWNER TO postgres;

--
-- Name: TABLE cpos_overrides; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.cpos_overrides IS 'Per-enrollment CPOS eligibility override granted by a financial aid officer. restores_title_iv = true causes the CPOS sweep to set sis.enrollments.is_title_iv_eligible = true despite a failing CPOS check. Analogous to sis.prerequisite_overrides — both are checked before any drop action.';


--
-- Name: cpos_program_rules; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.cpos_program_rules (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    program_id uuid NOT NULL,
    max_remedial_credits numeric(6,2) DEFAULT 30 NOT NULL,
    max_repeat_credits_per_course numeric(6,2) DEFAULT 0 NOT NULL,
    allow_one_repeat_of_passed boolean DEFAULT true NOT NULL,
    max_elective_credits numeric(6,2),
    consortium_credits_count boolean DEFAULT true NOT NULL,
    study_abroad_credits_count boolean DEFAULT true NOT NULL,
    max_timeframe_credits_override numeric(7,2),
    effective_from date DEFAULT CURRENT_DATE NOT NULL,
    effective_to date,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT cpos_program_rules_dates_valid CHECK (((effective_to IS NULL) OR (effective_to > effective_from))),
    CONSTRAINT cpos_program_rules_elective_non_negative CHECK (((max_elective_credits IS NULL) OR (max_elective_credits >= (0)::numeric))),
    CONSTRAINT cpos_program_rules_remedial_non_negative CHECK ((max_remedial_credits >= (0)::numeric)),
    CONSTRAINT cpos_program_rules_repeat_non_negative CHECK ((max_repeat_credits_per_course >= (0)::numeric))
);


ALTER TABLE sis.cpos_program_rules OWNER TO postgres;

--
-- Name: TABLE cpos_program_rules; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.cpos_program_rules IS 'Per-program CPOS (Course Program of Study) configuration for Title IV aid. Controls remedial credit caps (federal default: 30 hours), repeat credit rules (34 CFR §668.2), elective caps, and timeframe overrides. Effective dates allow different rules for different catalog year cohorts. The CPOS sweep service resolves the most recent active rule for a student''s declared_term_id to apply the correct catalog-year rules.';


--
-- Name: cpos_sweep_results; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.cpos_sweep_results (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    sweep_run_id uuid NOT NULL,
    enrollment_id uuid NOT NULL,
    student_id uuid NOT NULL,
    section_id uuid NOT NULL,
    student_program_id uuid,
    cpos_rule_id uuid,
    is_title_iv_eligible boolean NOT NULL,
    ineligibility_reason sis.cpos_eligibility_reason,
    active_override_id uuid,
    drop_reason sis.cpos_drop_reason,
    dropped_at timestamp with time zone,
    remedial_credits_counted numeric(6,2),
    repeat_credits_counted numeric(6,2),
    total_attempted_credits numeric(7,2),
    max_timeframe_credits numeric(7,2),
    notification_sent_at timestamp with time zone,
    evaluated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT cpos_sweep_results_dropped_needs_reason CHECK (((dropped_at IS NULL) OR (drop_reason IS NOT NULL))),
    CONSTRAINT cpos_sweep_results_ineligible_needs_reason CHECK (((is_title_iv_eligible = true) OR (ineligibility_reason IS NOT NULL)))
);


ALTER TABLE sis.cpos_sweep_results OWNER TO postgres;

--
-- Name: TABLE cpos_sweep_results; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.cpos_sweep_results IS 'Per-enrollment result of a CPOS sweep. Snapshots the credit totals that drove the determination so the financial aid officer can audit the calculation even after subsequent enrollments change the running totals. active_override_id links to the cpos_override that exempted the student from an ineligibility determination.';


--
-- Name: cpos_sweep_runs; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.cpos_sweep_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    term_id uuid NOT NULL,
    trigger_type sis.sweep_trigger NOT NULL,
    student_id uuid,
    is_dry_run boolean DEFAULT false NOT NULL,
    enrollments_evaluated integer DEFAULT 0 NOT NULL,
    enrollments_eligible integer DEFAULT 0 NOT NULL,
    enrollments_ineligible integer DEFAULT 0 NOT NULL,
    overrides_applied integer DEFAULT 0 NOT NULL,
    enrollments_dropped integer DEFAULT 0 NOT NULL,
    title_iv_flags_updated integer DEFAULT 0 NOT NULL,
    initiated_by_service character varying(100),
    initiated_by_user_id uuid,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    failed_at timestamp with time zone,
    failure_reason text,
    CONSTRAINT cpos_sweep_runs_counts_non_negative CHECK (((enrollments_evaluated >= 0) AND (enrollments_eligible >= 0) AND (enrollments_ineligible >= 0) AND (overrides_applied >= 0) AND (enrollments_dropped >= 0) AND (title_iv_flags_updated >= 0))),
    CONSTRAINT cpos_sweep_runs_not_both_complete_failed CHECK ((NOT ((completed_at IS NOT NULL) AND (failed_at IS NOT NULL))))
);


ALTER TABLE sis.cpos_sweep_runs OWNER TO postgres;

--
-- Name: TABLE cpos_sweep_runs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.cpos_sweep_runs IS 'Audit log of every CPOS sweep execution. title_iv_flags_updated counts enrollments where is_title_iv_eligible changed. is_dry_run = true evaluates CPOS without updating any flags or dropping — used to preview impact before the financial aid disbursement window. Per-enrollment results are in sis.cpos_sweep_results.';


--
-- Name: credential_types; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.credential_types (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying NOT NULL,
    academic_level character varying,
    ipeds_award_level integer,
    requires_state_board_approval boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.credential_types OWNER TO postgres;

--
-- Name: TABLE credential_types; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.credential_types IS 'The types of credentials the institution can award (Associate of Arts, Bachelor of Science, Certificate, etc.). ipeds_award_level maps to the IPEDS award level taxonomy for federal reporting. requires_state_board_approval flags credentials that need external approval before award.';


--
-- Name: disciplinary_incidents; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.disciplinary_incidents (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    reported_by_id uuid NOT NULL,
    incident_date date NOT NULL,
    category character varying(100) NOT NULL,
    severity sis.incident_severity NOT NULL,
    description text NOT NULL,
    action_taken character varying(255),
    is_reported_to_state boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.disciplinary_incidents OWNER TO postgres;

--
-- Name: TABLE disciplinary_incidents; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.disciplinary_incidents IS 'A formal student conduct or disciplinary record. category and severity classify the incident. is_reported_to_state flags incidents with mandatory state reporting requirements. action_taken documents the sanction. FERPA-restricted: accessible only to school officials with legitimate educational interest.';


--
-- Name: enrollments; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.enrollments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    section_id uuid NOT NULL,
    status sis.enrollment_status DEFAULT 'enrolled'::sis.enrollment_status NOT NULL,
    enrolled_at timestamp with time zone DEFAULT now() NOT NULL,
    status_updated_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    is_title_iv_eligible boolean DEFAULT true NOT NULL,
    cpos_reason sis.cpos_eligibility_reason DEFAULT 'eligible_core_requirement'::sis.cpos_eligibility_reason NOT NULL,
    fulfilled_catalog_requirement_id uuid,
    cpos_drop_reason sis.cpos_drop_reason,
    cpos_swept_at timestamp with time zone,
    cpos_sweep_run_id uuid,
    nsc_enrollment_intensity sis.nsc_enrollment_intensity,
    enrollment_effective_date date,
    credit_hours_enrolled numeric(5,2),
    last_reported_to_nsc_at timestamp with time zone,
    last_reported_intensity sis.nsc_enrollment_intensity
);


ALTER TABLE sis.enrollments OWNER TO postgres;

--
-- Name: TABLE enrollments; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.enrollments IS 'A student''s registration in a course section for a term. status: enrolled, withdrawn, dropped, auditing, incomplete, no_show. is_title_iv_eligible flags whether this enrollment counts for federal financial aid disbursement. cpos_reason captures the basis for cross-program of study enrollment when applicable. fulfilled_catalog_requirement_id links to the degree requirement this enrollment satisfies.';


--
-- Name: COLUMN enrollments.is_title_iv_eligible; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.is_title_iv_eligible IS 'Whether this enrollment counts toward the student''s Title IV financial aid credit load. Set by the CPOS sweep service based on cpos_reason and any active cpos_override. Financial aid disbursement reads this flag directly.';


--
-- Name: COLUMN enrollments.cpos_drop_reason; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.cpos_drop_reason IS 'If this enrollment was dropped by a CPOS sweep, the specific reason. NULL when the enrollment was not CPOS-dropped.';


--
-- Name: COLUMN enrollments.cpos_swept_at; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.cpos_swept_at IS 'Timestamp of the most recent CPOS sweep evaluation for this enrollment. NULL means this enrollment has never been evaluated by a CPOS sweep.';


--
-- Name: COLUMN enrollments.nsc_enrollment_intensity; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.nsc_enrollment_intensity IS 'NSC enrollment intensity classification at census date: F=Full-Time, H=Half-Time, L=Less Than Half-Time, N=Not Enrolled, A=Leave of Absence. Computed by the reporting service from credit_hours_enrolled against the applicable thresholds for the term''s academic_calendar type, then stored here so the NSC submission uses a consistent point-in-time value.';


--
-- Name: COLUMN enrollments.enrollment_effective_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.enrollment_effective_date IS 'The date this enrollment status became effective. May differ from enrolled_at or status_updated_at when a registrar backdates a change. Required by NSC enrollment reporting.';


--
-- Name: COLUMN enrollments.credit_hours_enrolled; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.credit_hours_enrolled IS 'Credit hours for this enrollment at census date. Stored separately from the section credit hours because audit students and special registrations may differ. Used to compute nsc_enrollment_intensity.';


--
-- Name: COLUMN enrollments.last_reported_to_nsc_at; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.enrollments.last_reported_to_nsc_at IS 'Timestamp when this enrollment record was last included in an NSC submission. NULL = never reported. Used to identify new and changed records for incremental NSC updates.';


--
-- Name: external_courses; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.external_courses (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    institution_id uuid NOT NULL,
    subject character varying NOT NULL,
    course character varying NOT NULL,
    title character varying NOT NULL,
    start_term_id uuid,
    end_term_id uuid,
    is_active boolean DEFAULT true NOT NULL,
    credits numeric(4,2) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.external_courses OWNER TO postgres;

--
-- Name: TABLE external_courses; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.external_courses IS 'Courses from external institutions used in transfer credit evaluation and articulation rule configuration. Links to the external institution and maps between start_term_id and end_term_id for catalog validity.';


--
-- Name: external_grade_entries; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.external_grade_entries (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    scale_id uuid NOT NULL,
    grade_symbol character varying(30) NOT NULL,
    grade_label character varying(100),
    numeric_lower numeric(6,2),
    numeric_upper numeric(6,2),
    percentage_midpoint numeric(5,2),
    approximate_gpa numeric(4,2),
    is_passing boolean DEFAULT true NOT NULL,
    display_order smallint DEFAULT 0 NOT NULL,
    CONSTRAINT external_grade_entries_gpa_range CHECK (((approximate_gpa IS NULL) OR ((approximate_gpa >= (0)::numeric) AND (approximate_gpa <= 4.0)))),
    CONSTRAINT external_grade_entries_numeric_bounds CHECK (((numeric_lower IS NULL) OR (numeric_upper IS NULL) OR (numeric_upper > numeric_lower))),
    CONSTRAINT external_grade_entries_pct_range CHECK (((percentage_midpoint IS NULL) OR ((percentage_midpoint >= (0)::numeric) AND (percentage_midpoint <= (100)::numeric))))
);


ALTER TABLE sis.external_grade_entries OWNER TO postgres;

--
-- Name: TABLE external_grade_entries; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.external_grade_entries IS 'Individual grade symbols within an external grading scale. grade_symbol is exactly as it appears on the external transcript. percentage_midpoint enables interpolated crosswalk lookups when an exact crosswalk entry does not exist for the received grade. is_passing records whether this grade is considered passing by the sending institution — used independently of our acceptance policy.';


--
-- Name: external_grading_scales; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.external_grading_scales (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(150) NOT NULL,
    country_code character(2),
    description text,
    is_numeric_scale boolean DEFAULT false NOT NULL,
    numeric_max numeric(6,2),
    reference_url character varying(1024),
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT external_grading_scales_numeric_max_positive CHECK (((numeric_max IS NULL) OR (numeric_max > (0)::numeric))),
    CONSTRAINT external_grading_scales_numeric_max_required_if_numeric CHECK (((is_numeric_scale = false) OR (numeric_max IS NOT NULL)))
);


ALTER TABLE sis.external_grading_scales OWNER TO postgres;

--
-- Name: TABLE external_grading_scales; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.external_grading_scales IS 'Named grading scales used by external/sending institutions. One scale may be shared across multiple institutions (e.g. UK Honours). Grade symbols within each scale are in sis.external_grade_entries. Crosswalk mappings to internal grades are in sis.grade_crosswalks.';


--
-- Name: external_institution_scale_assignments; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.external_institution_scale_assignments (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_institution_id uuid CONSTRAINT external_institution_scale_ass_external_institution_id_not_null NOT NULL,
    scale_id uuid NOT NULL,
    degree_level character varying(50),
    is_primary boolean DEFAULT true NOT NULL,
    effective_from date,
    effective_to date,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT external_inst_scale_dates_valid CHECK (((effective_from IS NULL) OR (effective_to IS NULL) OR (effective_to > effective_from)))
);


ALTER TABLE sis.external_institution_scale_assignments OWNER TO postgres;

--
-- Name: TABLE external_institution_scale_assignments; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.external_institution_scale_assignments IS 'Associates a sending institution with its grading scale(s). An institution may use different scales by degree level. Used by the transfer evaluator to auto-select the correct external scale when a transcript is received from a known institution.';


--
-- Name: external_institutions; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.external_institutions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    fice character varying(20),
    city character varying(100),
    state_province character varying(100),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    global_organization_id uuid,
    local_status character varying(50) DEFAULT 'active'::character varying NOT NULL,
    internal_notes text,
    calendar_type sis.academic_calendar DEFAULT 'semester'::sis.academic_calendar NOT NULL,
    is_accredited boolean DEFAULT true NOT NULL
);


ALTER TABLE sis.external_institutions OWNER TO postgres;

--
-- Name: TABLE external_institutions; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.external_institutions IS 'A tenant-specific record of a known external institution (feeder high school, transfer college, testing agency). global_organization_id links to the authoritative reference.external_organizations entry. local_status tracks the institution''s standing with this tenant (active, discontinued, unrecognized).';


--
-- Name: gpa_recalculation_runs; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.gpa_recalculation_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    trigger_type sis.gpa_recalc_trigger NOT NULL,
    student_id uuid,
    term_id uuid,
    students_processed integer DEFAULT 0 NOT NULL,
    students_updated integer DEFAULT 0 NOT NULL,
    initiated_by_service character varying(100),
    initiated_by_user_id uuid,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    failed_at timestamp with time zone,
    failure_reason text,
    CONSTRAINT gpa_recalculation_runs_counts_non_negative CHECK (((students_processed >= 0) AND (students_updated >= 0))),
    CONSTRAINT gpa_recalculation_runs_not_both_complete_and_failed CHECK ((NOT ((completed_at IS NOT NULL) AND (failed_at IS NOT NULL))))
);


ALTER TABLE sis.gpa_recalculation_runs OWNER TO postgres;

--
-- Name: TABLE gpa_recalculation_runs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.gpa_recalculation_runs IS 'Audit log of every GPA recalculation batch or singleton run. Written by the Rust GPA service before processing begins, updated on completion or failure. Supports both full batch (batch_full_recalc) and singleton (grade_posted) modes. students_updated < students_processed is normal — most grade posts do not change the cumulative GPA.';


--
-- Name: grade_crosswalks; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.grade_crosswalks (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_scale_id uuid NOT NULL,
    internal_scale_id uuid NOT NULL,
    external_grade_entry_id uuid NOT NULL,
    internal_grade_entry_id uuid NOT NULL,
    mapping_rationale text,
    authoritative_source character varying(255),
    is_approved boolean DEFAULT false NOT NULL,
    approved_by_user_id uuid,
    approved_at timestamp with time zone,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT grade_crosswalks_approved_has_approver CHECK (((is_approved = false) OR (approved_by_user_id IS NOT NULL))),
    CONSTRAINT grade_crosswalks_approved_has_timestamp CHECK (((is_approved = false) OR (approved_at IS NOT NULL)))
);


ALTER TABLE sis.grade_crosswalks OWNER TO postgres;

--
-- Name: TABLE grade_crosswalks; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.grade_crosswalks IS 'Translation bridge mapping external grade entries to internal grade entries. One row per (external_scale, internal_scale, external_grade) triple. Only approved crosswalk entries are used in automatic translation. Unapproved entries require registrar review before they take effect. The partial index on is_approved = true keeps the lookup path fast.';


--
-- Name: graduation_applications; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.graduation_applications (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    program_id uuid NOT NULL,
    target_term_id uuid NOT NULL,
    status crm.application_status DEFAULT 'draft'::crm.application_status NOT NULL,
    auditor_id uuid NOT NULL,
    audit_notes text,
    application_date timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.graduation_applications OWNER TO postgres;

--
-- Name: TABLE graduation_applications; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.graduation_applications IS 'A student''s formal application to graduate in a target term. auditor_id is the registrar staff member conducting the degree audit. audit_notes document any deficiencies. Status: submitted → under_audit → approved → awarded → denied.';


--
-- Name: intervention_cases; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.intervention_cases (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    assigned_advisor_id uuid,
    trigger_reason character varying(255) NOT NULL,
    is_open boolean DEFAULT true NOT NULL,
    opened_at timestamp with time zone DEFAULT now() NOT NULL,
    closed_at timestamp with time zone,
    outcome_notes text,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.intervention_cases OWNER TO postgres;

--
-- Name: TABLE intervention_cases; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.intervention_cases IS 'An at-risk student intervention case opened by an advisor, instructor, or early alert system. trigger_reason documents the basis for opening (e.g., attendance, grade, financial). is_open / closed_at track lifecycle. outcome_notes document the resolution. Linked to the student''s risk profile.';


--
-- Name: materials_catalog; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.materials_catalog (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    material_type sis.material_type NOT NULL,
    isbn_13 character varying(20),
    title character varying(255) NOT NULL,
    author character varying(255),
    publisher character varying(255),
    publication_year integer,
    estimated_retail_price numeric(8,2),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE sis.materials_catalog OWNER TO postgres;

--
-- Name: ncaa_academic_evaluations; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.ncaa_academic_evaluations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    user_id uuid NOT NULL,
    term_id uuid NOT NULL,
    snapshot_cumulative_gpa numeric(4,3) NOT NULL,
    term_degree_applicable_credits_earned numeric(6,2) CONSTRAINT ncaa_academic_evaluations_term_degree_applicable_credi_not_null NOT NULL,
    snapshot_degree_completion_percentage numeric(5,2) CONSTRAINT ncaa_academic_evaluations_snapshot_degree_completion_p_not_null NOT NULL,
    overall_eligibility sis.ncaa_eligibility_status NOT NULL,
    evaluated_at timestamp with time zone DEFAULT now() NOT NULL,
    evaluated_by_id uuid
);


ALTER TABLE sis.ncaa_academic_evaluations OWNER TO postgres;

--
-- Name: TABLE ncaa_academic_evaluations; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.ncaa_academic_evaluations IS 'Term-end NCAA academic eligibility evaluation for a student athlete. Snapshots cumulative_gpa, degree_completion_percentage, and term degree-applicable credits earned. overall_eligibility: eligible, warning, ineligible. Evaluated_by_id is the compliance officer or registrar staff member.';


--
-- Name: nsc_submission_logs; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.nsc_submission_logs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    submission_type character varying(20) NOT NULL,
    term_id uuid,
    status sis.nsc_submission_status DEFAULT 'pending'::sis.nsc_submission_status NOT NULL,
    file_format_version character varying(10),
    record_count integer DEFAULT 0 NOT NULL,
    accepted_count integer,
    error_count integer,
    file_reference character varying(1024),
    response_file_reference character varying(1024),
    nsc_batch_id character varying(100),
    transmitted_at timestamp with time zone,
    response_received_at timestamp with time zone,
    initiated_by_user_id uuid,
    initiated_by_service character varying(100),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT nsc_submission_logs_counts_non_negative CHECK (((record_count >= 0) AND ((accepted_count IS NULL) OR (accepted_count >= 0)) AND ((error_count IS NULL) OR (error_count >= 0)))),
    CONSTRAINT nsc_submission_logs_type_check CHECK (((submission_type)::text = ANY ((ARRAY['enrollment'::character varying, 'degree_verify'::character varying])::text[])))
);


ALTER TABLE sis.nsc_submission_logs OWNER TO postgres;

--
-- Name: TABLE nsc_submission_logs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.nsc_submission_logs IS 'Audit log of every NSC enrollment reporting and DegreeVerify file submission. One row per transmitted file. Links enrollment records to their submission via awarded_credentials.nsc_submission_id. Provides the resubmission history required by NSC''s reconciliation process and the audit trail required for Title IV program review.';


--
-- Name: prerequisite_groups; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.prerequisite_groups (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    course_id uuid NOT NULL,
    operator sis.prerequisite_operator DEFAULT 'all_of'::sis.prerequisite_operator NOT NULL,
    display_label character varying(255),
    display_order smallint DEFAULT 0 NOT NULL
);


ALTER TABLE sis.prerequisite_groups OWNER TO postgres;

--
-- Name: TABLE prerequisite_groups; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.prerequisite_groups IS 'Logical grouping node within a course''s prerequisite tree. A course may have multiple groups; the student must satisfy at least one requirement within each group. Within a group, the operator controls whether all requirements (all_of) or any one (any_of) must be met. Individual requirements are in sis.prerequisite_requirements.';


--
-- Name: prerequisite_overrides; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.prerequisite_overrides (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    section_id uuid NOT NULL,
    waived_requirement_id uuid,
    reason text NOT NULL,
    granted_by_user_id uuid NOT NULL,
    workflow_submission_id uuid,
    expires_at timestamp with time zone,
    is_active boolean DEFAULT true NOT NULL,
    granted_at timestamp with time zone DEFAULT now() NOT NULL,
    revoked_at timestamp with time zone,
    revoked_by_user_id uuid,
    revoke_reason text,
    CONSTRAINT prerequisite_overrides_revoked_needs_reason CHECK (((revoked_at IS NULL) OR (revoke_reason IS NOT NULL)))
);


ALTER TABLE sis.prerequisite_overrides OWNER TO postgres;

--
-- Name: TABLE prerequisite_overrides; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.prerequisite_overrides IS 'Per-student, per-section prerequisite waiver. Grants enrollment permission despite unmet prerequisites. waived_requirement_id = NULL waives all prerequisites for the section. The PQ sweep checks this table before flagging or dropping a student. Linked to a workflow.submissions approval for audit trail.';


--
-- Name: prerequisite_requirements; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.prerequisite_requirements (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    group_id uuid NOT NULL,
    kind sis.prerequisite_kind NOT NULL,
    required_course_id uuid,
    min_grade_symbol character varying(5),
    required_test_id uuid,
    min_test_score numeric,
    required_class_level character varying(20),
    required_program_id uuid,
    description character varying(500),
    transfer_credit_satisfies boolean DEFAULT true NOT NULL,
    exam_credit_satisfies boolean DEFAULT true NOT NULL,
    CONSTRAINT prereq_req_class_level_needs_level CHECK (((kind <> 'class_level'::sis.prerequisite_kind) OR (required_class_level IS NOT NULL))),
    CONSTRAINT prereq_req_course_kinds_need_course CHECK (((kind <> ALL (ARRAY['course_completion'::sis.prerequisite_kind, 'course_with_grade'::sis.prerequisite_kind, 'concurrent_enrollment'::sis.prerequisite_kind])) OR (required_course_id IS NOT NULL))),
    CONSTRAINT prereq_req_grade_kind_needs_grade CHECK (((kind <> 'course_with_grade'::sis.prerequisite_kind) OR (min_grade_symbol IS NOT NULL))),
    CONSTRAINT prereq_req_test_kind_needs_test CHECK (((kind <> 'test_score'::sis.prerequisite_kind) OR (required_test_id IS NOT NULL)))
);


ALTER TABLE sis.prerequisite_requirements OWNER TO postgres;

--
-- Name: TABLE prerequisite_requirements; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.prerequisite_requirements IS 'Individual requirement within a prerequisite group. kind drives which columns are evaluated. course_with_grade checks transcript_records for a completed course with final_letter_grade >= min_grade_symbol on the tenant''s grading scale. concurrent_enrollment checks active enrollments in the same term (i.e. the student is registered for the required course simultaneously). transfer_credit_satisfies and exam_credit_satisfies control whether non-institutional credit sources count toward this specific requirement.';


--
-- Name: prerequisite_sweep_results; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.prerequisite_sweep_results (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    sweep_run_id uuid NOT NULL,
    enrollment_id uuid NOT NULL,
    student_id uuid NOT NULL,
    section_id uuid NOT NULL,
    result_status sis.sweep_result_status NOT NULL,
    evaluation_detail jsonb,
    active_override_id uuid,
    dropped_at timestamp with time zone,
    notification_sent_at timestamp with time zone,
    evaluated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT prerequisite_sweep_results_dropped_needs_timestamp CHECK (((result_status <> 'dropped'::sis.sweep_result_status) OR (dropped_at IS NOT NULL)))
);


ALTER TABLE sis.prerequisite_sweep_results OWNER TO postgres;

--
-- Name: TABLE prerequisite_sweep_results; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.prerequisite_sweep_results IS 'Per-student, per-enrollment result of a prerequisite sweep. evaluation_detail (JSONB) contains the full tree of which groups and requirements passed or failed, enabling the registrar dashboard to show exactly which prerequisite was unmet without recomputing. Append-only per sweep run — each new sweep produces new rows.';


--
-- Name: prerequisite_sweep_runs; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.prerequisite_sweep_runs (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    term_id uuid NOT NULL,
    trigger_type sis.sweep_trigger NOT NULL,
    student_id uuid,
    section_id uuid,
    is_dry_run boolean DEFAULT false NOT NULL,
    enrollments_evaluated integer DEFAULT 0 NOT NULL,
    prerequisites_met integer DEFAULT 0 NOT NULL,
    overrides_applied integer DEFAULT 0 NOT NULL,
    flagged_for_review integer DEFAULT 0 NOT NULL,
    enrollments_dropped integer DEFAULT 0 NOT NULL,
    initiated_by_service character varying(100),
    initiated_by_user_id uuid,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    failed_at timestamp with time zone,
    failure_reason text,
    associated_cpos_run_id uuid,
    CONSTRAINT prerequisite_sweep_runs_counts_non_negative CHECK (((enrollments_evaluated >= 0) AND (prerequisites_met >= 0) AND (overrides_applied >= 0) AND (flagged_for_review >= 0) AND (enrollments_dropped >= 0)))
);


ALTER TABLE sis.prerequisite_sweep_runs OWNER TO postgres;

--
-- Name: TABLE prerequisite_sweep_runs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.prerequisite_sweep_runs IS 'Audit log of every prerequisite sweep execution. is_dry_run = true evaluates prerequisites without dropping anyone — used to preview the impact of a sweep before the add/drop deadline. Per-student results are in sis.prerequisite_sweep_results.';


--
-- Name: COLUMN prerequisite_sweep_runs.associated_cpos_run_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.prerequisite_sweep_runs.associated_cpos_run_id IS 'The CPOS sweep run that executed concurrently with this PQ sweep. When registration opens, both sweeps run together; this FK links the two runs for unified reporting.';


--
-- Name: program_accreditations; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.program_accreditations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    program_id uuid NOT NULL,
    accreditor_id uuid NOT NULL,
