--
-- Name: student_academic_standing; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.student_academic_standing (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    term_id uuid NOT NULL,
    policy_id uuid NOT NULL,
    cumulative_gpa_at_eval numeric(4,3),
    term_gpa_at_eval numeric(4,3),
    cumulative_credits_at_eval numeric(7,2),
    consecutive_probation_terms smallint DEFAULT 0 NOT NULL,
    standing_status sis.academic_standing_status NOT NULL,
    prior_standing_status sis.academic_standing_status,
    is_appealed boolean DEFAULT false NOT NULL,
    appeal_outcome character varying(50),
    appeal_workflow_id uuid,
    notes text,
    evaluated_by_service character varying(100),
    evaluated_by_user_id uuid,
    evaluated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT standing_credits_non_negative CHECK (((cumulative_credits_at_eval IS NULL) OR (cumulative_credits_at_eval >= (0)::numeric))),
    CONSTRAINT student_academic_standing_consecutive_non_negative CHECK ((consecutive_probation_terms >= 0)),
    CONSTRAINT student_academic_standing_gpa_range CHECK (((cumulative_gpa_at_eval IS NULL) OR ((cumulative_gpa_at_eval >= (0)::numeric) AND (cumulative_gpa_at_eval <= 4.0)))),
    CONSTRAINT student_academic_standing_term_gpa_range CHECK (((term_gpa_at_eval IS NULL) OR ((term_gpa_at_eval >= (0)::numeric) AND (term_gpa_at_eval <= 4.0))))
);


ALTER TABLE sis.student_academic_standing OWNER TO postgres;

--
-- Name: TABLE student_academic_standing; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_academic_standing IS 'Per-student, per-term academic standing determination. One row per (student, term); the unique constraint prevents duplicate evaluations. Snapshots GPA values at evaluation time so the determination is reproducible even if transcript records are later corrected. is_appealed and appeal_outcome track standing appeals linked to a workflow. The Rust standing service also updates sis.student_profiles.academic_standing_status to the most recent determination for fast registration eligibility checks.';


--
-- Name: COLUMN student_academic_standing.cumulative_credits_at_eval; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_academic_standing.cumulative_credits_at_eval IS 'Cumulative credits attempted at the time of this standing evaluation. Required to prove that the academic_standing_policies.min_credits_for_evaluation threshold was met at eval time. Without this snapshot, a subsequent transcript correction could make a historical evaluation appear to have been applied below the minimum threshold.';


--
-- Name: student_athletes; Type: TABLE; Schema: sis; Owner: postgres
