    CONSTRAINT student_demographics_dates_valid CHECK (((effective_end_date IS NULL) OR (effective_end_date > effective_start_date)))
);


ALTER TABLE sis.student_demographics OWNER TO postgres;

--
-- Name: TABLE student_demographics; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_demographics IS 'FERPA-restricted demographic data for a student. date_of_birth, legal_sex, gender_identity, race_categories (IPEDS multi-select array), hispanic_or_latino, and first_generation_student are collected for federal reporting and equity analysis. requires_iep_or_504 and housing_status are operational flags. All fields are classified in data_governance.pii_field_registry as restricted or regulated.';


--
-- Name: COLUMN student_demographics.effective_start_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_demographics.effective_start_date IS 'First date this demographic record was in effect. For the initial record: the student''s first enrollment date. For subsequent records: the date the change was processed.';


--
-- Name: COLUMN student_demographics.effective_end_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_demographics.effective_end_date IS 'Last date this record was in effect (exclusive). NULL = this is the current active record. When a student updates their legal name, the old row gets effective_end_date = today and a new row is inserted.';


--
-- Name: COLUMN student_demographics.is_current; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_demographics.is_current IS 'Denormalized current-row flag for fast query performance. The partial index on (student_id, tenant_id) WHERE is_current = true makes the common case (fetch current demographics) an index lookup. Must be kept consistent with effective_end_date by the Rust service.';


--
-- Name: COLUMN student_demographics.superseded_by_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_demographics.superseded_by_id IS 'FK to the row that replaced this one. Enables forward-traversal through the version chain: old_row.superseded_by_id → new_row.id. Combined with reversed FK chain gives complete audit history.';


