);


ALTER TABLE sis.student_programs OWNER TO postgres;

--
-- Name: TABLE student_programs; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_programs IS 'A student''s declared academic program(s). A student may have multiple active programs (double major, major+minor). is_primary marks the primary program for SAP and financial aid calculation. priority orders multiple programs. status: declared → active → completed → withdrawn.';


--
-- Name: COLUMN student_programs.status; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_programs.status IS 'Lifecycle status of this program declaration. active is the normal operational state. completed is set when a credential is awarded. CPOS sweep uses this column to determine which program''s requirements govern a student''s Title IV eligible courses.';


--
-- Name: COLUMN student_programs.declared_term_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_programs.declared_term_id IS 'The term in which this program was declared. Used as the start of the CPOS clock for max timeframe calculations.';


--
-- Name: COLUMN student_programs.expected_completion_term_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_programs.expected_completion_term_id IS 'The term the student is expected to complete this program. Drives graduation audit scheduling and CPOS timeframe warnings.';


--
-- Name: COLUMN student_programs.effective_end_date; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_programs.effective_end_date IS 'Date this program declaration ceased to be current. NULL = still active. For a student who changes major: old row gets effective_end_date = today, new row inserted with is_current = true and the new program_id. declared_on (existing column) serves as effective_start_date.';


--
-- Name: COLUMN student_programs.change_reason; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.student_programs.change_reason IS 'Why this program declaration changed. Audit trail for major changes. Examples: "Student requested major change to Computer Science", "Administrative correction — wrong program entered at admission".';


--
