    CONSTRAINT student_risk_profiles_dates_valid CHECK (((effective_end_date IS NULL) OR (effective_end_date > effective_start_date)))
);


ALTER TABLE sis.student_risk_profiles OWNER TO postgres;

--
-- Name: TABLE student_risk_profiles; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_risk_profiles IS 'SCD Type 2: each row represents one risk assessment period for a student. The history of rows shows the risk level trajectory over time. assessment_reason documents what triggered the risk level change. Time-travel query: WHERE student_id = $1 AND effective_start_date <= $date AND (effective_end_date IS NULL OR effective_end_date > $date).';


--
-- Name: student_timeframe_snapshots; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.student_timeframe_snapshots (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    student_program_id uuid,
    snapshot_published_length numeric(7,2) NOT NULL,
    snapshot_max_timeframe numeric(7,2) NOT NULL,
    snapshot_credits_attempted numeric(7,2) DEFAULT 0 NOT NULL,
    snapshot_credits_earned numeric(7,2) DEFAULT 0 NOT NULL,
    snapshot_credits_required numeric(7,2) NOT NULL,
    timeframe_percentage numeric(6,2) GENERATED ALWAYS AS (
CASE
    WHEN (snapshot_max_timeframe > (0)::numeric) THEN round(((snapshot_credits_attempted / snapshot_max_timeframe) * (100)::numeric), 2)
    ELSE (0)::numeric
END) STORED NOT NULL,
    credits_remaining_in_timeframe numeric(7,2) GENERATED ALWAYS AS (GREATEST((snapshot_max_timeframe - snapshot_credits_attempted), (0)::numeric)) STORED CONSTRAINT student_timeframe_snapshots_credits_remaining_in_timef_not_null NOT NULL,
    crossed_warning_threshold smallint,
    is_new_threshold_crossing boolean DEFAULT false NOT NULL,
    term_id uuid NOT NULL,
    gpa_recalc_run_id uuid,
    snapshot_taken_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT student_timeframe_snapshots_credits_non_negative CHECK (((snapshot_credits_attempted >= (0)::numeric) AND (snapshot_credits_earned >= (0)::numeric) AND (snapshot_published_length > (0)::numeric) AND (snapshot_max_timeframe > (0)::numeric))),
    CONSTRAINT student_timeframe_snapshots_threshold_level_valid CHECK (((crossed_warning_threshold IS NULL) OR (crossed_warning_threshold = ANY (ARRAY[1, 2, 3]))))
);


ALTER TABLE sis.student_timeframe_snapshots OWNER TO postgres;

--
-- Name: TABLE student_timeframe_snapshots; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.student_timeframe_snapshots IS 'Per-student, per-term timeframe position record covering ALL students (not just financial aid recipients, unlike finance.sap_evaluations). Written by the Rust GPA service after every end-of-term recalculation. timeframe_percentage and credits_remaining_in_timeframe are generated columns — computed automatically from the snapshot values. is_new_threshold_crossing = true signals the event bus to emit a timeframe warning event for advisor outreach.';


--
-- Name: transcript_records; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.transcript_records (
