    quality_points numeric(5,2) NOT NULL,
    is_transfer_credit boolean DEFAULT false NOT NULL,
    is_credit_for_prior_learning boolean DEFAULT false NOT NULL,
    is_credit_by_assessment boolean DEFAULT false NOT NULL,
    is_locked boolean DEFAULT false NOT NULL,
    recorded_at timestamp with time zone DEFAULT now() NOT NULL,
    duplicate integer,
    source_institution_id uuid,
    external_course_id uuid,
    record_type sis.transcript_record_type DEFAULT 'institutional'::sis.transcript_record_type NOT NULL,
