);


ALTER TABLE sis.transcript_records OWNER TO postgres;

--
-- Name: TABLE transcript_records; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.transcript_records IS 'The permanent academic record of a student''s coursework. Covers both institutional courses and accepted transfer credits. is_locked prevents modification once posted. includes_in_gpa and includes_in_attempted_hours drive GPA and credit load calculations. quality_points = credits × grade points. is_credit_by_assessment and is_credit_for_prior_learning flag non-traditional credit sources for IPEDS reporting. Immutable once recorded per institutional records policy.';


--
-- Name: COLUMN transcript_records.repeat_instance; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transcript_records.repeat_instance IS 'Which attempt this record represents (1 = first enrollment, 2 = first repeat, etc.). Computed by the Rust GPA service when a grade is posted.';


--
-- Name: COLUMN transcript_records.is_grade_replaced; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transcript_records.is_grade_replaced IS 'When true, this transcript record is excluded from GPA calculation because a subsequent attempt has replaced it per the repeat policy. The record remains visible on the transcript with a repeat notation.';


--
-- Name: COLUMN transcript_records.replaced_by_record_id; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transcript_records.replaced_by_record_id IS 'The transcript record for the subsequent attempt that replaced this grade. Forms a linked list through repeat attempts for full history tracking.';


--
-- Name: transfer_course_records; Type: TABLE; Schema: sis; Owner: postgres
