COMMENT ON TABLE sis.transfer_course_records IS 'Individual course-level decisions within a transfer evaluation. Captures external course metadata (code, title, credits, grade) and the articulation decision (awarded_institutional_course_id, awarded_institutional_credits, applied_articulation_rule_id). status: pending, accepted, denied, accepted_as_elective.';


--
-- Name: COLUMN transfer_course_records.external_grade_symbol; Type: COMMENT; Schema: sis; Owner: postgres
