COMMENT ON COLUMN sis.transfer_course_records.external_grade_symbol IS 'The grade as it appears on the external transcript (e.g. "A-", "Merit", "15/20"). Set by the evaluator when entering the transfer record.';


--
-- Name: COLUMN transfer_course_records.translated_letter_grade; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transfer_course_records.translated_letter_grade IS 'The equivalent internal letter grade after crosswalk translation. Set automatically by trg_translate_transfer_grade when status is accepted. May be overridden by the registrar via registrar_grade_override.';


--
-- Name: COLUMN transfer_course_records.translated_quality_points; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transfer_course_records.translated_quality_points IS 'Quality points to post to sis.transcript_records, computed from the translated letter grade and the applicable transfer_grade_policy.';


--
-- Name: COLUMN transfer_course_records.translation_source; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transfer_course_records.translation_source IS 'How the translated grade was determined — crosswalk, interpolation, policy default, or manual registrar entry.';


--
-- Name: COLUMN transfer_course_records.grade_meets_minimum; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON COLUMN sis.transfer_course_records.grade_meets_minimum IS 'Whether the external grade meets the minimum required by the applicable articulation rule or transfer_grade_policy. false does not automatically reject — the evaluator makes the final call.';


--
-- Name: transfer_evaluations; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.transfer_evaluations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    student_id uuid NOT NULL,
    external_institution_id uuid NOT NULL,
    evaluator_id uuid,
    official_transcript_document_id uuid,
    is_official boolean DEFAULT false NOT NULL,
    status character varying(50) DEFAULT 'in_progress'::character varying NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone
);


ALTER TABLE sis.transfer_evaluations OWNER TO postgres;

--
-- Name: TABLE transfer_evaluations; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.transfer_evaluations IS 'A formal evaluation of a student''s transfer credits from an external institution. official_transcript_document_id links to the received transcript in the DMS. is_official flags evaluations based on official sealed transcripts. Status: pending → in_review → completed.';


--
-- Name: transfer_grade_policies; Type: TABLE; Schema: sis; Owner: postgres
--

CREATE TABLE sis.transfer_grade_policies (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    external_institution_id uuid,
    internal_scale_id uuid NOT NULL,
    min_acceptable_grade_symbol character varying(30),
    min_grade_scale_id uuid,
    qp_treatment sis.transfer_qp_treatment DEFAULT 'use_translated_grade'::sis.transfer_qp_treatment NOT NULL,
    block_on_missing_crosswalk boolean DEFAULT false NOT NULL,
    show_letter_grade_on_transcript boolean DEFAULT true CONSTRAINT transfer_grade_policies_show_letter_grade_on_transcrip_not_null NOT NULL,
    include_in_cumulative_gpa boolean DEFAULT false NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_by_user_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT transfer_grade_policies_min_grade_needs_scale CHECK (((min_acceptable_grade_symbol IS NULL) OR (min_grade_scale_id IS NOT NULL)))
);


ALTER TABLE sis.transfer_grade_policies OWNER TO postgres;

--
-- Name: TABLE transfer_grade_policies; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON TABLE sis.transfer_grade_policies IS 'Per-tenant and per-institution transfer grading policies. Controls minimum acceptable grade, quality point treatment, which internal scale translations target, and transcript display. Resolution: institution-specific policy overrides tenant default. Set external_institution_id = NULL for the tenant-wide default.';


--
-- Name: vw_active_academic_standing; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_active_academic_standing AS
 SELECT DISTINCT ON (sas.tenant_id, sas.student_id) sas.tenant_id,
    sas.student_id,
    u.first_name,
    u.last_name,
    t.name AS term_name,
    sas.standing_status,
    sas.cumulative_gpa_at_eval AS cumulative_gpa,
    sas.term_gpa_at_eval AS term_gpa,
    sas.consecutive_probation_terms,
    sas.is_appealed,
    sas.evaluated_at
   FROM ((sis.student_academic_standing sas
     JOIN core.users u ON ((u.id = sas.student_id)))
     JOIN sis.academic_terms t ON ((t.id = sas.term_id)))
  ORDER BY sas.tenant_id, sas.student_id, sas.evaluated_at DESC;


ALTER VIEW sis.vw_active_academic_standing OWNER TO postgres;

--
-- Name: VIEW vw_active_academic_standing; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_active_academic_standing IS 'Most recent academic standing per student. Uses DISTINCT ON to return only the latest evaluation per student. Filtered to all standing statuses — consumers filter by standing_status as needed (e.g. WHERE standing_status <> ''good_standing'' for the probation/suspension dashboard).';


--
-- Name: vw_current_academic_programs; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_academic_programs AS
 SELECT id,
    tenant_id,
    department_id,
    name,
    credential_id,
    total_credits_required,
    cip_code,
    is_active,
