    updated_at,
    published_credit_length,
    max_timeframe_credits,
    diploma_title,
    nsc_degree_designation,
    hegis_code,
    is_title_iv_eligible,
    is_gainful_employment,
    weeks_of_instruction,
    effective_start_date,
    effective_end_date,
    is_current,
    catalog_year,
    superseded_at,
    superseded_by_id,
    change_summary
   FROM sis.academic_programs
  WHERE ((is_current = true) AND (is_active = true));


ALTER VIEW sis.vw_current_academic_programs OWNER TO postgres;

--
-- Name: vw_current_course_sections; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_course_sections AS
 SELECT id,
    tenant_id,
