    max_enrollment,
    updated_at,
    effective_start_date,
    effective_end_date,
    is_current,
    superseded_at,
    superseded_by_id,
    change_reason
   FROM sis.course_sections
  WHERE (is_current = true);


ALTER VIEW sis.vw_current_course_sections OWNER TO postgres;

--
-- Name: vw_current_courses; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_courses AS
 SELECT id,
    tenant_id,
    subject,
    course,
    title,
    description,
    credits,
    is_active,
    created_at,
    department_id,
    cip_code,
    course_level,
    grading_basis,
    lecture_hours,
    lab_hours,
    clinical_hours,
    independent_study_hours,
