    updated_at,
    fts_doc,
    is_repeatable,
    max_repeat_attempts,
    repeat_policy_id,
    effective_start_date,
    effective_end_date,
    is_current,
    catalog_year,
    superseded_at,
    superseded_by_id,
    change_notes
   FROM sis.courses
  WHERE (is_current = true);


ALTER VIEW sis.vw_current_courses OWNER TO postgres;

--
-- Name: vw_current_student_demographics; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_student_demographics AS
 SELECT student_id,
    tenant_id,
    date_of_birth,
    legal_sex,
    gender_identity,
    hispanic_or_latino,
    race_categories,
    primary_language,
    requires_iep_or_504,
