    effective_start_date,
    effective_end_date,
    is_current,
    superseded_at,
    superseded_by_id
   FROM sis.student_demographics
  WHERE (is_current = true);


ALTER VIEW sis.vw_current_student_demographics OWNER TO postgres;

--
-- Name: VIEW vw_current_student_demographics; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_current_student_demographics IS 'Current demographic record per student. Uses the partial index WHERE is_current = true for O(1) lookup. For point-in-time queries use the base table directly with effective_start_date <= $date AND (effective_end_date IS NULL OR effective_end_date > $date).';


--
-- Name: vw_current_student_programs; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_student_programs AS
 SELECT id,
    tenant_id,
    student_id,
    program_id,
    priority,
    is_primary,
    declared_on,
    updated_at,
    status,
    declared_term_id,
    expected_completion_term_id,
    completed_at,
    effective_end_date,
    is_current,
    superseded_at,
    superseded_by_id,
    change_reason
   FROM sis.student_programs
  WHERE (is_current = true);


ALTER VIEW sis.vw_current_student_programs OWNER TO postgres;

--
-- Name: vw_current_student_risk_profiles; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_current_student_risk_profiles AS
 SELECT tenant_id,
    student_id,
    current_risk_level,
    risk_score,
    days_since_last_lms_login,
    current_term_absences,
    missing_assignments_count,
    last_calculated_at,
    updated_at,
    effective_start_date,
    effective_end_date,
    is_current,
    superseded_at,
    superseded_by_id,
    assessment_reason
   FROM sis.student_risk_profiles
  WHERE (is_current = true);


ALTER VIEW sis.vw_current_student_risk_profiles OWNER TO postgres;

--
-- Name: vw_demographics_change_log; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_demographics_change_log AS
 SELECT d.tenant_id,
    d.student_id,
    u.first_name AS current_first_name,
    u.last_name AS current_last_name,
    d.legal_sex,
    d.gender_identity,
    d.date_of_birth,
    d.hispanic_or_latino,
    d.race_categories,
    d.requires_iep_or_504,
    d.effective_start_date,
    d.effective_end_date,
    d.is_current,
    d.superseded_at,
        CASE
            WHEN (d.effective_end_date IS NOT NULL) THEN (d.effective_end_date - d.effective_start_date)
            ELSE (CURRENT_DATE - d.effective_start_date)
        END AS days_in_effect
   FROM (sis.student_demographics d
     JOIN core.users u ON ((u.id = d.student_id)))
  ORDER BY d.student_id, d.effective_start_date;


ALTER VIEW sis.vw_demographics_change_log OWNER TO postgres;

--
-- Name: VIEW vw_demographics_change_log; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_demographics_change_log IS 'Complete audit trail of demographic changes per student. days_in_effect shows how long each version was the current record. Used for FERPA audit responses, financial aid verification, and IPEDS race/ethnicity reporting accuracy audits.';


--
-- Name: vw_external_scale_crosswalk; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_external_scale_crosswalk AS
 SELECT gc.tenant_id,
    egs.name AS external_scale_name,
    egs.country_code,
    ege.grade_symbol AS external_grade,
    ege.grade_label AS external_grade_label,
    ege.percentage_midpoint AS external_pct_midpoint,
    ege.is_passing AS passing_at_sender,
    '→'::text AS maps_to,
    lgs.name AS internal_scale_name,
    lge.letter_grade AS internal_letter_grade,
    lge.min_percentage AS internal_min_pct,
    lge.quality_points AS internal_quality_points,
    gc.mapping_rationale,
    gc.authoritative_source,
    gc.is_approved,
    gc.approved_at
   FROM ((((sis.grade_crosswalks gc
     JOIN sis.external_grading_scales egs ON ((egs.id = gc.external_scale_id)))
     JOIN sis.external_grade_entries ege ON ((ege.id = gc.external_grade_entry_id)))
     JOIN lms.grading_scales lgs ON ((lgs.id = gc.internal_scale_id)))
     JOIN lms.grading_scale_entries lge ON ((lge.id = gc.internal_grade_entry_id)))
  ORDER BY egs.name, ege.display_order;


ALTER VIEW sis.vw_external_scale_crosswalk OWNER TO postgres;

--
-- Name: VIEW vw_external_scale_crosswalk; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_external_scale_crosswalk IS 'Human-readable crosswalk reference for registrar and admissions staff. Shows the complete external → internal grade mapping for all approved and pending crosswalk entries. Used to review and build crosswalk tables in the transfer evaluation administration UI.';


--
-- Name: vw_nsc_degree_verify; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_nsc_degree_verify AS
 SELECT ac.tenant_id,
    ac.student_id,
    u.first_name,
    u.last_name,
    sp.middle_initial,
    sp.ssn_last_four,
    sp.nsc_student_id,
    sd.date_of_birth,
    ac.id AS credential_id,
    ac.conferral_date,
    ac.nsc_degree_designation,
    ac.diploma_title,
    ac.cip_code_snapshot,
    ac.ipeds_award_level_snapshot,
    ac.honors_designation,
    ac.nsc_submitted_at,
    ac.nsc_match_status,
    ( SELECT json_agg(json_build_object('cip_code', acm.cip_code_snapshot, 'major_title', acm.major_title, 'is_primary', acm.is_primary_major) ORDER BY acm.display_order) AS json_agg
           FROM sis.awarded_credential_majors acm
          WHERE (acm.credential_id = ac.id)) AS majors
   FROM (((sis.awarded_credentials ac
     JOIN core.users u ON ((u.id = ac.student_id)))
     JOIN sis.student_profiles sp ON (((sp.user_id = ac.student_id) AND (sp.tenant_id = ac.tenant_id))))
     JOIN sis.student_demographics sd ON (((sd.student_id = ac.student_id) AND (sd.tenant_id = ac.tenant_id))));


ALTER VIEW sis.vw_nsc_degree_verify OWNER TO postgres;

--
-- Name: VIEW vw_nsc_degree_verify; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_nsc_degree_verify IS 'NSC DegreeVerify submission data, one row per awarded credential. Includes all majors as a JSON array for multi-major reporting. nsc_submitted_at = NULL identifies credentials pending first submission. nsc_match_status = NOMATCH identifies credentials requiring manual review. Consumed by the Rust reporting service to generate DegreeVerify flat files.';


--
-- Name: vw_nsc_enrollment_report; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_nsc_enrollment_report AS
 SELECT sp.tenant_id,
    sp.user_id AS student_id,
    u.first_name,
    u.last_name,
    sp.middle_initial,
    sp.ssn_last_four,
    sp.nsc_student_id,
    sd.date_of_birth,
    t.name AS term_name,
    t.nsc_reporting_period,
    t.nsc_academic_year,
    t.census_date,
    t.start_date AS term_start,
    t.end_date AS term_end,
    ( SELECT e.nsc_enrollment_intensity
           FROM (sis.enrollments e
             JOIN sis.course_sections cs ON ((cs.id = e.section_id)))
          WHERE ((e.student_id = sp.user_id) AND (cs.term_id = t.id) AND (e.tenant_id = sp.tenant_id) AND (e.status = 'enrolled'::sis.enrollment_status))
          ORDER BY
                CASE e.nsc_enrollment_intensity
                    WHEN 'F'::sis.nsc_enrollment_intensity THEN 1
                    WHEN 'Q'::sis.nsc_enrollment_intensity THEN 2
                    WHEN 'H'::sis.nsc_enrollment_intensity THEN 3
                    WHEN 'L'::sis.nsc_enrollment_intensity THEN 4
                    WHEN 'A'::sis.nsc_enrollment_intensity THEN 5
                    WHEN 'W'::sis.nsc_enrollment_intensity THEN 6
                    WHEN 'G'::sis.nsc_enrollment_intensity THEN 7
                    WHEN 'D'::sis.nsc_enrollment_intensity THEN 8
                    WHEN 'N'::sis.nsc_enrollment_intensity THEN 9
                    ELSE NULL::integer
                END
         LIMIT 1) AS enrollment_intensity,
    ( SELECT COALESCE(sum(e.credit_hours_enrolled), (0)::numeric) AS "coalesce"
           FROM (sis.enrollments e
             JOIN sis.course_sections cs ON ((cs.id = e.section_id)))
          WHERE ((e.student_id = sp.user_id) AND (cs.term_id = t.id) AND (e.tenant_id = sp.tenant_id) AND (e.status = 'enrolled'::sis.enrollment_status))) AS total_credits_enrolled,
    ( SELECT ap.cip_code
           FROM (sis.student_programs spr
             JOIN sis.academic_programs ap ON ((ap.id = spr.program_id)))
          WHERE ((spr.student_id = sp.user_id) AND (spr.tenant_id = sp.tenant_id) AND (spr.is_primary = true) AND (spr.status = 'active'::sis.student_program_status))
         LIMIT 1) AS primary_cip_code,
    sp.is_nsc_opted_out
   FROM (((sis.student_profiles sp
     JOIN core.users u ON ((u.id = sp.user_id)))
     JOIN sis.student_demographics sd ON (((sd.student_id = sp.user_id) AND (sd.tenant_id = sp.tenant_id))))
     CROSS JOIN sis.academic_terms t)
  WHERE ((t.tenant_id = sp.tenant_id) AND (t.status = ANY (ARRAY['active'::sis.term_status, 'archived'::sis.term_status])) AND (sp.is_nsc_opted_out = false));


ALTER VIEW sis.vw_nsc_enrollment_report OWNER TO postgres;

--
-- Name: VIEW vw_nsc_enrollment_report; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_nsc_enrollment_report IS 'NSC StudentTracker enrollment report data, one row per student per term. Resolves enrollment intensity as the most intense classification across all sections in the term. Excludes opted-out students. The Rust reporting service reads this view and formats the flat file per the NSC School Handbook specification. census_date must be populated on academic_terms before this view produces meaningful NSC submissions.';


--
-- Name: vw_prerequisite_map; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_prerequisite_map AS
 SELECT pg.tenant_id,
    pg.course_id,
    (((parent_c.subject)::text || ' '::text) || (parent_c.course)::text) AS course_code,
    parent_c.title AS course_title,
    pg.id AS group_id,
    pg.operator AS group_operator,
    pg.display_label AS group_label,
    pg.display_order AS group_display_order,
    pr.id AS requirement_id,
    pr.kind,
    (((req_c.subject)::text || ' '::text) || (req_c.course)::text) AS required_course_code,
    req_c.title AS required_course_title,
    pr.min_grade_symbol,
    pr.required_class_level,
    pr.description,
    pr.transfer_credit_satisfies,
    pr.exam_credit_satisfies
   FROM (((sis.prerequisite_groups pg
     JOIN sis.courses parent_c ON ((parent_c.id = pg.course_id)))
     JOIN sis.prerequisite_requirements pr ON ((pr.group_id = pg.id)))
     LEFT JOIN sis.courses req_c ON ((req_c.id = pr.required_course_id)))
  ORDER BY pg.course_id, pg.display_order, pr.kind;


ALTER VIEW sis.vw_prerequisite_map OWNER TO postgres;

--
-- Name: VIEW vw_prerequisite_map; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_prerequisite_map IS 'Human-readable prerequisite tree for all courses. Flattens the two-level group/requirement structure into a single row per requirement with full course code and title resolution. Consumed by the course catalog, registration eligibility UI, and the PQ sweep dashboard to display why a check failed.';


--
-- Name: vw_student_compliance_summary; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_student_compliance_summary AS
 SELECT sp.tenant_id,
    sp.user_id AS student_id,
    u.first_name,
    u.last_name,
    sp.cumulative_credits_attempted,
    sp.cumulative_credits_earned,
    sp.current_timeframe_pct,
    sp.cumulative_gpa,
    sp.term_gpa,
    sp.academic_standing_status,
    sp.gpa_last_calculated_at,
    sas.standing_status AS formal_standing_status,
    sas.cumulative_gpa_at_eval AS standing_snapshot_gpa,
    sas.cumulative_credits_at_eval AS standing_snapshot_credits,
    sas.consecutive_probation_terms,
    sas.term_id AS last_standing_term_id,
    sas.evaluated_at AS standing_evaluated_at,
    sap.resulting_sap_status,
    sap.snapshot_cumulative_gpa AS sap_snapshot_gpa,
    sap.snapshot_attempted_credits AS sap_snapshot_credits,
    sap.snapshot_pace_percentage,
    sap.snapshot_max_timeframe_credits,
        CASE
            WHEN (sap.snapshot_max_timeframe_credits > (0)::numeric) THEN round(((sap.snapshot_attempted_credits / sap.snapshot_max_timeframe_credits) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS sap_timeframe_pct,
    sap.gpa_component_met,
    sap.pace_component_met,
    sap.max_timeframe_component_met,
    sap.consecutive_warning_terms AS sap_consecutive_warning_terms,
    sap.is_financial_aid_recipient,
    sap.evaluation_term_id AS sap_last_term_id,
    sap.evaluated_at AS sap_evaluated_at,
    tfs.timeframe_percentage AS current_timeframe_pct_verified,
    tfs.credits_remaining_in_timeframe,
    tfs.snapshot_max_timeframe,
    tfs.crossed_warning_threshold AS last_crossed_threshold,
    tfs.term_id AS timeframe_snapshot_term_id,
    ((sp.academic_standing_status <> ALL (ARRAY['good_standing'::sis.academic_standing_status, 'reinstated'::sis.academic_standing_status])) AND (sap.resulting_sap_status IS NOT NULL) AND (sap.resulting_sap_status <> 'good_standing'::finance.sap_status)) AS dual_compliance_risk,
    (sap.resulting_sap_status = ANY (ARRAY['suspension'::finance.sap_status, 'max_timeframe_exceeded'::finance.sap_status])) AS aid_suspension_risk,
    (sp.academic_standing_status = ANY (ARRAY['academic_suspension'::sis.academic_standing_status, 'academic_dismissal'::sis.academic_standing_status])) AS registration_blocked,
        CASE
            WHEN (sp.current_timeframe_pct IS NULL) THEN 0
            WHEN (sp.current_timeframe_pct >= (100)::numeric) THEN 3
            WHEN (sp.current_timeframe_pct >= (90)::numeric) THEN 2
            WHEN (sp.current_timeframe_pct >= (75)::numeric) THEN 1
            ELSE 0
        END AS timeframe_risk_tier,
    (EXISTS ( SELECT 1
           FROM finance.sap_appeals sa
          WHERE ((sa.student_id = sp.user_id) AND (sa.tenant_id = sp.tenant_id) AND ((sa.appeal_status)::text = 'pending_committee_review'::text)))) AS sap_appeal_pending,
    (EXISTS ( SELECT 1
           FROM sis.student_academic_standing pending_sas
          WHERE ((pending_sas.student_id = sp.user_id) AND (pending_sas.tenant_id = sp.tenant_id) AND (pending_sas.is_appealed = true) AND (pending_sas.appeal_outcome IS NULL)))) AS standing_appeal_pending
   FROM ((((sis.student_profiles sp
     JOIN core.users u ON ((u.id = sp.user_id)))
     LEFT JOIN LATERAL ( SELECT student_academic_standing.id,
            student_academic_standing.tenant_id,
            student_academic_standing.student_id,
            student_academic_standing.term_id,
            student_academic_standing.policy_id,
            student_academic_standing.cumulative_gpa_at_eval,
            student_academic_standing.term_gpa_at_eval,
            student_academic_standing.cumulative_credits_at_eval,
            student_academic_standing.consecutive_probation_terms,
            student_academic_standing.standing_status,
            student_academic_standing.prior_standing_status,
            student_academic_standing.is_appealed,
            student_academic_standing.appeal_outcome,
            student_academic_standing.appeal_workflow_id,
            student_academic_standing.notes,
            student_academic_standing.evaluated_by_service,
            student_academic_standing.evaluated_by_user_id,
            student_academic_standing.evaluated_at
           FROM sis.student_academic_standing
          WHERE ((student_academic_standing.student_id = sp.user_id) AND (student_academic_standing.tenant_id = sp.tenant_id))
          ORDER BY student_academic_standing.evaluated_at DESC
         LIMIT 1) sas ON (true))
     LEFT JOIN LATERAL ( SELECT sap_evaluations.id,
            sap_evaluations.tenant_id,
            sap_evaluations.student_id,
            sap_evaluations.evaluation_term_id,
            sap_evaluations.snapshot_cumulative_gpa,
            sap_evaluations.snapshot_attempted_credits,
            sap_evaluations.snapshot_earned_credits,
            sap_evaluations.snapshot_pace_percentage,
            sap_evaluations.resulting_sap_status,
            sap_evaluations.evaluated_at,
            sap_evaluations.is_manual_override,
            sap_evaluations.override_reason,
            sap_evaluations.overridden_by_id,
            sap_evaluations.sap_policy_id,
            sap_evaluations.run_id,
            sap_evaluations.is_financial_aid_recipient,
            sap_evaluations.gpa_component_met,
            sap_evaluations.pace_component_met,
            sap_evaluations.max_timeframe_component_met,
            sap_evaluations.snapshot_max_timeframe_credits,
            sap_evaluations.consecutive_warning_terms,
            sap_evaluations.notification_sent_at,
            sap_evaluations.academic_standing_record_id
           FROM finance.sap_evaluations
          WHERE ((sap_evaluations.student_id = sp.user_id) AND (sap_evaluations.tenant_id = sp.tenant_id))
          ORDER BY sap_evaluations.evaluated_at DESC
         LIMIT 1) sap ON (true))
     LEFT JOIN LATERAL ( SELECT student_timeframe_snapshots.id,
            student_timeframe_snapshots.tenant_id,
            student_timeframe_snapshots.student_id,
            student_timeframe_snapshots.student_program_id,
            student_timeframe_snapshots.snapshot_published_length,
            student_timeframe_snapshots.snapshot_max_timeframe,
            student_timeframe_snapshots.snapshot_credits_attempted,
            student_timeframe_snapshots.snapshot_credits_earned,
            student_timeframe_snapshots.snapshot_credits_required,
            student_timeframe_snapshots.timeframe_percentage,
            student_timeframe_snapshots.credits_remaining_in_timeframe,
            student_timeframe_snapshots.crossed_warning_threshold,
            student_timeframe_snapshots.is_new_threshold_crossing,
            student_timeframe_snapshots.term_id,
            student_timeframe_snapshots.gpa_recalc_run_id,
            student_timeframe_snapshots.snapshot_taken_at
           FROM sis.student_timeframe_snapshots
          WHERE ((student_timeframe_snapshots.student_id = sp.user_id) AND (student_timeframe_snapshots.tenant_id = sp.tenant_id))
          ORDER BY student_timeframe_snapshots.snapshot_taken_at DESC
         LIMIT 1) tfs ON (true));


ALTER VIEW sis.vw_student_compliance_summary OWNER TO postgres;

--
-- Name: VIEW vw_student_compliance_summary; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_student_compliance_summary IS 'Unified per-student compliance posture: academic standing, SAP status, and timeframe position in a single row per student. LATERAL joins resolve the most recent row from each system efficiently. timeframe_risk_tier (0–3) enables single-column dashboard filtering:   0 = safe (<75%), 1 = approaching (75–89%),   2 = critical (90–99%), 3 = exceeded (>=100%). current_timeframe_pct_verified comes from student_timeframe_snapshots (all students); sap_timeframe_pct comes from sap_evaluations (aid students). Both are present so the financial aid office and registrar see consistent values from their respective authoritative sources. RLS is enforced through sis.student_profiles (base table).';


--
-- Name: vw_student_program_history; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_student_program_history AS
 SELECT sp.tenant_id,
    sp.student_id,
    u.first_name,
    u.last_name,
    ap.name AS program_name,
    ap.cip_code,
    sp.declared_on AS effective_start,
    sp.effective_end_date AS effective_end,
    sp.is_current,
    sp.is_primary,
    sp.status,
    sp.change_reason,
    sp.superseded_at
   FROM ((sis.student_programs sp
     JOIN sis.academic_programs ap ON ((ap.id = sp.program_id)))
     JOIN core.users u ON ((u.id = sp.student_id)))
  ORDER BY sp.student_id, sp.declared_on;


ALTER VIEW sis.vw_student_program_history OWNER TO postgres;

--
-- Name: VIEW vw_student_program_history; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_student_program_history IS 'Complete major/program change history per student in chronological order. Shows every declared program with its effective period. The current program has is_current = true and effective_end_date IS NULL. Used for IPEDS reporting, graduation audits, and accreditation self-studies.';


--
-- Name: vw_student_repeat_summary; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_student_repeat_summary AS
 SELECT tr.tenant_id,
    tr.student_id,
    tr.course_id,
    (((c.subject)::text || ' '::text) || (c.course)::text) AS course_code,
    c.title AS course_title,
    c.max_repeat_attempts,
    count(*) AS total_attempts,
    count(*) FILTER (WHERE (NOT tr.is_grade_replaced)) AS attempts_counting_in_gpa,
    count(*) FILTER (WHERE tr.is_grade_replaced) AS attempts_grade_replaced,
    max((
        CASE
            WHEN (NOT tr.is_grade_replaced) THEN tr.final_letter_grade
            ELSE NULL::character varying
        END)::text) AS counting_grade,
    max(
        CASE
            WHEN (NOT tr.is_grade_replaced) THEN tr.quality_points
            ELSE NULL::numeric
        END) AS counting_quality_points,
    tr.repeat_policy_applied,
    tr.forgiveness_applied
   FROM (sis.transcript_records tr
     JOIN sis.courses c ON ((c.id = tr.course_id)))
  WHERE ((tr.record_type = 'institutional'::sis.transcript_record_type) AND (tr.repeat_instance > 0))
  GROUP BY tr.tenant_id, tr.student_id, tr.course_id, c.subject, c.course, c.title, c.max_repeat_attempts, tr.repeat_policy_applied, tr.forgiveness_applied
 HAVING (count(*) > 1);


ALTER VIEW sis.vw_student_repeat_summary OWNER TO postgres;

--
-- Name: VIEW vw_student_repeat_summary; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_student_repeat_summary IS 'Per-student, per-course repeat attempt history. Only returns courses with more than one attempt (HAVING COUNT(*) > 1). counting_grade is the grade currently included in GPA calculations. Consumed by the registrar repeat course dashboard and the student academic history report.';


--
-- Name: vw_transfer_equivalencies; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_transfer_equivalencies AS
 SELECT ext_inst.tenant_id,
    ext_inst.id AS external_institution_id,
    ext_inst.name AS external_institution_name,
    ext_inst.calendar_type AS external_calendar_type,
    (((ext_crs.subject)::text || ' '::text) || (ext_crs.course)::text) AS external_course_code,
    ext_crs.title AS external_course_title,
    ext_crs.credits AS external_credits,
    rule.required_score,
    int_crs.id AS institutional_course_id,
    (((int_crs.subject)::text || ' '::text) || (int_crs.course)::text) AS institutional_course_code,
    int_crs.title AS institutional_course_title,
    int_crs.credits AS institutional_credits
   FROM (((sis.articulation_rules rule
     JOIN sis.external_courses ext_crs ON ((rule.external_course_id = ext_crs.id)))
     JOIN sis.external_institutions ext_inst ON ((ext_crs.institution_id = ext_inst.id)))
     JOIN sis.courses int_crs ON ((rule.internal_course_id = int_crs.id)))
  WHERE (rule.status = 'active'::sis.articulation_status);


ALTER VIEW sis.vw_transfer_equivalencies OWNER TO postgres;

--
-- Name: VIEW vw_transfer_equivalencies; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_transfer_equivalencies IS 'Public-facing view of active articulation rules presented as human-readable transfer equivalencies. Joins articulation_rules with external institution names, external course details, and internal course details. Consumed by the transfer credit estimator tool on the admissions portal.';


--
-- Name: vw_transfer_grade_summary; Type: VIEW; Schema: sis; Owner: postgres
--

CREATE VIEW sis.vw_transfer_grade_summary AS
 SELECT te.tenant_id,
    te.student_id,
    ei.name AS sending_institution,
    ec.subject AS external_subject,
    ec.course AS external_number,
    ec.title AS external_title,
    ec.credits AS external_credits,
    tcr.external_grade_symbol,
    ege.grade_label AS external_grade_label,
    ege.is_passing AS passing_at_sender,
    tcr.grade_meets_minimum,
    tcr.status AS transfer_status,
    tcr.translated_letter_grade,
    tcr.translated_quality_points,
    tcr.translation_source,
    (((c.subject)::text || ' '::text) || (c.course)::text) AS internal_course,
    c.title AS internal_course_title,
    tcr.awarded_institutional_credits,
        CASE
            WHEN (tgp.include_in_cumulative_gpa AND (tcr.translated_quality_points IS NOT NULL)) THEN round((tcr.translated_quality_points * tcr.awarded_institutional_credits), 3)
            ELSE (0)::numeric
        END AS quality_points_earned,
    tgp.include_in_cumulative_gpa,
    tcr.registrar_grade_override,
    tcr.translation_source AS how_grade_was_determined,
    te.id AS evaluation_id,
    tcr.id AS transfer_course_record_id
   FROM ((((((sis.transfer_course_records tcr
     JOIN sis.transfer_evaluations te ON ((te.id = tcr.evaluation_id)))
     JOIN sis.external_institutions ei ON ((ei.id = te.external_institution_id)))
     LEFT JOIN sis.external_courses ec ON ((ec.id = tcr.id)))
     LEFT JOIN sis.external_grade_entries ege ON ((ege.id = tcr.external_grade_entry_id)))
     LEFT JOIN sis.courses c ON ((c.id = tcr.awarded_institutional_course_id)))
     LEFT JOIN sis.transfer_grade_policies tgp ON (((tgp.tenant_id = te.tenant_id) AND ((tgp.external_institution_id = te.external_institution_id) OR (tgp.external_institution_id IS NULL)) AND (tgp.is_active = true))))
  ORDER BY te.student_id, ei.name, tcr.status;


ALTER VIEW sis.vw_transfer_grade_summary OWNER TO postgres;

--
-- Name: VIEW vw_transfer_grade_summary; Type: COMMENT; Schema: sis; Owner: postgres
--

COMMENT ON VIEW sis.vw_transfer_grade_summary IS 'Per-student transfer credit summary showing external grade, translated internal grade, quality points, and GPA impact. Consumed by the transfer evaluation dashboard and student transfer report. RLS enforced through base tables. When multiple policies match (institution + tenant default), the most specific (institution-level) policy row appears — ORDER BY ensures consistent display when both levels apply.';


--
-- Name: esignatures; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.esignatures (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    routing_log_id uuid NOT NULL,
    signer_user_id uuid NOT NULL,
    signature_method workflow.signature_method NOT NULL,
    ip_address character varying(45) NOT NULL,
    user_agent text NOT NULL,
    cryptographic_hash character varying(255) NOT NULL,
    signed_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE workflow.esignatures OWNER TO postgres;

--
-- Name: TABLE esignatures; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.esignatures IS 'A cryptographically anchored e-signature captured when a routing step requires formal acknowledgement or approval. cryptographic_hash is SHA-256(submission_id + user_id + signed_at + ip_address) providing tamper evidence. signature_method: typed_name, drawn, certificate. ip_address and user_agent provide forensic context. Append-only; signatures are immutable.';


--
-- Name: form_stages; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.form_stages (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    tenant_id uuid NOT NULL,
    form_id uuid NOT NULL,
    stage_name character varying(255) NOT NULL,
    stage_order integer NOT NULL,
    completion_strategy workflow.stage_completion_strategy DEFAULT 'all_must_approve'::workflow.stage_completion_strategy NOT NULL,
    quorum_required_count integer,
    rejection_kills_workflow boolean DEFAULT true NOT NULL
);


ALTER TABLE workflow.form_stages OWNER TO postgres;

--
-- Name: TABLE form_stages; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.form_stages IS 'An ordered stage grouping steps within a workflow form. Stages execute sequentially; steps within a stage may execute in parallel depending on completion_strategy. quorum_required_count is only evaluated when completion_strategy = quorum_required.';


--
-- Name: forms; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.forms (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT workflow_forms_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT workflow_forms_tenant_id_not_null NOT NULL,
    department_id uuid CONSTRAINT workflow_forms_department_id_not_null NOT NULL,
    name character varying CONSTRAINT workflow_forms_name_not_null NOT NULL,
    description text,
    ui_schema jsonb CONSTRAINT workflow_forms_ui_schema_not_null NOT NULL,
    is_active boolean DEFAULT false,
    created_at timestamp with time zone DEFAULT now() CONSTRAINT workflow_forms_created_at_not_null NOT NULL,
    updated_at timestamp with time zone DEFAULT now() CONSTRAINT workflow_forms_updated_at_not_null NOT NULL
);


ALTER TABLE workflow.forms OWNER TO postgres;

--
-- Name: TABLE forms; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.forms IS 'A reusable form definition. ui_schema (JSONB) defines the form fields, validation rules, and layout for the frontend renderer. department_id scopes the form to its owning department. Forms are versioned by creating new form rows; submissions reference the form_id active at submission time.';


--
-- Name: routing_logs; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.routing_logs (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT submission_routing_logs_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT submission_routing_logs_tenant_id_not_null NOT NULL,
    submission_id uuid CONSTRAINT submission_routing_logs_submission_id_not_null NOT NULL,
    step_id uuid CONSTRAINT submission_routing_logs_step_id_not_null NOT NULL,
    assigned_to_user_id uuid CONSTRAINT submission_routing_logs_assigned_to_user_id_not_null NOT NULL,
    action_taken workflow.workflow_action_type,
    reviewer_comments text,
    assigned_at timestamp with time zone DEFAULT now() CONSTRAINT submission_routing_logs_assigned_at_not_null NOT NULL,
    acted_upon_at timestamp with time zone
);


ALTER TABLE workflow.routing_logs OWNER TO postgres;

--
-- Name: TABLE routing_logs; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.routing_logs IS 'Immutable record of every routing action taken on a submission. One row per step per submission. assigned_to_user_id is the reviewer. action_taken: approved, rejected, returned_for_revision, delegated, escalated. acted_upon_at and reviewer_comments complete the audit trail. Append-only; never updated.';


--
-- Name: steps; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.steps (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT workflow_steps_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT workflow_steps_tenant_id_not_null NOT NULL,
    form_id uuid CONSTRAINT workflow_steps_form_id_not_null NOT NULL,
    action_required workflow.workflow_action_type CONSTRAINT workflow_steps_action_required_not_null NOT NULL,
    target_resolver character varying(100) CONSTRAINT workflow_steps_target_resolver_not_null NOT NULL,
    target_user_id uuid,
    conditional_logic jsonb,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    stage_id uuid,
    timeout_hours integer,
    escalation_target_resolver character varying(100)
);


ALTER TABLE workflow.steps OWNER TO postgres;

--
-- Name: TABLE steps; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.steps IS 'An individual review/approval step within a stage. target_resolver determines who receives the step: specific_user, role, department_head, submitter_supervisor, or a dynamic expression. target_user_id is populated when target_resolver = specific_user. conditional_logic (JSONB) allows steps to be skipped based on submission payload values. escalation_target_resolver fires if the step is not acted upon within the configured SLA window.';


--
-- Name: submissions; Type: TABLE; Schema: workflow; Owner: postgres
--

CREATE TABLE workflow.submissions (
    id uuid DEFAULT public.uuid_generate_v4() CONSTRAINT workflow_submissions_id_not_null NOT NULL,
    tenant_id uuid CONSTRAINT workflow_submissions_tenant_id_not_null NOT NULL,
    form_id uuid CONSTRAINT workflow_submissions_form_id_not_null NOT NULL,
    initiator_user_id uuid CONSTRAINT workflow_submissions_initiator_user_id_not_null NOT NULL,
    payload_data jsonb CONSTRAINT workflow_submissions_payload_data_not_null NOT NULL,
    current_stage_order integer DEFAULT 1 CONSTRAINT workflow_submissions_current_step_order_not_null NOT NULL,
    status workflow.workflow_submission_status DEFAULT 'draft'::workflow.workflow_submission_status CONSTRAINT workflow_submissions_status_not_null NOT NULL,
    submitted_at timestamp with time zone,
    completed_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


ALTER TABLE workflow.submissions OWNER TO postgres;

--
-- Name: TABLE submissions; Type: COMMENT; Schema: workflow; Owner: postgres
--

COMMENT ON TABLE workflow.submissions IS 'An instance of a form submitted by a user. payload_data (JSONB) contains the submitted field values. current_stage_order tracks routing progress. Status: draft → submitted → in_review → approved → rejected → cancelled. completed_at is set when the final stage is resolved.';


